// Reusable HTML email wrapper — founder headshot + personal note at top
function focEmailWrap(bodyHtml, opts = {}) {
  const showFounder = opts.founderNote !== false;
  const founderNote = opts.founderNote || '';
  const headshotUrl = 'https://founderopscenter.com/assets/Russ%20headshot%20nuetral%20background.jpg.png';
  const founderTopBlock = showFounder ? `
  <!-- Founder personal intro -->
  <tr><td style="padding:28px 32px 0">
    <table cellpadding="0" cellspacing="0" border="0" style="width:100%"><tr>
      <td style="width:60px;vertical-align:top;padding-right:14px">
        <img src="${headshotUrl}" alt="Russell Cole" width="52" height="52" style="border-radius:50%;display:block;object-fit:cover;border:2px solid #059669">
      </td>
      <td style="vertical-align:top">
        <p style="margin:0 0 4px;font-size:15px;font-weight:700;color:#111827">Russell Cole</p>
        <p style="margin:0;font-size:12px;color:#6b7280">Founder, FounderOps Center</p>
      </td>
    </tr></table>
    <p style="margin:16px 0 0;font-size:14px;color:#374151;line-height:1.6">${founderNote}</p>
  </td></tr>` : '';

  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif">
<table cellpadding="0" cellspacing="0" border="0" width="100%" style="background:#f3f4f6;padding:32px 16px">
<tr><td align="center">
<table cellpadding="0" cellspacing="0" border="0" width="600" style="max-width:600px;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.08)">
  <!-- Header -->
  <tr><td style="background:linear-gradient(135deg,#059669 0%,#047857 100%);padding:24px 32px;text-align:center">
    <h1 style="margin:0;font-size:20px;color:#ffffff;font-weight:700;letter-spacing:-0.3px">🌱 FounderOps Center</h1>
    <p style="margin:4px 0 0;font-size:11px;color:rgba(255,255,255,0.8);font-weight:500">AgTech Ecosystem Intelligence</p>
  </td></tr>
  ${founderTopBlock}
  <!-- Body -->
  <tr><td style="padding:${showFounder ? '20px' : '32px'} 32px 12px;color:#374151;font-size:14px;line-height:1.65">${bodyHtml}</td></tr>
  <!-- Footer -->
  <tr><td style="padding:24px 32px;border-top:1px solid #e5e7eb;margin-top:20px">
    <p style="margin:0;font-size:11px;color:#9ca3af;text-align:center">
      <a href="https://founderopscenter.com" style="color:#059669;text-decoration:none;font-weight:600">founderopscenter.com</a><br>
      Connecting founders, investors, and ecosystems in AgTech<br><br>
      <span style="color:#d1d5db">You received this because you're part of the FounderOps Center community.</span>
    </p>
  </td></tr>
</table>
</td></tr></table>
</body></html>`;
}

