// Core send function — fires and forgets, logs to console, shows toast on failure
async function sendAutoEmail(to, subject, html) {
  try {
    const res = await fetch(EDGE_FN_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ to, subject, html })
    });
    const data = await res.json();
    if (!res.ok) {
      console.error('sendAutoEmail failed:', data);
      return { success: false, error: data };
    }
    console.log('📧 Email sent:', { to, subject, id: data.id });
    return { success: true, id: data.id };
  } catch (err) {
    console.error('sendAutoEmail error:', err);
    return { success: false, error: err.message };
  }
}

// Listen for auth state changes (session check happens in INIT block at bottom)
_supabase.auth.onAuthStateChange((event, session) => {
  if (event === 'SIGNED_IN' && session?.user) {
    applyUser(session.user, event === 'SIGNED_IN');
  } else if (event === 'SIGNED_OUT') {
    currentUser = null; isAdmin = false; _userProfile = null; _allProfiles = [];
    _userWorkspaces = []; _activeWorkspaceId = null;
    const btn = document.getElementById('topbar-user-btn');
    if (btn) { btn.textContent = '→ Sign In'; btn.onclick = () => openModal('signin-modal'); }
    // Hide profile/admin/roadmap nav buttons
    const pb = document.getElementById('nav-profile-btn'); if (pb) pb.style.display = 'none';
    const ab = document.getElementById('nav-admin-btn'); if (ab) ab.style.display = 'none';
    const rb = document.getElementById('nav-roadmap-btn'); if (rb) rb.style.display = 'none';
    const cb = document.getElementById('nav-connections-btn'); if (cb) cb.style.display = 'none';
    const acb = document.getElementById('nav-action-btn'); if (acb) acb.style.display = 'none';
    const hbb = document.getElementById('nav-hub-btn'); if (hbb) hbb.style.display = 'none';
    const ivb = document.getElementById('nav-investor-btn'); if (ivb) ivb.style.display = 'none';
    const mts = document.getElementById('sidebar-my-tools'); if (mts) mts.style.display = 'none';
    const ps = document.getElementById('admin-persona-switcher'); if (ps) { ps.style.display = 'none'; ps.value = ''; }
    const pwb = document.getElementById('admin-preview-wiz-btn'); if (pwb) pwb.style.display = 'none';
    const nb = document.getElementById('notif-bell'); if (nb) nb.style.display = 'none';
    _adminPersonaOverride = null;
    // Reset branding to default on signout
    const lt = document.querySelector('.logo-text'); if (lt) lt.textContent = 'Founder Ops Center';
    const li = document.querySelector('.logo-icon'); if (li) li.textContent = 'F';
    const tl = document.querySelector('.sidebar-tagline'); if (tl) tl.textContent = 'AgTech ecosystem intelligence for founders, investors, and operators.';
    document.title = 'AgTech Founder Ops Center';
    // Show clean full-screen signed-out landing
    showSignedOutPage();
  }
});

function applyUser(user, isNew) {
  const email = user.email || '';
  const name = user.user_metadata?.full_name || email.split('@')[0];
  const avatar = user.user_metadata?.avatar_url || null;
  currentUser = { id: user.id, email, name, avatar, method: 'google' };
  // isAdmin is determined from profiles.is_platform_admin, set after profile loads.
  isAdmin = false;

  // Hide landing page if showing
  hideLanding();

  // Update topbar button
  const btn = document.getElementById('topbar-user-btn');
  if (btn) {
    btn.innerHTML = avatar
      ? `<img src="${avatar}" alt="${name}" style="width:28px;height:28px;border-radius:50%;cursor:pointer;border:2px solid var(--green)" title="${email}" onclick="openSignOutMenu()">`
      : avatarHtml(email, 'google');
    btn.onclick = null;
  }
  closeModal('signin-modal');
  dismissOnboard();

  // Show nav buttons in My Tools section
  const profileBtn = document.getElementById('nav-profile-btn');
  const adminBtn = document.getElementById('nav-admin-btn');
  const roadmapBtn = document.getElementById('nav-roadmap-btn');
  const connectionsBtn = document.getElementById('nav-connections-btn');
  const actionBtn = document.getElementById('nav-action-btn');
  const hubBtn = document.getElementById('nav-hub-btn');
  const myToolsSection = document.getElementById('sidebar-my-tools');
  if (myToolsSection) myToolsSection.style.display = 'block';
  if (profileBtn) profileBtn.style.display = 'flex';
  if (connectionsBtn) connectionsBtn.style.display = 'block';
  if (actionBtn) actionBtn.style.display = 'block';
  if (hubBtn) hubBtn.style.display = 'block';
  if (adminBtn && isAdmin) adminBtn.style.display = 'block';
  // Show persona switcher for admin
  const personaSwitcher = document.getElementById('admin-persona-switcher');
  if (personaSwitcher) personaSwitcher.style.display = isAdmin ? 'inline-block' : 'none';
  const savePersonaBtn = document.getElementById('admin-save-persona-btn');
  if (savePersonaBtn) savePersonaBtn.style.display = isAdmin ? 'inline-block' : 'none';
  const previewWizBtn = document.getElementById('admin-preview-wiz-btn');
  if (previewWizBtn) previewWizBtn.style.display = isAdmin ? 'inline-block' : 'none';
  // Roadmap nav only for non-admin users with access (admin sees it in the admin dashboard tabs)

  // Track & notify on new users
  const seenKey = 'foc_seen_' + user.id;
  if (!localStorage.getItem(seenKey)) {
    localStorage.setItem(seenKey, '1');
    notifyNewUser(name, email);
    // Welcome email now fires after onboarding completes (persona-tailored)
  }
  const logins = getLogins();
  const existing = logins.find(l => l.id === user.id);
  if (!existing) {
    logins.unshift({ id: user.id, email, name, method: 'google', ts: new Date().toISOString(), pages: [] });
    saveLogins(logins);
  }
  const msg = isAdmin ? '✅ Welcome back, Admin!' : '✅ Welcome, ' + name + '!';
  toast(msg);

  // Check for existing profile — block check, then show wizard if new
  loadProfile(user.id).then(async profile => {
    // If no profile found by auth ID, check for a pre-created profile by email
    if (!profile && email) {
      const { data: preCre } = await _supabase.from('pre_created_profiles').select('*').eq('email', email.toLowerCase()).maybeSingle();
      if (preCre && preCre.profile_data) {
        // Migrate: create a real profile from the pre-created data
        const pd = preCre.profile_data;
        const newProfile = {
          id: user.id,
          email: email,
          full_name: name || pd.full_name || email.split('@')[0],
          avatar_url: user.user_metadata?.avatar_url || null,
          needs_review: true,
          pre_created: true,
          ...pd
        };
        const { data: mData, error: mErr } = await upsertProfile(newProfile);
        if (!mErr && mData) {
          profile = mData;
          // Clean up the pre_created_profiles row
          await _supabase.from('pre_created_profiles').delete().eq('email', email.toLowerCase());
          toast('👋 Welcome! Russell pre-loaded your profile — please review it.');
        } else {
          console.error('Pre-created profile migration error:', mErr);
        }
      }
    }

    _userProfile = profile;
    isAdmin = !!(profile && profile.is_platform_admin === true);
    // Re-show admin-only top bar + sidebar buttons now that isAdmin is resolved.
    // (applyUser() hid them earlier because isAdmin defaults to false until the
    // profile row is fetched from Supabase.)
    try {
      const _adminBtnSide = document.getElementById('nav-admin-btn');
      if (_adminBtnSide) _adminBtnSide.style.display = isAdmin ? 'block' : 'none';
      const _udAdminBtn = document.getElementById('ud-admin-btn');
      if (_udAdminBtn) _udAdminBtn.style.display = isAdmin ? 'flex' : 'none';
      const _personaSwitcher = document.getElementById('admin-persona-switcher');
      if (_personaSwitcher) _personaSwitcher.style.display = isAdmin ? 'inline-block' : 'none';
      const _savePersonaBtn = document.getElementById('admin-save-persona-btn');
      if (_savePersonaBtn) _savePersonaBtn.style.display = isAdmin ? 'inline-block' : 'none';
      const _previewWizBtn = document.getElementById('admin-preview-wiz-btn');
      if (_previewWizBtn) _previewWizBtn.style.display = isAdmin ? 'inline-block' : 'none';
      const _roadmapSideBtn = document.getElementById('nav-roadmap-btn');
      if (_roadmapSideBtn && isAdmin) _roadmapSideBtn.style.display = 'block';
    } catch (_e) { /* non-fatal */ }
    // Load the workspaces this user is an active member of (Supabase source of truth).
    await loadUserWorkspaces();
    // Claim flow: if the user arrived via ?claim=<code>, redeem it now.
    await consumePendingClaim();
    // First-login auto-join: attach to workspaces matching this user's email domain.
    await maybeAutoJoinOnFirstLogin();
    if (profile && profile.blocked) {
      showBlockedScreen();
      return;
    }
    // Show roadmap nav for non-admin users granted access (admin sees it in admin dashboard)
    if (!isAdmin && profile && (profile.admin_tags||[]).includes('roadmap_access')) {
      const rmBtn = document.getElementById('nav-roadmap-btn');
      if (rmBtn) rmBtn.style.display = 'block';
    }
    if (!profile || !profile.onboarding_complete) {
      // If user came from "Share Your Idea" CTA, skip onboarding and go straight to Venture Studio
      if (_ventureStudioAfterSignIn) {
        _ventureStudioAfterSignIn = false;
        localStorage.removeItem('foc_venture_after_signin');
        // Create minimal founder profile so they can access the platform
        const minProfile = {
          id: user.id,
          email: user.email,
          full_name: user.user_metadata?.full_name || user.email.split('@')[0],
          persona: 'founder',
          onboarding_complete: false
        };
        const { error: upErr } = await _supabase.from('profiles').upsert(minProfile, { onConflict: 'id' });
        if (!upErr) _userProfile = { ...minProfile, ...(profile || {}), persona: 'founder' };
        applyPersonaUI(_userProfile || minProfile);
        document.getElementById('sidebar').style.display = '';
        document.getElementById('main').style.display = '';
        document.getElementById('landing-page').style.display = 'none';
        go('venture');
        // Show a gentle reminder to complete their profile later
        setTimeout(() => toast('💡 After submitting your idea, complete your profile for full platform access.'), 2000);
      } else {
        setTimeout(() => showWizard(), 800);
      }
    } else if (profile.needs_review) {
      // Pre-created account — show edit wizard so they can review and confirm
      toast('📋 Please review your profile and make any changes.');
      setTimeout(() => {
        editWizard();
        // Override the save to also clear needs_review
        _wizNeedsReviewMode = true;
      }, 800);
    } else {
      // Sync badges, tier, and completeness
      _userProfile = await syncProfileMeta(profile);
      // Check auto-suspend for incomplete profiles
      const suspended = await checkAutoSuspend(_userProfile);
      if (suspended) { showBlockedScreen(); return; }
      // Apply persona-tailored UI (branding, nav visibility)
      applyPersonaUI(_userProfile);
      // Auto-register ecosystem managers who have access tags or persona
      if (_userProfile && currentUser && !isClaimedEcoManager(currentUser.id)) {
        const hasEcoTag = (_userProfile.admin_tags || []).includes('ecosystem_access');
        const isEcoPers = _userProfile.persona === 'ecosystem_manager';
        if (hasEcoTag || isEcoPers) {
          // Check if they're listed as manager on any pre-claimed partner ecosystem
          const managedEco = PARTNER_ECOSYSTEMS.find(e => e.claimed && e.manager === _userProfile.full_name);
          const partnerEcoId = _ecoSettings?.partner_ecosystem_id || (managedEco ? managedEco.id : 'custom');
          const partnerEcoName = managedEco ? managedEco.shortName : (_ecoSettings?.program_name || 'My Ecosystem');
          registerEcoManager(currentUser.id, currentUser.email, partnerEcoId, partnerEcoName);
          // Re-apply so nav button shows
          applyPersonaUI(_userProfile);
        }
      }
      // Check if user came from "Share Your Idea" on landing page
      if (_ventureStudioAfterSignIn) {
        _ventureStudioAfterSignIn = false;
        localStorage.removeItem('foc_venture_after_signin');
        go('venture');
      } else if (currentPage) {
        render(currentPage);
      }
    }
    // Update notification bell after any profile state change
    updateNotifBell();
    // Load Supabase deals for investor dashboard + venture submissions for admin bell
    if (currentUser) {
      loadSupabaseDeals().then(d => { if (d.length) { _supabaseDeals = d; } });
      loadVentureSubmissions().then(() => updateNotifBell());
    }
  });
}

