let _ventureStudioAfterSignIn = localStorage.getItem('foc_venture_after_signin') === 'true';

function enterApp() {
  hideLanding();
  openModal('signin-modal');
}

function enterAppGuest() {
  hideLanding();
  render('overview');
}

function hideLanding() {
  const landing = document.getElementById('landing-page');
  if (landing) landing.remove();
  document.getElementById('sidebar').style.display = '';
  document.getElementById('main').style.display = '';
  document.querySelector('.fab').style.display = '';
}

// ── Landing Page Carousel ──
let _lpSlide = 0;
let _lpHovered = false;
const LP_SLIDE_COUNT = 4;

function lpCarouselGo(idx) {
  _lpSlide = Math.max(0, Math.min(idx, LP_SLIDE_COUNT - 1));
  const track = document.getElementById('lp-carousel-track');
  if (track) {
    const slides = track.querySelectorAll('.lp-carousel-slide');
    slides.forEach(s => s.style.transform = 'translateX(-' + (_lpSlide * 100) + '%)');
  }
  const dots = document.querySelectorAll('.lp-carousel-dot');
  dots.forEach((d, i) => d.classList.toggle('active', i === _lpSlide));
}

function lpCarouselMove(dir) {
  let next = _lpSlide + dir;
  if (next < 0) next = LP_SLIDE_COUNT - 1;
  if (next >= LP_SLIDE_COUNT) next = 0;
  lpCarouselGo(next);
}

function lpCarouselHover(hovering) { _lpHovered = hovering; }

// Auto-advance carousel every 6 seconds, pause on hover
setInterval(() => {
  const landing = document.getElementById('landing-page');
  if (landing && !_lpHovered) lpCarouselMove(1);
}, 6000);

