// Helper: wrap text in a link if URL exists
function lnk(text, url){
  if(!url) return text;
  return `<a href="${url}" target="_blank" rel="noopener" style="color:inherit;text-decoration:underline;text-underline-offset:2px;text-decoration-color:var(--green)">${text}&nbsp;<span style="font-size:9px;opacity:.7">🔗</span></a>`;
}

// ── MOBILE SIDEBAR ────────────────────────────────────────────────
function openSidebar(){
  const sb = document.getElementById('sidebar');
  const ov = document.getElementById('sidebar-overlay');
  sb.classList.add('mobile-open');
  sb.classList.remove('collapsed');
  if(ov) ov.classList.add('show');
}
function closeSidebar(){
  const sb = document.getElementById('sidebar');
  const ov = document.getElementById('sidebar-overlay');
  sb.classList.remove('mobile-open');
  if(ov) ov.classList.remove('show');
}
const _accordionState = { global: true, region: false, mytools: false };
function toggleAccordion(section) {
  _accordionState[section] = !_accordionState[section];
  const items = document.getElementById('accordion-' + section + '-items');
  const arrow = document.getElementById('accordion-' + section + '-arrow');
  if (items) items.style.display = _accordionState[section] ? '' : 'none';
  if (arrow) arrow.style.transform = _accordionState[section] ? '' : 'rotate(-90deg)';
}

function toggleSidebar(){
  if(window.innerWidth <= 700){
    const sb = document.getElementById('sidebar');
    sb.classList.contains('mobile-open') ? closeSidebar() : openSidebar();
  } else {
    document.getElementById('sidebar').classList.toggle('collapsed');
  }
}
// Close sidebar when nav item tapped on mobile
document.addEventListener('click', e => {
  if(window.innerWidth <= 700 && e.target.closest('.nav-item')){
    setTimeout(closeSidebar, 120);
  }
});

// ── ONBOARDING ─────────────────────────────────────────────────────
function showOnboarding(){
  document.getElementById('onboard-modal').classList.add('open');
}
function dismissOnboard(){
  localStorage.setItem('foc_onboarded','1');
  document.getElementById('onboard-modal').classList.remove('open');
}
function onboardStep(n){
  ['onboard-s1','onboard-s2','onboard-s3'].forEach(id=>{
    document.getElementById(id).style.display='none';
  });
  document.getElementById('onboard-s'+n).style.display='block';
}
function setFounderType(type){
  localStorage.setItem('foc_founder_type', type);
  toast('👋 Welcome, '+type+'!');
  onboardStep(3);
}
function onboardSignup(){
  const email = document.getElementById('onboard-email').value.trim();
  if(!email){ toast('Please enter your email'); return; }
  signIn('signup');
  dismissOnboard();
}

// ── THEME ─────────────────────────────────────────────────────────
function toggleTheme(){
  const dark = document.documentElement.classList.toggle('dark');
  document.getElementById('theme-btn').textContent = dark ? '☀️ Light Mode' : '🌙 Dark Mode';
  try { localStorage.setItem('foc-theme', dark ? 'dark' : 'light'); } catch(e){}
}
function restoreTheme(){
  try {
    const t = localStorage.getItem('foc-theme');
    if(t === 'dark'){ document.documentElement.classList.add('dark'); document.getElementById('theme-btn').textContent = '☀️ Light Mode'; }
  } catch(e){}
}

// ── TOAST ─────────────────────────────────────────────────────────
function toast(msg, dur=2800){
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(t._timer);
  t._timer = setTimeout(()=>t.classList.remove('show'), dur);
}

// ── MODAL ─────────────────────────────────────────────────────────
function openModal(id){ document.getElementById(id).classList.add('open'); }
function closeModal(id){ document.getElementById(id).classList.remove('open'); }

