let _fqStep = 0;
let _fqAnswers = {};
let _fqPersona = 'founder';

function openFoundingQuestionnaire(persona) {
  _fqPersona = persona || 'founder';
  // Fallback for personas not in FOUNDING_Q
  if (!FOUNDING_Q[_fqPersona]) _fqPersona = 'founder';
  _fqStep = 0;
  _fqAnswers = {};
  renderFoundingQ();
  openModal('founding-q-modal');
}

function renderFoundingQ() {
  const qs = FOUNDING_Q[_fqPersona];
  const el = document.getElementById('founding-q-content');
  if (!el) return;

  if (_fqStep === -1) {
    // Intro screen
    el.innerHTML = `
      <div style="text-align:center">
        <div style="font-size:32px;margin-bottom:12px">🌱</div>
        <h3 style="margin-bottom:8px">Welcome, Founding Member</h3>
        <p style="color:var(--text-muted);margin-bottom:20px;font-size:14px;line-height:1.6">
          You're one of the first people on this platform. That means your voice carries extra weight.<br><br>
          We have <strong>${qs.length} quick questions</strong> that will directly shape what we build next.
          Your answers go straight to Russell and the product team.
        </p>
        <p style="background:var(--bg);border-radius:10px;padding:12px 16px;font-size:13px;color:var(--text-muted);margin-bottom:20px">
          🏅 <strong>Founding Members</strong> get permanent perks: <strong>10 warm intros/month</strong> (vs 3 standard), early access to new features, and a Founding Member badge on your profile.
        </p>
        <button onclick="setFqStep(0)" style="padding:12px 32px;background:var(--green);color:#fff;border:none;border-radius:10px;font-weight:700;font-size:14px;cursor:pointer">Let's Go →</button>
        <br><button onclick="skipFoundingQ()" style="margin-top:12px;background:none;border:none;color:var(--text-faint);font-size:12px;cursor:pointer">I'll do this later</button>
      </div>`;
    return;
  }

  if (_fqStep >= qs.length) {
    // Done screen
    el.innerHTML = `
      <div style="text-align:center">
        <div style="font-size:40px;margin-bottom:12px">🎉</div>
        <h3 style="margin-bottom:8px">Thank You, Founding Member</h3>
        <p style="color:var(--text-muted);margin-bottom:16px;font-size:14px;line-height:1.6">
          Your answers are incredibly valuable. They go directly into our product roadmap.<br><br>
          You now have your <strong>🏅 Founding Member</strong> badge and <strong>10 intros/month</strong>.
        </p>
        <button onclick="closeModal('founding-q-modal')" style="padding:12px 32px;background:var(--green);color:#fff;border:none;border-radius:10px;font-weight:700;font-size:14px;cursor:pointer">Explore the Platform →</button>
      </div>`;
    saveFoundingQAnswers();
    return;
  }

  const q = qs[_fqStep];
  const progress = Math.round(((_fqStep) / qs.length) * 100);
  let inputHtml = '';

  if (q.type === 'select') {
    inputHtml = q.opts.map(o => `
      <label style="display:flex;align-items:center;gap:10px;padding:10px 14px;border:1.5px solid ${_fqAnswers[q.id] === o ? 'var(--green)' : 'var(--border)'};border-radius:10px;cursor:pointer;font-size:13px;transition:all 0.15s;background:${_fqAnswers[q.id] === o ? 'rgba(22,163,74,0.06)' : 'var(--surface)'}"
        onclick="document.querySelectorAll('.fq-opt').forEach(l=>{l.style.borderColor='var(--border)';l.style.background='var(--surface)'});this.style.borderColor='var(--green)';this.style.background='rgba(22,163,74,0.06)';_fqAnswers['${q.id}']='${o.replace(/'/g, "\\'")}'"
        class="fq-opt">${o}</label>
    `).join('');
  } else {
    inputHtml = `<textarea class="form-textarea" rows="4" id="fq-ta" placeholder="${q.placeholder || 'Share your thoughts...'}" style="font-size:13px">${_fqAnswers[q.id] || ''}</textarea>`;
  }

  el.innerHTML = `
    <div style="margin-bottom:16px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <span style="font-size:11px;color:var(--text-faint);font-weight:600">FOUNDING MEMBER INPUT</span>
        <span style="font-size:11px;color:var(--text-faint)">${_fqStep + 1} of ${qs.length}</span>
      </div>
      <div style="height:4px;background:var(--border);border-radius:4px;overflow:hidden">
        <div style="height:100%;width:${progress}%;background:var(--green);border-radius:4px;transition:width 0.3s"></div>
      </div>
    </div>
    <h3 style="font-size:16px;margin-bottom:16px;line-height:1.4">${q.q}</h3>
    <div style="display:flex;flex-direction:column;gap:8px;margin-bottom:20px;max-height:300px;overflow-y:auto">
      ${inputHtml}
    </div>
    <div style="display:flex;gap:10px;justify-content:space-between">
      <button onclick="${_fqStep > 0 ? '_fqStep--;renderFoundingQ()' : 'closeModal(\'founding-q-modal\')'}" style="padding:10px 20px;background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:13px;cursor:pointer">${_fqStep > 0 ? '← Back' : 'Skip'}</button>
      <button onclick="fqNext()" style="padding:10px 24px;background:var(--green);color:#fff;border:none;border-radius:8px;font-weight:700;font-size:13px;cursor:pointer">${_fqStep < qs.length - 1 ? 'Next →' : 'Finish ✓'}</button>
    </div>`;
}

function fqNext() {
  const qs = FOUNDING_Q[_fqPersona];
  const q = qs[_fqStep];
  // Collect textarea answer
  if (q.type === 'textarea') {
    const ta = document.getElementById('fq-ta');
    if (ta) _fqAnswers[q.id] = ta.value.trim();
  }
  _fqStep++;
  renderFoundingQ();
}

function skipFoundingQ() {
  closeModal('founding-q-modal');
  // Store that they skipped — can prompt again later
  if (currentUser) {
    localStorage.setItem('fq_skipped_' + currentUser.id, Date.now());
  }
}

async function saveFoundingQAnswers() {
  if (!currentUser) return;
  const payload = {
    user_id: currentUser.id,
    email: currentUser.email,
    persona: _fqPersona,
    answers: _fqAnswers,
    completed_at: new Date().toISOString()
  };
  // Save to Supabase
  try {
    const { error } = await _supabase.from('founding_member_survey').upsert(payload, { onConflict: 'user_id' });
    if (error) console.warn('Survey save error (table may not exist yet):', error.message);
    else console.log('Founding member survey saved:', payload);
  } catch(e) { console.warn('Survey save failed:', e); }

  // Also grant founding member badge
  if (_userProfile) {
    const badges = _userProfile.badges || [];
    if (!badges.includes('founding_member')) {
      badges.push('founding_member');
      _userProfile.badges = badges;
      _userProfile.tier = 'founding_member';
      try {
        await upsertProfile({ id: currentUser.id, badges, tier: 'founding_member' });
      } catch(e) { console.warn('Badge update failed:', e); }
    }
  }

  // Track analytics event
  trackEvent('founding_survey_completed', { persona: _fqPersona, question_count: Object.keys(_fqAnswers).length });
}

// ── BEHAVIORAL ANALYTICS TRACKING ────────────────────────────────
const _analytics = [];
function trackEvent(event, data = {}) {
  const entry = {
    event,
    ...data,
    user_id: currentUser?.id || 'anon',
    persona: _userProfile?.persona || 'unknown',
    timestamp: new Date().toISOString(),
    page: currentPage,
    session_id: window._sessionId || 'unknown'
  };
  _analytics.push(entry);
  console.log('📊 Track:', event, data);

  // Batch save to Supabase every 10 events
  if (_analytics.length % 10 === 0) flushAnalytics();
}

async function flushAnalytics() {
  if (!_analytics.length) return;
  const batch = _analytics.splice(0, _analytics.length);
  try {
    const { error } = await _supabase.from('analytics_events').insert(batch);
    if (error) console.warn('Analytics flush error (table may not exist):', error.message);
  } catch(e) { console.warn('Analytics flush failed:', e); }
}

// Generate session ID
window._sessionId = 'sess_' + Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

// Flush analytics on page unload
window.addEventListener('beforeunload', flushAnalytics);

// ── NAVIGATION ────────────────────────────────────────────────────
let currentPage = 'overview';
function go(page, btn){
  // Handle compound navigation (e.g. 'admin_deals' → admin page + deals tab)
  if (page === 'admin_deals') { adminTab = 'deals'; page = 'admin'; }
  if (page === 'admin_venture') { adminTab = 'venture_studio'; page = 'admin'; }
  if (page === 'admin_eco') { adminTab = 'eco_claims'; page = 'admin'; }
  if (page === 'admin_claims') { adminTab = 'eco_claims'; page = 'admin'; }
  if (page !== 'crops') _selectedCrop = null; // reset crop detail when leaving crops
  if (page !== 'hub') _selectedMentor = null; // reset mentor detail when leaving hub
  if (page !== 'accelerators') _selectedAccelerator = null; // reset accelerator detail when leaving accelerators
  if (page !== 'venture') _ventureStep = 0;
  currentPage = page;
  try { localStorage.setItem('foc-page', page); } catch(e){}
  document.querySelectorAll('.nav-item').forEach(b=>b.classList.remove('active'));
  if(btn) btn.classList.add('active');
  trackEvent('page_view', { page });
  render(page);
  document.getElementById('page').scrollTop = 0;
}
let _currentRegion = 'ca';
function updateRegion(v){
  _currentRegion = v;
  _ecoSegmentOpen = null;
  _ecoTrendOpen = null;
  _selectedCrop = null;
  render(currentPage);
}

// ── ACCORDION ────────────────────────────────────────────────────
function acc(id, title, subtitle, content, icon='📄', count=''){
  return `<div class="acc">
    <div class="acc-hdr" onclick="toggleAcc('${id}')">
      <div class="acc-left"><span class="acc-icon">${icon}</span>
        <div><div class="acc-title">${title}</div>${subtitle?`<div class="acc-subtitle">${subtitle}</div>`:''}</div>
      </div>
      <div class="acc-right">${count?`<span class="acc-count">${count}</span>`:''}<span class="acc-chev">▼</span></div>
    </div>
    <div class="acc-body" id="${id}-b">${content}</div>
  </div>`;
}
function toggleAcc(id){
  document.querySelector(`[onclick="toggleAcc('${id}')"]`).classList.toggle('open');
  document.getElementById(id+'-b').classList.toggle('open');
}

// ── TABS ──────────────────────────────────────────────────────────
function tabs(gid, defs){
  const nav = defs.map((t,i)=>`<button class="tab-btn${i===0?' active':''}" onclick="switchTab('${gid}',${i},this)">${t.label}</button>`).join('');
  const panels = defs.map((t,i)=>`<div class="tab-panel${i===0?' active':''}" id="${gid}-p${i}">${t.content}</div>`).join('');
  return `<div class="tabs-nav">${nav}</div>${panels}`;
}
function switchTab(gid,idx,btn){
  btn.closest('.tabs-nav').querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll(`[id^="${gid}-p"]`).forEach(p=>p.classList.remove('active'));
  document.getElementById(`${gid}-p${idx}`).classList.add('active');
}

