function openBookingEmail(){
  const fromName = currentUser ? currentUser.name : '';
  const subject = encodeURIComponent('Sharing my availability to book a meeting with Russell Cole');
  const body = encodeURIComponent(
    'Hi Russell,\n\n' +
    'Purpose of call: \n\n' +
    'Times available this week and next week below:\n\n' +
    '- \n- \n- \n\n' +
    'Looking forward to connecting!\n\n' +
    (fromName ? fromName : '')
  );
  const mailtoUrl = 'mailto:russellcolevop@gmail.com?subject=' + subject + '&body=' + body;
  // Use location.href for better mobile compatibility
  window.location.href = mailtoUrl;
  closeModal('book-modal');
  toast('📅 Email client opening — send your availability to Russell');
}

