function dlDoc(name){
  if (!currentUser) {
    openModal('signin-modal');
    toast('📄 Sign in to access documents');
    return;
  }
  const path = DOC_URLS[name];
  if (!path) {
    toast('🔜 Coming soon — ' + name);
    return;
  }
  // Trigger download via hidden anchor
  const a = document.createElement('a');
  a.href = path;
  a.download = '';
  a.target = '_blank';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  toast('⬇️ Downloading ' + name + '...');
}

async function submitDocRequest(){
  const txt = document.getElementById('doc-request-text')?.value?.trim();
  if(!txt){ toast('Please describe the document you need.'); return; }
  // Store in Supabase doc_requests table (or introductions as fallback)
  try {
    const { error } = await _supabase.from('introductions').insert({
      from_user: currentUser.id,
      to_user: currentUser.id,
      status: 'doc_request',
      notes: 'DOC REQUEST: ' + txt,
      created_at: new Date().toISOString()
    });
    if(error) throw error;
    document.getElementById('doc-request-text').value = '';
    toast('Thanks! Your document request has been submitted.');
  } catch(e) {
    // Fallback: open mailto
    window.open('mailto:russellcolevop@gmail.com?subject=Document%20Request%20-%20FounderOps%20Center&body=' + encodeURIComponent('Document request from ' + (currentUser.email || 'a user') + ':\n\n' + txt), '_blank');
    document.getElementById('doc-request-text').value = '';
    toast('Request sent via email — thanks!');
  }
}

// ── STAT MODAL ────────────────────────────────────────────────────
const STAT_DETAILS = {};
function toggleStat(id){
  const s = STAT_DETAILS[id];
  if(!s) return;
  document.getElementById('smd-val').textContent = s.val;
  document.getElementById('smd-lbl').textContent = s.lbl;
  document.getElementById('smd-src').textContent = 'Source: ' + s.src;
  document.getElementById('smd-body').innerHTML = s.detail;
  openModal('stat-modal');
}

