function pgJourney(){return `
<div class="page-hdr"><h1>Founder's Journey in AgTech</h1>
<p>Navigate the path from idea to scale with clarity. Understand your entry points, stages, opportunities, and milestones specific to agricultural technology.</p></div>

<div class="card"><h3>🗺️ Understanding Your Path</h3>
<p style="font-size:13px;color:var(--text-muted);line-height:1.6;margin-bottom:8px">There's no one-size-fits-all approach to building an AgTech startup. Your journey depends on your entry point, resources, team, and goals.</p>
<p style="font-size:12px;color:var(--text-muted)"><strong>Key Focus Areas:</strong> Entry points → Development stages (Idea → MVP → LOI → Fundraising) → Programs &amp; opportunities → Success milestones</p></div>

<div class="card"><h3>🚪 Entry Points: How Founders Get Started</h3>
<div class="entry-grid">
<div class="entry-card">
  <div class="entry-path">Path 1</div>
  <h4>Own Idea / Problem You've Identified</h4>
  <p>You've identified a specific problem in agriculture based on personal experience, industry insight, or market research.</p>
  <p style="margin-top:8px"><strong>Characteristics:</strong></p>
  <ul><li>Strong domain expertise or lived experience</li><li>Deep understanding of the problem space</li><li>May need help with business model and go-to-market</li></ul>
  <p style="margin-top:8px"><strong>Next Steps:</strong></p>
  <ul><li>Validate the problem with potential customers</li><li>Join accelerators for structure and mentorship</li><li>Consider applying to Founder Institute or CDL</li></ul>
</div>
<div class="entry-card">
  <div class="entry-path">Path 2</div>
  <h4>Incubator / Accelerator Provided Ideas</h4>
  <p>Joining a program that provides validated problem statements, matching you with co-founders and resources.</p>
  <p style="margin-top:8px"><strong>Characteristics:</strong></p>
  <ul><li>Structured approach with proven frameworks</li><li>Access to mentors and industry connections</li><li>May need to build domain expertise quickly</li></ul>
  <p style="margin-top:8px"><strong>Next Steps:</strong></p>
  <ul><li>Immerse yourself in the agricultural sector</li><li>Talk to farmers and industry stakeholders</li><li>Leverage program resources and network</li></ul>
</div>
</div></div>

<div class="card"><h3>📈 Development Stages: From Idea to Scale</h3>
${acc('s1','Stage 1','Idea Validation &amp; Customer Discovery',`<div class="stage-detail">
<div class="stage-focus">Focus</div>
<p>Talk to 50+ farmers and agricultural stakeholders to deeply understand the problem before building anything.</p>
<ul><li>Conduct structured customer interviews (problem-focused, not solution-focused)</li>
<li>Map the existing workflow and identify friction points</li>
<li>Quantify the cost/impact of the problem</li>
<li>Identify your beachhead customer segment</li></ul>
<p><strong>Key Deliverable:</strong> Customer discovery summary with evidence of problem severity and willingness to pay.</p>
</div>`,'💡')}
${acc('s2','Stage 2','MVP / Prototype Development',`<div class="stage-detail">
<div class="stage-focus">Focus</div>
<p>Build the minimum viable product that demonstrates your core value proposition.</p>
<ul><li>Define MVP scope: what's the minimum to prove your hypothesis?</li>
<li>Set up development sprints with regular farmer feedback loops</li>
<li>Consider hardware prototyping partners for physical products</li>
<li>Run 3–5 beta pilots on real farms before broad launch</li></ul>
<p><strong>Key Deliverable:</strong> Working prototype with documented farm test results.</p>
</div>`,'🔧')}
${acc('s3','Stage 3','LOI Collection &amp; Market Validation',`<div class="stage-detail">
<div class="stage-focus">Focus</div>
<p>Secure Letters of Intent (LOIs) from potential customers — the clearest signal of real market demand.</p>
<ul><li>Target 10–20 LOIs from farms representing your core segment</li>
<li>LOIs should include a price point and intended purchase timeline</li>
<li>Use LOIs to validate your pricing model</li>
<li>Present LOIs to investors as proof of traction</li></ul>
<p><strong>Key Deliverable:</strong> Signed LOIs totaling significant first-year revenue potential.</p>
</div>`,'📝')}
${acc('s4','Stage 4','Pitch Deck &amp; Financial Modeling',`<div class="stage-detail">
<div class="stage-focus">Focus</div>
<p>Build investor materials that clearly communicate the opportunity, traction, and your team's ability to execute.</p>
<ul><li>Develop a 10–15 slide pitch deck (problem, solution, market, traction, team, ask)</li>
<li>Build a 3–5 year financial model with bottom-up revenue projections</li>
<li>Create a data room: cap table, legal docs, customer contracts</li>
<li>Prepare responses to the 20 most common investor questions</li></ul>
<p><strong>Key Deliverable:</strong> Investor-ready pitch deck and financial model. See Documents section for templates.</p>
</div>`,'📊')}
${acc('s5','Stage 5','Fundraising &amp; Team Building',`<div class="stage-detail">
<div class="stage-focus">Focus</div>
<p>Secure capital to scale operations and build a world-class team to execute your vision.</p>
<div class="funding-row">
  <div class="funding-box"><div class="amt">$50K–$500K</div><div class="stg">Pre-Seed<br><span style="font-size:10px;color:var(--text-muted)">Grants, angels, accelerators</span></div></div>
  <div class="funding-box"><div class="amt">$500K–$2M</div><div class="stg">Seed<br><span style="font-size:10px;color:var(--text-muted)">Angel investors, seed VCs</span></div></div>
  <div class="funding-box"><div class="amt">$2M–$15M</div><div class="stg">Series A<br><span style="font-size:10px;color:var(--text-muted)">VCs focused on scaling</span></div></div>
</div>
<ul style="margin-top:12px"><li>Technical co-founder or CTO (if tech-heavy)</li>
<li>Sales/BD leader with agricultural connections</li>
<li>Advisory board with industry credibility</li>
<li>Consider fractional roles before full-time hires</li></ul>
</div>`,'🚀')}
</div>

<div class="card"><h3>🎯 Key AgTech Programs &amp; Opportunities</h3><div class="sub">Impactful programs designed to support AgTech founders</div>
${tabs('progs',[
  {label:'Accelerators',content:`
    ${prog('SVG Ventures | THRIVE','Leading global AgTech accelerator — 2026 Challenge open','THRIVE is the premier AgTech-focused accelerator. 2026 Global Impact Challenge: apply by May 15, up to $1M investment. Themes: climate, soil health, water, biodiversity, food security. Summit Oct 15 in Silicon Valley. Pioneer Fund for early-stage.',['b-green:Global','b-blue:VC Network','b-purple:Corporate Partners'])}
    ${prog('Creative Destruction Lab (CDL)','Science-based seed-stage program','World-renowned seed-stage program for massively scalable companies with a strong AgTech stream. Intensive mentorship model.',['b-blue:Science-based','b-green:Mentor-driven','b-purple:High-growth'])}
    ${prog('Cultivator (Canada)','Powered by Protein Industries Canada','Accelerator program for plant-based protein and agri-food companies across Canada\'s Prairies.',['b-green:Plant protein','b-yellow:Agri-food','b-blue:Canadian focus'])}
    ${prog('Techstars Farm to Fork','Global food &amp; agriculture innovation','Part of the global Techstars network, specializing in food system innovation from farm to consumer.',['b-blue:Global'])}
    ${prog('Yield Lab','AgTech accelerator and venture fund','Multi-regional AgTech accelerator and venture fund across North America, Europe, and Latin America.',['b-purple:Multi-region'])}`},
  {label:'Pitch Competitions',content:`
    ${prog('Rabobank–FoodBytes!','Global food &amp; agriculture startup pitch','International pitch competition connecting early-stage food and agriculture startups with investors and corporate partners.',['b-blue:Global','b-green:Food & Ag'])}
    ${prog('Ag in Motion Innovation Showcase','Canada\'s largest outdoor ag show','Annual showcase for AgTech innovations at Canada\'s largest outdoor agricultural exhibition in Saskatchewan.',['b-green:Canada','b-yellow:Field demo'])}
    ${prog('FCC Young Farmer Award','Next-gen agricultural entrepreneurs','Recognition program for young Canadian agricultural entrepreneurs demonstrating innovation and leadership.',['b-green:Canada'])}`},
  {label:'Grants & Funding',content:`
    ${prog('Sustainable CAP','Federal-provincial agri-food funding (2023–2028)','Up to $3.5 billion over 5 years for programs strengthening competitiveness, innovation and resiliency in the agriculture and agri-food sector.',['b-green:Canada','b-blue:Federal','b-yellow:$3.5B total'])}
    ${prog('AgriInnovate','Repayable contributions for commercialization','Up to $10 million in repayable contributions to accelerate commercialization of innovative agri-food products and technologies.',['b-green:Canada','b-yellow:Up to $10M'])}
    ${prog('NRC IRAP (formerly SDTC)','Cleantech funding including ag innovations','SDTC was wound down in 2024. Clean technology agricultural projects are now supported through NRC IRAP and the Clean Growth Hub.',['b-green:Canada','b-purple:Cleantech'])}`},
  {label:'General Programs',content:`
    ${prog('Founder Institute','Global early-stage accelerator','The world\'s largest pre-seed startup accelerator, helping founders build enduring technology companies. Strong for first-time founders.',['b-blue:Global','b-green:Pre-seed'])}
    ${prog('North Forge','Manitoba incubator for science-based innovation','Manitoba\'s leading technology incubator supporting startups in agricultural technology, cleantech, and other science-based sectors.',['b-green:Manitoba','b-yellow:Science-based'])}
    ${prog('Bioenterprise','Ontario agri-technology development','Helps agri-technology businesses grow through advisory services, funding connections, and commercialization support across Canada.',['b-green:Canada','b-blue:Advisory'])}`}
])}</div>

<div class="card"><h3>🏆 Success Milestones &amp; Exit Opportunities</h3>
<div class="milestone-grid">
<div class="milestone"><h4>📈 Growth Financing</h4>
<p>Scale operations, expand geographically, build category leadership.</p>
<ul><li>Series A: $2M–$15M</li><li>Series B: $10M–$50M</li><li>Series C+: $50M+</li></ul></div>
<div class="milestone"><h4>🤝 Acquisition / Strategic Exit</h4>
<p>Acquired by larger agribusiness, tech company, or strategic partner.</p>
<ul><li>Agribusiness giants (Bayer, Corteva, Syngenta)</li><li>Food corporations (Cargill, ADM)</li><li>Tech companies (Microsoft, Google)</li></ul></div>
<div class="milestone"><h4>🏛️ IPO / Public Markets</h4>
<p>List on public markets after demonstrating sustained growth and category leadership.</p>
<ul><li>Typically $50M+ ARR threshold</li><li>NYSE / NASDAQ / TSX options</li><li>SPAC route for faster path</li></ul></div>
</div></div>`;}

function prog(name,sub,desc,tags){
  return `<div class="prog-card"><h4>${lnk(name,LINKS[name])}</h4><div class="prog-sub">${sub}</div><p>${desc}</p>
  <div class="tag-row">${tags.map(t=>{const[cl,lbl]=t.split(':');return`<span class="badge ${cl}">${lbl}</span>`;}).join('')}</div></div>`;
}

