// PAGE: GLOSSARY
// ════════════════════════════════════════════════
const GLOSS = {
  '🚜 Farm Operations & Equipment':[
    ['Row Spacing','Distance between crop rows, varies by crop type and machinery. Corn: 30", soybeans: 7.5–15", wheat: 6–8". Narrower rows often increase yield but require compatible equipment.'],
    ['No-Till','Farming practice that leaves soil undisturbed from harvest to planting. Reduces erosion, saves fuel, but requires specialized planters and different weed management.'],
    ['Swathing','Cutting crops and laying them in windrows to dry in the field before combining. Common for canola and some cereal crops.'],
    ['Straight Cut','Harvesting crops directly without swathing. Requires proper timing and crop maturity.'],
    ['Seeding Rate','Number of seeds planted per acre, measured in lbs/acre or seeds/ft². Critical for optimizing yield and plant population.'],
    ['Variable Rate Technology (VRT)','Precision ag technology that applies inputs (seed, fertilizer, pesticides) at varying rates across a field based on soil conditions or yield maps.'],
    ['GPS Guidance','Satellite navigation system used in farm equipment for precise field operations, reducing overlap and improving efficiency.'],
    ['Autosteer','Automatic steering system for farm equipment using GPS, allowing hands-free operation and precise field patterns.'],
  ],
  '🌾 Crop Management & Agronomy':[
    ['GDD (Growing Degree Days)','Heat unit measurement used to predict crop development stages. Each crop has specific GDD requirements for maturity.'],
    ['Canopy Closure','Point when crop leaves completely cover the soil surface. Important for weed competition and spray application timing.'],
    ['Lodging','When crops fall over due to weather, disease, or excessive nitrogen. Reduces yield and harvest efficiency.'],
    ['Sclerotinia (White Mold)','Fungal disease affecting many crops, especially canola and soybeans. Forms white cottony growth and hard black sclerotia.'],
    ['Fusarium Head Blight','Fungal disease in wheat and barley causing yield loss and mycotoxin contamination. Major quality concern.'],
    ['Herbicide Resistance','When weeds survive herbicide applications. Major management challenge requiring rotation of herbicide modes of action.'],
    ['Pre-Emergence','Herbicide application before crop or weed emergence. Critical timing for weed control programs.'],
    ['Plant Back Restrictions','Time period required between herbicide application and planting sensitive crops to avoid injury.'],
  ],
  '🌍 Soil & Fertility':[
    ['Soil Test','Laboratory analysis measuring soil pH, nutrient levels, and organic matter. Basis for fertilizer recommendations.'],
    ['CEC (Cation Exchange Capacity)','Soil\'s ability to hold positively charged nutrients. Higher CEC soils can hold more nutrients and are generally more productive.'],
    ['Soil pH','Measure of soil acidity/alkalinity (0–14 scale). Most crops prefer 6.0–7.5. Affects nutrient availability significantly.'],
    ['N-P-K','Primary macronutrients: Nitrogen (growth & yield), Phosphorus (root development & energy), Potassium (disease resistance & water use).'],
    ['Micronutrients','Essential elements needed in small amounts: iron, manganese, zinc, copper, boron, molybdenum. Deficiencies can limit yield.'],
    ['Organic Matter','Decomposed plant/animal material in soil. Improves water holding capacity, nutrient retention, and soil structure.'],
    ['Soil Compaction','Compression of soil particles reducing pore space. Limits root growth, water infiltration, and air movement.'],
    ['Field Capacity','Maximum amount of water soil can hold against gravity. Optimal moisture level for most field operations.'],
  ],
  '💻 Technology & Data':[
    ['Yield Map','Spatial representation of crop yield across a field, generated by combine harvesters with yield monitoring systems.'],
    ['NDVI (Normalized Difference Vegetation Index)','Satellite/drone measurement of crop health and vigor using light reflectance. Scale of -1 to +1.'],
    ['Prescription Map','Field map showing variable rate application zones for inputs like fertilizer or seed.'],
    ['Telematics','Technology combining telecommunications and data analytics to monitor and manage farm equipment remotely.'],
    ['IoT Sensors','Internet-connected devices measuring soil moisture, temperature, humidity, etc. for real-time field monitoring.'],
    ['Machine Learning','AI technology that learns from farm data to predict outcomes, detect problems, or optimize operations.'],
    ['Digital Twin','Virtual replica of a farm or field used for simulation and predictive modeling.'],
    ['Edge Computing','Processing data locally on farm equipment rather than sending to cloud, enabling real-time decisions.'],
  ],
  '📈 Business & Marketing':[
    ['Basis','Difference between local grain price and futures price. Reflects local supply/demand and transportation costs.'],
    ['Futures Contract','Agreement to buy/sell commodity at specific price and date. Used for price risk management.'],
    ['Crop Insurance','Federal program protecting farmers against yield or revenue losses. Premium costs shared with government.'],
    ['Cash Rent','Fixed annual payment for farmland rental. Common alternative to crop share arrangements.'],
    ['Crop Share','Land rental where landowner receives percentage of crop production instead of cash payment.'],
    ['Forward Contract','Agreement to deliver grain at future date for predetermined price. Provides price certainty.'],
    ['LDP (Loan Deficiency Payment)','Government payment when market price is below loan rate. Part of farm safety net programs.'],
    ['Conservation Compliance','Requirements to implement soil conservation practices to remain eligible for farm programs.'],
  ],
  '🐄 Livestock & Specialty':[
    ['TMR (Total Mixed Ration)','Complete feed mixture containing all nutrients for livestock. Ensures balanced nutrition.'],
    ['Brix','Measurement of sugar content in plants. Higher brix indicates better plant health and feed quality.'],
    ['Silage','Fermented, high-moisture stored fodder. Made from corn, alfalfa, or other crops for livestock feed.'],
    ['Grazing Management','Controlled livestock grazing to optimize pasture health and animal performance.'],
    ['Rotational Grazing','Moving livestock between paddocks to allow pasture recovery and maximize forage production.'],
    ['BCS (Body Condition Score)','Visual/physical assessment of livestock fat reserves. Scale varies by species (1–5 or 1–9).'],
    ['Estrus Synchronization','Hormonal treatment to control breeding cycles in livestock for improved reproductive efficiency.'],
    ['Feedlot','Confined area where livestock are fed high-energy rations for rapid weight gain before slaughter.'],
  ]
};
function pgGlossary(){
  const sections = Object.entries(GLOSS).map(([cat,terms],i)=>{
    const items = terms.map(([t,d])=>`<div class="acc-item"><div class="acc-item-title">${t}</div><div class="acc-item-desc">${d}</div></div>`).join('');
    const icon = cat.split(' ')[0];
    const name = cat.substring(cat.indexOf(' ')+1);
    return acc(`gl${i}`,name,'',items,icon,`${terms.length} terms`);
  }).join('');
  return `<div class="page-hdr"><h1>AgTech Glossary for Tech Founders</h1>
<p>Essential agricultural terminology and concepts for technology entrepreneurs entering the agtech space.</p></div>
<div class="card">${sections}</div>`;
}

