    return '<div style="margin-bottom:4px"><button onclick="closeEcoTrend()" style="background:none;border:1px solid var(--border);border-radius:6px;padding:6px 14px;font-size:12px;cursor:pointer;color:var(--text);font-weight:600;font-family:inherit;display:inline-flex;align-items:center;gap:5px">← Back</button><span style="font-size:15px;font-weight:700;margin-left:10px;color:var(--text)">' + t.name + '</span></div>'
