function analyzeCompanies(companies) {
  const total = companies.length;

  // Sector distribution
  const bySector = {};
  companies.forEach(c => { bySector[c.sector] = (bySector[c.sector]||0) + 1; });
  const sectorDist = Object.entries(bySector).sort((a,b) => b[1]-a[1]);

  // Geography
  const byGeo = {};
  companies.forEach(c => { byGeo[c.hq] = (byGeo[c.hq]||0) + 1; });
  const geoDist = Object.entries(byGeo).sort((a,b) => b[1]-a[1]);

  // Stage distribution
  const byStage = {};
  companies.forEach(c => { byStage[c.stage] = (byStage[c.stage]||0) + 1; });
  const stageDist = Object.entries(byStage).sort((a,b) => b[1]-a[1]);

  // Funding parsing (rough)
  function parseFunding(f) {
    if (!f) return 0;
    const num = parseFloat(f.replace(/[^0-9.]/g,''));
    if (f.includes('B')) return num * 1000;
    return num || 0;
  }

  // Total funding
  const totalFunding = companies.reduce((sum,c) => sum + parseFunding(c.funding), 0);

  // Top funded
  const topFunded = [...companies].sort((a,b) => parseFunding(b.funding) - parseFunding(a.funding)).slice(0,10);

  // Canadian companies
  const canadian = companies.filter(c => c.hq === 'Canada');

  // Repeat listers (appear on multiple lists)
  const repeats = companies.filter(c => c.list && c.list.includes(','));

  // Founding year distribution
  const byYear = {};
  companies.forEach(c => { if(c.yr) byYear[c.yr] = (byYear[c.yr]||0) + 1; });
  const yearDist = Object.entries(byYear).sort((a,b) => a[0]-b[0]);

  // Average age
  const ages = companies.filter(c=>c.yr).map(c => 2026 - c.yr);
  const avgAge = ages.length ? (ages.reduce((a,b)=>a+b,0)/ages.length).toFixed(1) : 0;

  return { total, sectorDist, geoDist, stageDist, totalFunding, topFunded, canadian, repeats, yearDist, avgAge };
}

