function pgSegments(){
  // For non-Canada regions, use the REGION_DATA segments
  if (_currentRegion !== 'ca') {
    const rd = REGION_DATA[_currentRegion];
    if (!rd || !rd.segments || !rd.segments.length) return '<div class="page-hdr"><h1>Industry Segments</h1><p>No detailed segment data available for this region yet. Check the <a href="#" onclick="go(\'ecosystem\',null);return false" style="color:var(--green)">Ecosystem Overview</a> for market insights.</p></div>';
    return `<div class="page-hdr"><h1>${rd.flag} ${rd.name} AgTech Industry Segments</h1>
<p>Overview of ${rd.country}'s agtech sectors with market size, adoption rates, and key players.</p></div>
<div class="seg-grid">${rd.segments.map(s=>`
<div class="seg-card" onclick="openEcoSegmentGo('${s.id}')">
  <h4>${s.icon} ${s.name}</h4>
  <p>${s.desc}</p>
  <div style="display:flex;align-items:center;justify-content:space-between;margin-top:4px">
    <span style="font-size:11px;color:var(--text-muted)">${s.marketSize.substring(0,50)}${s.marketSize.length>50?'...':''}</span>
    <span style="font-size:11px;color:var(--green)">▼ Details</span>
  </div>
</div>`).join('')}</div>`;
  }
  const segs=[
    {id:'prec',n:'Precision Farming & Digital Tools',d:'Data-driven farming, IoT sensors, satellite imagery, and farm management software.',g:'+12% YoY',
      opp:'Scalable digital tools for Prairie farms averaging 1,000+ acres.',
      cos:['Deveron','Semios','BinSentry','Farmers Edge','Conservis'],
      market:'~CA$2–3B market est. by 2027 — Prairie-led adoption (Grand View Research).',
      challenge:'Rural connectivity gaps limit real-time data use.'},
    {id:'auto',n:'Automation & Robotics',d:'Autonomous machinery, robotic systems, and AI-driven farm operations.',g:'+18% YoY',
      opp:'Labour shortages in grain and horticulture are driving fast adoption.',
      cos:['4AG Robotics','DOT Technology','Prairie Robotics','CNH Industrial'],
      market:'Strong growth across Western Canada; one of the fastest-moving segments.',
      challenge:'High capital cost; short Prairie field seasons compress ROI timelines.'},
    {id:'bio',n:'Agricultural Biotech & Crop Protection',d:'Biopesticides, biofertilizers, seed technologies, and biological crop protection innovations.',g:'+15% YoY',
      opp:'Biological inputs replacing synthetics as regulatory and consumer pressure increases.',
      cos:['Vive Crop Protection','Performance Plants','Iterion','BASF BioAg'],
      market:'Significant PIC Supercluster investment across the Prairies.',
      challenge:'Registration timelines of 3–7 years and high compliance costs.'},
    {id:'cea',n:'Indoor Farming & Controlled Environments',d:'Vertical farming, hydroponics, greenhouse technology, and controlled environment agriculture.',g:'+22% YoY',
      opp:'Year-round food production for Canadian urban centres with severe winters.',
      cos:['GoodLeaf Farms','Mucci Farms','Little Leaf Farms','Revol Greens'],
      market:'Fastest-growing segment globally; Canada has significant greenhouse capacity.',
      challenge:'High energy costs in Canadian climate; government incentives essential.'},
    {id:'food',n:'Food Tech & Supply Chain',d:'Food processing innovations, traceability, waste reduction, and supply chain optimization.',g:'+14% YoY',
      opp:'Cold chain optimization and traceability are critical for Canadian exports.',
      cos:['Milk Moovement','Provision Analytics','Entosystem','GreenLeaf Foods'],
      market:'Post-COVID supply chain transformation driving rapid investment.',
      challenge:'Legacy systems in food processing are slow to upgrade.'},
    {id:'alt',n:'Alternative Proteins & Cannabis Technology',d:'Plant-based proteins, cultured meat, novel ingredients, and cannabis sector innovations.',g:'+6.8% YoY',
      opp:'Canada\'s pulse and oilseed crops are ideal feedstock for protein extraction.',
      cos:['Protein Industries Canada','Merit Functional Foods','Roquette','NWF Agriculture'],
      market:'PIC Supercluster — federal $153M+ matched by private sector across plant protein projects.',
      challenge:'Consumer adoption slowed post-2022; sector maturing and consolidating.'},
  ];
  segs.forEach(s=>{ SEG_DETAILS[s.id]={name:s.n,growth:s.g,opp:s.opp,cos:s.cos,market:s.market,challenge:s.challenge}; });
  return `<div class="page-hdr"><h1>Canadian AgTech Industry Segments</h1>
<p>Overview of Canada's agtech sectors with notable companies, growth metrics, and founder opportunities. Click any card for details.</p></div>
<div class="ca-banner">🇨🇦 Canada — Data current as of Q2 2026 &nbsp;·&nbsp; Growth estimates from multiple industry reports; ranges may vary by source</div>
<div class="seg-grid">${segs.map(s=>`
<div class="seg-card" onclick="toggleSeg('${s.id}')">
  <h4>${s.n}</h4>
  <p>${s.d}</p>
  <div style="display:flex;align-items:center;justify-content:space-between;margin-top:4px">
    <div class="growth-tag">↑ ${s.g}</div>
    <span style="font-size:11px;color:var(--green)">▼ Details</span>
  </div>
</div>`).join('')}</div>`;
}

