                  <select style="padding:6px 10px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text);font-size:12px" onchange="updateVentureStatus(${idx},this.value);render('venture')" onclick="event.stopPropagation()">
                    <option value="New" ${(sub.status||'New')==='New'?'selected':''}>New</option>
                    <option value="Under Review" ${(sub.status||'New')==='Under Review'?'selected':''}>Under Review</option>
                    <option value="Approved" ${(sub.status||'New')==='Approved'?'selected':''}>Approved</option>
                    <option value="Declined" ${(sub.status||'New')==='Declined'?'selected':''}>Declined</option>
                  </select>
