function ventureValidateField(el, type) {
  const val = el.value.trim();
  let valid = true;
  let errEl = null;
  if (type === 'email') {
    errEl = document.getElementById('venture-email-err');
    if (val && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) valid = false;
  } else if (type === 'url') {
    errEl = document.getElementById('venture-linkedin-err');
    if (val) {
      try { new URL(val); if (!val.startsWith('http://') && !val.startsWith('https://')) valid = false; } catch(e) { valid = false; }
    }
  }
  if (errEl) {
    errEl.style.display = valid ? 'none' : 'block';
    el.style.borderColor = valid ? 'var(--border)' : '#dc2626';
  }
}

function ventureNextStep(targetStep) {
  // Read DOM values first in case onchange/oninput didn't fire
  const readDom = (sel) => { const el = document.querySelector(sel); return el ? el.value.trim() : ''; };

  if (_ventureStep === 0) {
    // Step 1: Your Idea — require name, pitch, sector
    const name = readDom('input[placeholder="e.g., GreenHarvest AI"]') || _ventureForm.name;
    const pitch = readDom('textarea[placeholder="What does your startup do in one sentence?"]') || _ventureForm.pitch;
    const sector = _ventureForm.sector;
    if (name) _ventureForm.name = name;
    if (pitch) _ventureForm.pitch = pitch;
    if (!_ventureForm.name) { toast('Please enter your startup/project name.'); return; }
    if (!_ventureForm.pitch) { toast('Please enter a one-line pitch.'); return; }
    if (!_ventureForm.sector) { toast('Please select an AgTech sector.'); return; }
  } else if (_ventureStep === 1) {
    // Step 2: Market & Problem — require problem + customers
    const problem = readDom('textarea[placeholder="Describe the problem..."]') || _ventureForm.problem;
    const customers = readDom('textarea[placeholder="Describe your ideal customer..."]') || _ventureForm.customers;
    if (problem) _ventureForm.problem = problem;
    if (customers) _ventureForm.customers = customers;
    if (!_ventureForm.problem) { toast('Please describe the problem you\'re solving.'); return; }
    if (!_ventureForm.customers) { toast('Please describe your target customers.'); return; }
  } else if (_ventureStep === 2) {
    // Step 3: You & Your Team — require name + email
    const fName = readDom('input[placeholder="Your full name"]') || _ventureForm.founderName || currentUser?.name;
    const fEmail = readDom('input[placeholder="Your email"]') || _ventureForm.founderEmail || currentUser?.email;
    const linkedIn = readDom('input[placeholder="https://linkedin.com/in/yourprofile"]') || _ventureForm.linkedinUrl;
    if (fName) _ventureForm.founderName = fName;
    if (fEmail) _ventureForm.founderEmail = fEmail;
    if (linkedIn) _ventureForm.linkedinUrl = linkedIn;
    if (!_ventureForm.founderName) { toast('Please enter your name.'); return; }
    if (!_ventureForm.founderEmail) { toast('Please enter your email.'); return; }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(_ventureForm.founderEmail)) { toast('Please enter a valid email address.'); return; }
    if (_ventureForm.linkedinUrl && _ventureForm.linkedinUrl.trim()) {
      const url = _ventureForm.linkedinUrl.trim();
      if (!url.startsWith('http://') && !url.startsWith('https://')) { toast('LinkedIn URL must start with https://'); return; }
      try { new URL(url); } catch(e) { toast('Please enter a valid LinkedIn URL.'); return; }
    }
  }
  // Step 4 (Goals & Needs) has no required fields — everything is optional
  _ventureStep = targetStep;
  render('venture');
}

async function submitVentureApplication(){
  // Auto-seed from currentUser if form fields weren't manually touched
  if (!_ventureForm.founderName && currentUser?.name) _ventureForm.founderName = currentUser.name;
  if (!_ventureForm.founderEmail && currentUser?.email) _ventureForm.founderEmail = currentUser.email;

  // Also read directly from DOM inputs in case oninput didn't fire (autopopulated values)
  const nameInput = document.querySelector('input[placeholder="Your full name"]');
  const emailInput = document.querySelector('input[placeholder="Your email"]');
  const linkedinInput = document.querySelector('input[placeholder="https://linkedin.com/in/yourprofile"]');
  if (nameInput && nameInput.value && !_ventureForm.founderName) _ventureForm.founderName = nameInput.value;
  if (emailInput && emailInput.value && !_ventureForm.founderEmail) _ventureForm.founderEmail = emailInput.value;
  if (linkedinInput && linkedinInput.value) _ventureForm.linkedinUrl = linkedinInput.value;

  // Validate required fields
  if(!_ventureForm.name || !_ventureForm.pitch || !_ventureForm.sector || !_ventureForm.founderName || !_ventureForm.founderEmail){
    alert('Please fill in all required fields: Startup Name, One-Line Pitch, Sector, Your Name, and Your Email.');
    return;
  }

  // Validate email format
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(_ventureForm.founderEmail)) {
    alert('Please enter a valid email address (e.g. you@example.com).');
    return;
  }

  // Validate LinkedIn URL if provided
  if (_ventureForm.linkedinUrl && _ventureForm.linkedinUrl.trim()) {
    const url = _ventureForm.linkedinUrl.trim();
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      alert('LinkedIn URL must start with https:// (e.g. https://linkedin.com/in/yourprofile).');
      return;
    }
    try { new URL(url); } catch(e) {
      alert('Please enter a valid LinkedIn URL (e.g. https://linkedin.com/in/yourprofile).');
      return;
    }
  }

  const submission = {
    id: Date.now().toString(),
    createdAt: new Date().toISOString(),
    status: 'New',
    ..._ventureForm
  };

  _ventureSubmissions.push(submission);
  localStorage.setItem('foc_venture_submissions', JSON.stringify(_ventureSubmissions));

  // Try to save to Supabase (fail silently if table doesn't exist)
  try{
    await _supabase.from('venture_submissions').insert([submission]);
  }catch(e){}

  // Update notification bell for admins
  updateNotifBell();

  // Show success modal
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.5);display:flex;align-items:center;justify-content:center;z-index:9999';
  const isGuest = !currentUser;
  modal.innerHTML = `<div style="background:var(--surface);border-radius:12px;padding:40px;max-width:500px;text-align:center;box-shadow:0 20px 60px rgba(0,0,0,.3)">
    <div style="font-size:48px;margin-bottom:16px">🎉</div>
    <h2 style="margin:0 0 12px 0;font-size:22px;font-weight:700;color:var(--text)">Your idea has been submitted!</h2>
    <p style="margin:0 0 24px 0;color:var(--text-muted);line-height:1.6;font-size:14px">The FounderOps Venture Studio team will review your submission and get back to you within 48 hours.</p>
    ${isGuest ? `<div style="background:var(--accent-bg,rgba(22,163,74,.05));border:1px solid rgba(22,163,74,.2);border-radius:10px;padding:16px;margin-bottom:20px;text-align:left">
      <p style="margin:0 0 10px;font-size:13px;font-weight:600;color:var(--text)">🔗 Want to track your submission?</p>
      <p style="margin:0 0 12px;font-size:12px;color:var(--text-muted);line-height:1.6">Create a free account to link this submission to your profile, get status updates, access market intelligence, and connect with mentors and investors.</p>
      <button onclick="dismissVentureToSignin(this)" style="width:100%;padding:10px;background:#16a34a;color:white;border:none;border-radius:8px;font-weight:600;cursor:pointer;font-size:13px">Create Free Account →</button>
    </div>
    <div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap">
      <button onclick="dismissVentureToStep0(this)" style="padding:10px 20px;background:var(--hover);color:var(--text);border:1px solid var(--border);border-radius:8px;font-weight:600;cursor:pointer;font-size:13px">Submit Another Idea</button>
      <button onclick="this.closest('[style*=fixed]').remove()" style="padding:10px 20px;background:none;color:var(--text-muted);border:none;font-size:13px;cursor:pointer">No thanks, I'm done</button>
    </div>` : `<div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap">
      <button onclick="dismissVentureToOverview(this)" style="padding:12px 28px;background:#16a34a;color:white;border:none;border-radius:8px;font-weight:600;cursor:pointer;font-size:14px">Explore the Platform →</button>
      <button onclick="dismissVentureToStep0(this)" style="padding:12px 28px;background:var(--hover);color:var(--text);border:1px solid var(--border);border-radius:8px;font-weight:600;cursor:pointer;font-size:14px">Submit Another Idea</button>
    </div>`}
  </div>`;
  document.body.appendChild(modal);
}

function vsEmailAction(type, email, name, startupName) {
  const firstName = (name || '').split(' ')[0] || 'there';
  const emails = {
    confirm: {
      subject: `We received your idea — ${startupName || 'Your Submission'} | FounderOps Center`,
      body: `Hi ${firstName},\n\nThank you for submitting your idea${startupName ? ' for ' + startupName : ''} to the FounderOps Venture Studio. We're excited to learn about what you're building.\n\nHere's what happens next:\n\n- Our team will review your submission within the next 30 days, or at our next monthly review — whichever comes first.\n- If we have questions, we'll reach out directly.\n- In the meantime, explore the FounderOps ecosystem — browse market data, connect with mentors, and discover accelerator programs at founderopscenter.com.\n\nYour idea matters. The AgTech ecosystem needs more people like you who are willing to think differently about how we grow, feed, and sustain.\n\nWe'll be in touch soon.\n\nBest,\nRussell Cole\nFounder, FounderOps Center\nfounderopscenter.com`
    },
    info: {
      subject: `Quick follow-up on ${startupName || 'your submission'} | FounderOps Center`,
      body: `Hi ${firstName},\n\nThanks again for submitting ${startupName || 'your idea'} to the FounderOps Venture Studio. We've reviewed your submission and are intrigued.\n\nWe'd love to learn a bit more before our next review. Could you help us with:\n\n1. [Specific question about the idea]\n2. [Specific question about the team/market]\n3. [Any additional context needed]\n\nNo rush — just reply to this email whenever you have a chance.\n\nBest,\nRussell Cole\nFounder, FounderOps Center`
    },
    call: {
      subject: `Let's talk about ${startupName || 'your idea'} — FounderOps Center`,
      body: `Hi ${firstName},\n\nThanks for submitting ${startupName || 'your idea'} to the FounderOps Venture Studio. We've been reviewing your submission and would love to connect for a quick call.\n\nWould any of these times work for a 20-minute chat?\n\n- [Option 1]\n- [Option 2]\n- [Option 3]\n\nOr feel free to book directly: https://calendly.com/[your-link]\n\nLooking forward to hearing more about what you're building.\n\nBest,\nRussell Cole\nFounder, FounderOps Center`
    },
    accept: {
      subject: `Great news — ${startupName || 'your idea'} has been accepted! | FounderOps Venture Studio`,
      body: `Hi ${firstName},\n\nI'm excited to let you know that ${startupName || 'your idea'} has been accepted into the FounderOps Venture Studio pipeline.\n\nWhat this means:\n\n- You'll be connected with relevant mentors and advisors in the AgTech ecosystem\n- We'll help you refine your pitch and strategy\n- You'll get visibility to our investor network when you're ready\n- Access to our full ecosystem of accelerators, market data, and founder resources\n\nNext step: Let's schedule a kickoff call to discuss your roadmap and how we can best support you.\n\nWould any of these times work?\n\n- [Option 1]\n- [Option 2]\n- [Option 3]\n\nCongratulations — let's build something great.\n\nBest,\nRussell Cole\nFounder, FounderOps Center\nfounderopscenter.com`
    },
    decline: {
      subject: `Update on ${startupName || 'your submission'} | FounderOps Center`,
      body: `Hi ${firstName},\n\nThank you for submitting ${startupName || 'your idea'} to the FounderOps Venture Studio. We appreciate you sharing your vision with us.\n\nAfter review, we've decided not to move forward with this particular idea at this time. This doesn't mean your idea isn't valuable — it may simply not be the right fit for our current focus areas.\n\nHere's how you can keep building:\n\n- Stay active on the platform — browse market data, connect with mentors, and discover opportunities at founderopscenter.com\n- You're welcome to submit a new idea anytime — we review submissions monthly\n- Connect with our accelerator partners who may be a great fit for your stage\n\nKeep innovating. The AgTech space needs more founders thinking about these problems.\n\nBest,\nRussell Cole\nFounder, FounderOps Center`
    }
  };
  const e = emails[type];
  if (!e) return;
  const mailto = 'mailto:' + encodeURIComponent(email) + '?subject=' + encodeURIComponent(e.subject) + '&body=' + encodeURIComponent(e.body);
  window.open(mailto, '_blank');
  toast('📧 Email draft opened for ' + (name || email));
}

async function vsStatusAction(idx, newStatus) {
  const sub = _ventureSubmissions[idx];
  if (!sub) return;
  const name = sub.founderName || '';
  const email = sub.founderEmail || '';
  const startupName = sub.name || '';

  if (!confirm((newStatus === 'Approved' ? '✅ Accept' : '❌ Decline') + ' "' + startupName + '" by ' + name + '?\n\nThis will update the status and open an email to notify them.')) return;

  // Update status
  sub.status = newStatus;
  localStorage.setItem('foc_venture_submissions', JSON.stringify(_ventureSubmissions));
  try {
    await _supabase.from('venture_submissions').update({ status: newStatus }).eq('id', sub.id);
  } catch(e) {}

  // Open the appropriate email
  vsEmailAction(newStatus === 'Approved' ? 'accept' : 'decline', email, name, startupName);

  toast((newStatus === 'Approved' ? '✅ Accepted' : '❌ Declined') + ': ' + startupName);
  render('admin');
}

async function vsSaveNotes(idx) {
  const sub = _ventureSubmissions[idx];
  if (!sub) return;
  const textarea = document.getElementById('vs-notes-' + idx);
  if (!textarea) return;
  const notes = textarea.value;
  sub.admin_notes = notes;
  localStorage.setItem('foc_venture_submissions', JSON.stringify(_ventureSubmissions));
  try {
    await _supabase.from('venture_submissions').update({ admin_notes: notes }).eq('id', sub.id);
  } catch(e) {}
  toast('💾 Notes saved');
}

async function updateVentureStatus(idx, newStatus) {
  const sub = _ventureSubmissions[idx];
  if (!sub) return;
  sub.status = newStatus;
  localStorage.setItem('foc_venture_submissions', JSON.stringify(_ventureSubmissions));
  // Persist to Supabase
  try {
    await _supabase.from('venture_submissions').update({ status: newStatus }).eq('id', sub.id);
  } catch(e) {}
  render(adminTab === 'venture_studio' ? 'admin' : 'venture');
}

async function loadVentureSubmissions() {
  if (_ventureSubmissionsLoaded) return _ventureSubmissions;
  try {
    const { data, error } = await _supabase.from('venture_submissions').select('*').order('createdAt', { ascending: false });
    if (!error && data && data.length > 0) {
      _ventureSubmissions = data;
      localStorage.setItem('foc_venture_submissions', JSON.stringify(data));
      _ventureSubmissionsLoaded = true;
      return data;
    }
  } catch(e) { console.log('venture_submissions table may not exist yet'); }
  // Fall back to localStorage
  _ventureSubmissionsLoaded = true;
  return _ventureSubmissions;
}

// ════════════════════════════════════════════════
// PAGE: ACCELERATOR HUB
// ════════════════════════════════════════════════
function pgAccelerators(){
  const countryFlags = {'US':'🇺🇸','France':'🇫🇷','Netherlands':'🇳🇱','Israel':'🇮🇱','Australia':'🇦🇺','Singapore':'🇸🇬','Canada':'🇨🇦','Poland':'🇵🇱','EU':'🇪🇺','Global':'🌐','Multiple':'🌎'};
  const regionMap = {'na':'North America','eu':'Europe','il':'Israel','au':'Australia/APAC','apac':'Asia-Pacific','latam':'Latin America'};
  const regionNames = {'all':'All','na':'North America','eu':'Europe','il':'Israel','au':'Australia/APAC','apac':'Asia-Pacific','latam':'Latin America'};
  const artifactTypes = {
    'business-plan':'📄 Business Plan',
    'pitch-deck':'📊 Pitch Deck',
    'video-pitch':'🎥 Video Pitch',
    'mvp-demo':'💻 MVP Demo',
    'team-bios':'👥 Team Bios',
    'financial-projections':'📈 Financial Projections',
    'customer-traction':'📋 Customer Traction Data',
    'prototype':'🔧 Working Prototype',
    'letter-of-intent':'📝 Letters of Intent'
  };

  function getFlag(country){
    return countryFlags[country] || '🌍';
  }

  function getReadinessState(accelerator){
    const requiredArtifacts = (accelerator.requirements || []).filter(r => {
      const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
      return key;
    });

    const completedCount = requiredArtifacts.filter(r => {
      const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
      return _founderProfile[key] === 'done';
    }).length;

    const total = requiredArtifacts.length;
    if(total === 0) return { badge:'🟢', text:'Ready to Apply', state:'ready' };
    if(completedCount === total) return { badge:'🟢', text:'Ready to Apply', state:'ready' };
    if(completedCount >= total - 2) return { badge:'🟡', text:'Almost Ready', state:'almost' };
    return { badge:'🔴', text:'Build Your Profile', state:'build' };
  }

  function getReadinessBorder(readiness){
    if(readiness.state === 'ready') return '2px solid #16a34a';
    if(readiness.state === 'almost') return '2px solid #eab308';
    return '2px solid #cbd5e1';
  }

  function getProgramIconColor(name){
    const colors = ['#3b82f6','#8b5cf6','#ec4899','#f59e0b','#10b981','#06b6d4','#6366f1','#14b8a6'];
    let hash = 0;
    for(let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
  }

  function filterPrograms(){
    let filtered = ACCELERATORS;
    if(_accelFilter.region !== 'all'){
      filtered = filtered.filter(a => a.region === _accelFilter.region);
    }
    if(_accelFilter.readiness && _accelFilter.readiness !== 'all'){
      filtered = filtered.filter(a => {
        const readiness = getReadinessState(a);
        return readiness.state === _accelFilter.readiness;
      });
    }
    if(_accelFilter.investmentRange && _accelFilter.investmentRange !== 'all'){
      filtered = filtered.filter(a => {
        const match = a.investment.match(/\d+/);
        if(!match) return true;
        const amount = parseInt(match[0]);
        switch(_accelFilter.investmentRange){
          case 'under50': return amount < 50;
          case '50to100': return amount >= 50 && amount < 100;
          case '100to250': return amount >= 100 && amount < 250;
          case 'over250': return amount >= 250;
          default: return true;
        }
      });
    }
    return filtered;
  }

  function getUniqueRegions(){
    return [...new Set(ACCELERATORS.map(a => a.region))].sort();
  }

  function calcStats(){
    const progs = filterPrograms();
    const regions = new Set();
    let totalInv = 0;
    let invCount = 0;
    let rolling = 0;

    ACCELERATORS.forEach(a => {
      regions.add(a.region);
      if(a.deadline.toLowerCase().includes('rolling')) rolling++;
      const invStr = a.investment.match(/\d+/);
      if(invStr){
        totalInv += parseInt(invStr[0]);
        invCount++;
      }
    });

    const avgInv = invCount > 0 ? '$' + Math.round(totalInv / invCount / 1000) + 'K' : 'N/A';
    return {
      total: ACCELERATORS.length,
      regions: regions.size,
      avgInv: avgInv,
      rolling: rolling,
      filtered: progs.length
    };
  }

  function renderDetailView(){
    const a = ACCELERATORS.find(prog => prog.id === _selectedAccelerator);
    if(!a) return '';

    const readiness = getReadinessState(a);
    const requiredCount = (a.requirements || []).filter(r => {
      const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
      return key;
    }).length;

    const completedCount = (a.requirements || []).filter(r => {
      const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
      return _founderProfile[key] === 'done';
    }).length;

    const hasReqs = (a.requirements || []).length > 0;
    const hasAlumni = (a.alumni || []).length > 0;
    const hasFocus = (a.focus || []).length > 0;
    const isRolling = a.deadline.toLowerCase().includes('rolling');

    let reqsHtml = '';
    if(hasReqs){
      reqsHtml = '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px;margin-top:16px"><h3 style="margin-top:0;margin-bottom:16px">Application Requirements</h3><div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">';
      a.requirements.forEach(req => {
        const key = Object.keys(artifactTypes).find(k => k === req || artifactTypes[k].includes(r));
        const artifactKey = key || req;
        const icon = artifactTypes[artifactKey] ? artifactTypes[artifactKey].split(' ')[0] : '📋';
        const label = artifactTypes[artifactKey] ? artifactTypes[artifactKey].substring(2) : req;
        const status = _founderProfile[artifactKey] || 'not-started';
        const isComplete = status === 'done';
        const statusColor = isComplete ? '#16a34a' : '#cbd5e1';
        const statusText = isComplete ? '✅ Done' : status === 'help' ? '⚠️ Need Help' : '⬜ Not Started';

        reqsHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px"><div style="display:flex;align-items:center;gap:8px"><span style="font-size:20px">' + icon + '</span><span style="flex:1;font-size:14px;font-weight:600">' + label + '</span></div><div style="margin-top:8px;font-size:12px;color:' + statusColor + ';font-weight:500">' + statusText + '</div><button onclick="trackProgram(' + a.id + ',\'' + artifactKey + '\');render(\'accelerators\')" style="margin-top:8px;width:100%;padding:6px 12px;background:var(--hover);border:1px solid var(--border);border-radius:6px;font-size:12px;font-weight:500;color:var(--text);cursor:pointer">Mark as Ready</button></div>';
      });
      reqsHtml += '</div></div>';
    }

    let alumniHtml = '';
    if(hasAlumni){
      alumniHtml = '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px;margin-top:16px"><h3 style="margin-top:0;margin-bottom:12px">Notable Alumni</h3><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px">';
      a.alumni.forEach(alum => {
        alumniHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px;font-size:13px;font-weight:500;color:var(--text);text-align:center">' + alum + '</div>';
      });
      alumniHtml += '</div></div>';
    }

    let focusHtml = '';
    if(hasFocus){
      focusHtml = '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px;margin-top:16px"><h3 style="margin-top:0;margin-bottom:12px">Focus Areas</h3><div style="display:flex;flex-wrap:wrap;gap:8px">';
      a.focus.forEach(f => {
        focusHtml += '<div style="padding:8px 14px;background:#ecfdf5;color:#059669;border-radius:16px;font-size:12px;font-weight:500">' + f.replace(/-/g,' ') + '</div>';
      });
      focusHtml += '</div></div>';
    }

    const allRequirementsMet = completedCount === requiredCount && requiredCount > 0;
    let applySection = '';
    // Application flow is on hold pending founder feedback
    applySection = '<div style="background:var(--card);border:2px solid #f59e0b;border-radius:12px;padding:24px;margin-top:16px;text-align:center"><div style="font-size:28px;margin-bottom:8px">⏸️</div><div style="font-size:15px;font-weight:700;color:var(--text);margin-bottom:6px">Application Flow On Hold</div><div style="font-size:13px;color:var(--text-muted);line-height:1.6;max-width:480px;margin:0 auto">We\'re gathering feedback from founders to build the best application experience possible. In the meantime, explore programs and prepare your materials — you\'ll be ready when applications open.</div><div style="margin-top:14px;padding:10px 16px;background:#fffbeb;border:1px solid #fcd34d;border-radius:8px;font-size:12px;color:#92400e;display:inline-block">📋 Complete the <strong>founding member questionnaire</strong> to help shape this feature</div></div>';

    const pmSection = '<div style="background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:20px;margin-top:20px"><div style="font-size:12px;font-weight:600;color:var(--text);text-transform:uppercase;margin-bottom:8px;opacity:0.7">For Program Managers</div><div style="padding:12px;background:#f0f9ff;border-left:4px solid #3b82f6;border-radius:4px;margin-bottom:12px"><div style="font-size:13px;color:#1e40af;line-height:1.5"><strong>FounderOps Center</strong> can be your application management platform. Pre-qualified applicants • Standardized profiles • Artifact verification • Pipeline tracking</div></div><button onclick="window.open(\'mailto:russellcolevop@gmail.com?subject=FounderOps Accelerator Program Dashboard\',\'_blank\')" style="width:100%;padding:10px 16px;background:#3b82f6;color:white;border:none;border-radius:6px;font-weight:600;cursor:pointer;font-size:13px">📧 Contact Russell Cole</button></div>';

    return '<div style="max-width:900px"><a href="#" onclick="closeAccelerator();return false" style="color:var(--green);font-size:14px;text-decoration:none;margin-bottom:20px;display:inline-block;font-weight:600">← Back to Programs</a><div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:24px;margin-bottom:20px"><div style="display:flex;align-items:flex-start;gap:16px;margin-bottom:20px"><div style="width:60px;height:60px;border-radius:8px;background:' + getProgramIconColor(a.name) + ';display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:700;color:white;flex-shrink:0">' + a.name.charAt(0) + '</div><div style="flex:1"><h1 style="font-size:26px;font-weight:800;color:var(--text);margin:0 0 4px 0">' + a.name + '</h1><div style="color:var(--text-muted);font-size:14px">' + a.org + '</div></div></div><div style="display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px"><div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:10px 14px;font-size:13px;font-weight:500">📍 ' + a.location + '</div><div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:10px 14px;font-size:13px;font-weight:500">⏱️ ' + a.duration + '</div><div style="background:#ecfdf5;border:1px solid #d1fae5;border-radius:8px;padding:10px 14px;font-size:13px;font-weight:500;color:#059669">💰 ' + a.investment + '</div><div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:10px 14px;font-size:13px;font-weight:500">📊 ' + a.equity + '</div><div style="background:' + (isRolling ? '#ecfdf5' : 'var(--surface)') + ';border:1px solid ' + (isRolling ? '#d1fae5' : 'var(--border)') + ';border-radius:8px;padding:10px 14px;font-size:13px;font-weight:500;color:' + (isRolling ? '#059669' : 'var(--text)') + '">📅 ' + (isRolling ? '✅ Rolling Applications' : a.deadline) + '</div></div><p style="color:var(--text-muted);line-height:1.6;margin:0">' + a.description + '</p></div>' + reqsHtml + focusHtml + alumniHtml + applySection + pmSection + '</div>';
  }

  function renderBrowse(){
    const stats = calcStats();
    const progs = filterPrograms();

    let html = '<div><div class="page-hdr"><h1>⚡ AgTech Accelerator Hub</h1><p>22 programs across 6 regions. Build your profile, then apply with one click.</p></div><div class="grid4" style="margin-bottom:20px"><div class="stat-card"><div class="stat-val">' + stats.total + '</div><div class="stat-lbl">Total Programs</div></div><div class="stat-card"><div class="stat-val">' + stats.regions + '</div><div class="stat-lbl">Active Regions</div></div><div class="stat-card"><div class="stat-val">' + stats.avgInv + '</div><div class="stat-lbl">Avg Investment</div></div><div class="stat-card"><div class="stat-val">' + stats.rolling + '</div><div class="stat-lbl">Rolling Deadlines</div></div></div>';

    html += '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:16px;margin-bottom:20px"><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px"><div><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Region</label><select onchange="_accelFilter.region=this.value;render(\'accelerators\')" style="width:100%;padding:8px 12px;border:1px solid var(--border);border-radius:7px;background:var(--surface);color:var(--text);font-size:13px"><option value="all">All Regions</option>';

    getUniqueRegions().forEach(r => {
      html += '<option value="' + r + '" ' + (_accelFilter.region === r ? 'selected' : '') + '>' + (regionNames[r] || r) + '</option>';
    });

    html += '</select></div><div><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Readiness</label><select onchange="_accelFilter.readiness=this.value;render(\'accelerators\')" style="width:100%;padding:8px 12px;border:1px solid var(--border);border-radius:7px;background:var(--surface);color:var(--text);font-size:13px"><option value="all">All Programs</option><option value="ready" ' + (_accelFilter.readiness === 'ready' ? 'selected' : '') + '>🟢 Ready to Apply</option><option value="almost" ' + (_accelFilter.readiness === 'almost' ? 'selected' : '') + '>🟡 Almost Ready</option><option value="build" ' + (_accelFilter.readiness === 'build' ? 'selected' : '') + '>🔴 Build Your Profile</option></select></div><div><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Investment</label><select onchange="_accelFilter.investmentRange=this.value;render(\'accelerators\')" style="width:100%;padding:8px 12px;border:1px solid var(--border);border-radius:7px;background:var(--surface);color:var(--text);font-size:13px"><option value="all">All Ranges</option><option value="under50" ' + (_accelFilter.investmentRange === 'under50' ? 'selected' : '') + '>&lt;$50K</option><option value="50to100" ' + (_accelFilter.investmentRange === '50to100' ? 'selected' : '') + '>$50K-$100K</option><option value="100to250" ' + (_accelFilter.investmentRange === '100to250' ? 'selected' : '') + '>$100K-$250K</option><option value="over250" ' + (_accelFilter.investmentRange === 'over250' ? 'selected' : '') + '>$250K+</option></select></div></div></div>';

    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:16px" class="accel-grid">';

    progs.forEach(a => {
      const readiness = getReadinessState(a);
      const requiredCount = (a.requirements || []).filter(r => {
        const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
        return key;
      }).length;

      const completedCount = (a.requirements || []).filter(r => {
        const key = Object.keys(artifactTypes).find(k => k === r || artifactTypes[k].includes(r));
        return _founderProfile[key] === 'done';
      }).length;

      const isRolling = a.deadline.toLowerCase().includes('rolling');
      const focusTags = (a.focus || []).slice(0,3).map(f => '<span style="display:inline-block;padding:4px 8px;background:#f0fdf4;color:#15803d;border-radius:4px;font-size:11px;margin-right:4px;margin-bottom:4px;font-weight:500">' + f.replace(/-/g,' ') + '</span>').join('');
      const flag = getFlag(a.country);

      html += '<div style="background:var(--card);border:' + getReadinessBorder(readiness) + ';border-radius:12px;padding:16px;cursor:pointer;transition:all .2s;display:flex;flex-direction:column" onclick="openAccelerator(' + a.id + ')" onmouseover="this.style.boxShadow=\'0 8px 16px rgba(0,0,0,.12)\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.boxShadow=\'\';this.style.transform=\'translateY(0)\'"><div style="display:flex;align-items:center;gap:12px;margin-bottom:12px"><div style="width:40px;height:40px;border-radius:6px;background:' + getProgramIconColor(a.name) + ';display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;color:white;flex-shrink:0">' + a.name.charAt(0) + '</div><div style="flex:1;min-width:0"><div style="font-size:14px;font-weight:700;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + a.name + '</div><div style="font-size:11px;color:var(--text-muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + a.org + '</div></div></div><div style="font-size:13px;margin-bottom:10px">📍 ' + flag + ' ' + a.location + '</div><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px"><span style="display:inline-block;padding:4px 10px;background:#ecfdf5;color:#059669;border-radius:6px;font-size:11px;font-weight:500">' + a.investment + '</span><span style="display:inline-block;padding:4px 10px;background:var(--surface);border:1px solid var(--border);border-radius:6px;font-size:11px;font-weight:500">' + a.equity + '</span><span style="display:inline-block;padding:4px 10px;background:var(--surface);border:1px solid var(--border);border-radius:6px;font-size:11px;font-weight:500">' + a.duration + '</span>' + (isRolling ? '<span style="display:inline-block;padding:4px 10px;background:#ecfdf5;color:#059669;border-radius:6px;font-size:11px;font-weight:500">✅ Rolling</span>' : '') + '</div><div style="margin-bottom:10px;font-size:12px">' + focusTags + '</div><div style="padding:10px;background:var(--surface);border-radius:8px;margin-bottom:12px;border:1px solid var(--border)"><div style="display:flex;align-items:center;gap:8px;margin-bottom:4px"><span style="font-size:16px">' + readiness.badge + '</span><span style="font-size:12px;font-weight:600;color:var(--text)">' + readiness.text + '</span></div><div style="font-size:11px;color:var(--text-muted)">' + completedCount + ' of ' + (requiredCount > 0 ? requiredCount : '0') + ' requirements met</div></div><div style="color:var(--green);font-size:13px;font-weight:600;margin-top:auto">View Details →</div></div>';
    });

    html += '</div></div>';
    return html;
  }

  function renderProfile(){
    const readinessCount = Object.values(_founderProfile).filter(v => v === 'done').length;
    const totalArtifacts = Object.keys(artifactTypes).length;
    const readinessPercent = totalArtifacts > 0 ? Math.round((readinessCount / totalArtifacts) * 100) : 0;

    const eligiblePrograms = ACCELERATORS.filter(a => {
      const readiness = getReadinessState(a);
      return readiness.state === 'ready';
    }).length;

    let html = '<div style="max-width:900px"><div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:24px;margin-bottom:20px"><div style="text-align:center;margin-bottom:20px"><div style="display:inline-block;position:relative;width:140px;height:140px"><svg viewBox="0 0 140 140" style="width:100%;height:100%"><circle cx="70" cy="70" r="65" fill="none" stroke="#e5e7eb" stroke-width="8"/><circle cx="70" cy="70" r="65" fill="none" stroke="#16a34a" stroke-width="8" stroke-dasharray="' + (readinessPercent * 4.08) + ' 408" stroke-linecap="round" style="transform:rotate(-90deg);transform-origin:70px 70px"/></svg><div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);text-align:center"><div style="font-size:32px;font-weight:800;color:var(--green)">' + readinessPercent + '%</div><div style="font-size:12px;color:var(--text-muted);margin-top:4px">Complete</div></div></div></div><div style="text-align:center;margin-bottom:8px"><div style="font-size:16px;font-weight:700;color:var(--text)">Your Readiness Score</div></div><div style="background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:16px;text-align:center"><div style="font-size:13px;color:var(--text-muted);margin-bottom:4px">You\'re eligible for</div><div style="font-size:18px;font-weight:700;color:var(--green)">' + eligiblePrograms + ' of 22 programs</div><div style="font-size:12px;color:var(--text-muted);margin-top:4px">Ready-to-apply programs</div></div><div style="padding:12px;background:#f0fdf4;border:1px solid #dcfce7;border-radius:8px;text-align:center;font-size:12px;color:#166534">Complete ' + (totalArtifacts - readinessCount) + ' more artifact(s) to increase your eligible programs</div></div>';

    html += '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px;margin-bottom:20px"><h3 style="margin-top:0;margin-bottom:16px">Core Information</h3><div><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Startup Name</label><input type="text" value="' + (_founderProfile.startupName || '') + '" onchange="_founderProfile.startupName=this.value;render(\'accelerators\')" style="width:100%;padding:10px 14px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);font-size:14px;margin-bottom:12px;box-sizing:border-box"><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">One-Line Pitch</label><input type="text" value="' + (_founderProfile.pitch || '') + '" onchange="_founderProfile.pitch=this.value;render(\'accelerators\')" placeholder="What does your startup do?" style="width:100%;padding:10px 14px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);font-size:14px;margin-bottom:12px;box-sizing:border-box"><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Detailed Description</label><textarea style="width:100%;padding:10px 14px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);font-size:14px;resize:vertical;min-height:100px;margin-bottom:12px;box-sizing:border-box" onchange="_founderProfile.description=this.value" placeholder="Tell us more about your startup...">' + (_founderProfile.description || '') + '</textarea><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;text-transform:uppercase">Sector</label><select onchange="_founderProfile.sector=this.value;render(\'accelerators\')" style="width:100%;padding:10px 14px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);font-size:14px"><option value="">Select a sector...</option><option value="Precision Agriculture" ' + (_founderProfile.sector === 'Precision Agriculture' ? 'selected' : '') + '>Precision Agriculture</option><option value="Crop Protection" ' + (_founderProfile.sector === 'Crop Protection' ? 'selected' : '') + '>Crop Protection</option><option value="Animal Health" ' + (_founderProfile.sector === 'Animal Health' ? 'selected' : '') + '>Animal Health</option><option value="Food Safety" ' + (_founderProfile.sector === 'Food Safety' ? 'selected' : '') + '>Food Safety</option><option value="Supply Chain" ' + (_founderProfile.sector === 'Supply Chain' ? 'selected' : '') + '>Supply Chain</option><option value="Water Management" ' + (_founderProfile.sector === 'Water Management' ? 'selected' : '') + '>Water Management</option><option value="Biological Inputs" ' + (_founderProfile.sector === 'Biological Inputs' ? 'selected' : '') + '>Biological Inputs</option><option value="Robotics & Automation" ' + (_founderProfile.sector === 'Robotics & Automation' ? 'selected' : '') + '>Robotics & Automation</option><option value="Data & Analytics" ' + (_founderProfile.sector === 'Data & Analytics' ? 'selected' : '') + '>Data & Analytics</option><option value="Marketplace/Platform" ' + (_founderProfile.sector === 'Marketplace/Platform' ? 'selected' : '') + '>Marketplace/Platform</option><option value="Climate & Sustainability" ' + (_founderProfile.sector === 'Climate & Sustainability' ? 'selected' : '') + '>Climate & Sustainability</option><option value="Other" ' + (_founderProfile.sector === 'Other' ? 'selected' : '') + '>Other</option></select></div></div>';

    html += '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px;margin-bottom:20px"><h3 style="margin-top:0;margin-bottom:16px">Artifacts & Documents</h3><p style="font-size:12px;color:var(--text-muted);margin-bottom:16px">Mark each artifact as complete when you\'re ready. Click to cycle through states: Not Started → Done → Need Help → Not Started</p><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px">';

    Object.entries(artifactTypes).forEach(([key, label]) => {
      const status = _founderProfile[key] || 'not-started';
      const states = {
        'not-started': {bg:'#f8fafc', color:'#64748b', border:'#cbd5e1', icon:'⬜'},
        'done': {bg:'#ecfdf5', color:'#059669', border:'#dcfce7', icon:'✅'},
        'help': {bg:'#fffbeb', color:'#b45309', border:'#fef3c7', icon:'⚠️'}
      };
      const state = states[status];
      const nextStatus = status === 'not-started' ? 'done' : status === 'done' ? 'help' : 'not-started';

      html += '<div style="background:' + state.bg + ';border:2px solid ' + state.border + ';border-radius:8px;padding:12px;cursor:pointer;transition:all .2s;text-align:center" onclick="_founderProfile[\'' + key + '\']=\'' + nextStatus + '\';render(\'accelerators\')" onmouseover="this.style.opacity=0.8" onmouseout="this.style.opacity=1"><div style="font-size:14px;font-weight:600;color:' + state.color + ';margin-bottom:6px">' + state.icon + '</div><div style="font-size:13px;font-weight:600;color:' + state.color + ';margin-bottom:4px">' + label.substring(label.indexOf(' ') + 1) + '</div><div style="font-size:11px;color:' + state.color + ';opacity:0.8">' + (status === 'not-started' ? 'Click to complete' : status === 'done' ? 'Done' : 'Need Help') + '</div></div>';
    });

    html += '</div></div>';

    html += '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:20px"><h3 style="margin-top:0;margin-bottom:16px">Program Eligibility</h3><p style="font-size:12px;color:var(--text-muted);margin-bottom:16px">See which programs match your profile based on your readiness level</p><div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:8px">';

    ACCELERATORS.forEach(a => {
      const readiness = getReadinessState(a);
      const borderColor = readiness.state === 'ready' ? '#16a34a' : readiness.state === 'almost' ? '#eab308' : '#cbd5e1';
      const bgColor = readiness.state === 'ready' ? '#ecfdf5' : readiness.state === 'almost' ? '#fffbeb' : '#f8fafc';

      html += '<div style="border:1px solid ' + borderColor + ';background:' + bgColor + ';border-radius:6px;padding:8px;cursor:pointer;font-size:11px;text-align:center;font-weight:500;transition:all .2s" onclick="openAccelerator(' + a.id + ')" onmouseover="this.style.boxShadow=\'0 4px 8px rgba(0,0,0,.1)\'" onmouseout="this.style.boxShadow=\'\'"><div style="margin-bottom:4px">' + readiness.badge + '</div><div style="color:var(--text);font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + a.name.substring(0, 12) + '</div></div>';
    });

    html += '</div></div></div>';
    return html;
  }

  function renderTracker(){
    const apps = _founderProfile.applications || [];

    if(apps.length === 0){
      return '<div style="max-width:600px"><div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:40px;text-align:center"><div style="font-size:40px;margin-bottom:12px">🎯</div><h2 style="font-size:18px;font-weight:700;color:var(--text);margin:0 0 8px 0">No applications yet</h2><p style="color:var(--text-muted);margin:0 0 16px 0">Browse programs and start applying to track your progress</p><button onclick="setAccelTab(\'browse\')" style="padding:12px 24px;background:var(--green);color:white;border:none;border-radius:8px;font-weight:600;cursor:pointer;font-size:14px">Browse Programs →</button></div></div>';
    }

    const statuses = ['Interested','Preparing','Applied','Interview','Accepted','Declined'];
    let html = '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:16px">';

    statuses.forEach(status => {
      const statusApps = apps.filter(a => a.status === status || (status === 'Interested' && !a.status));
      const statusColors = {
        'Interested':'#e0e7ff',
        'Preparing':'#fef3c7',
        'Applied':'#dbeafe',
        'Interview':'#fce7f3',
        'Accepted':'#ecfdf5',
        'Declined':'#fee2e2'
      };
      const statusIcons = {
        'Interested':'🔖',
        'Preparing':'⚙️',
        'Applied':'📤',
        'Interview':'💬',
        'Accepted':'🎉',
        'Declined':'❌'
      };

      html += '<div style="background:' + (statusColors[status] || 'var(--surface)') + ';border:1px solid var(--border);border-radius:12px;padding:16px"><div style="display:flex;align-items:center;gap:8px;margin-bottom:12px"><span style="font-size:20px">' + statusIcons[status] + '</span><h3 style="margin:0;font-size:14px;font-weight:700;color:var(--text)">' + status + '</h3><span style="margin-left:auto;background:var(--surface);border-radius:12px;padding:2px 8px;font-size:12px;font-weight:600;color:var(--text)">' + statusApps.length + '</span></h3><div style="space-y:8px">';

      statusApps.forEach(app => {
        const prog = ACCELERATORS.find(p => p.id === app.programId);
        if(prog){
          html += '<div style="background:white;border:1px solid var(--border);border-radius:6px;padding:8px;margin-bottom:8px;font-size:12px"><div style="font-weight:600;color:var(--text);margin-bottom:2px">' + prog.name + '</div><div style="color:var(--text-muted);font-size:11px">Added ' + new Date(app.addedAt).toLocaleDateString() + '</div></div>';
        }
      });

      html += '</div></div>';
    });

    html += '</div>';
    return html;
  }

  function trackProgram(programId, status){
    if(!_founderProfile.applications) _founderProfile.applications = [];
    const existing = _founderProfile.applications.find(a => a.programId === programId);
    if(existing){
      existing.status = status;
      existing.updatedAt = new Date().toISOString();
    } else {
      _founderProfile.applications.push({
        programId: programId,
        status: status,
        addedAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
      });
    }
  }

  if(!_accelFilter) _accelFilter = { region: 'all', readiness: 'all', investmentRange: 'all' };

  if(_selectedAccelerator){
    return renderDetailView();
  }

  function renderPartnerEcosystems() {
    if (_selectedPartnerEco) {
      const eco = PARTNER_ECOSYSTEMS.find(e => e.id === _selectedPartnerEco);
      if (!eco) { _selectedPartnerEco = null; return renderPartnerEcosystems(); }
      const persona = _userProfile?.persona;
      // Check if signed-in user is this ecosystem's manager (by matching claimed ecosystems)
      const userEcos = currentUser ? getUserEcosystems(currentUser.id) : [];
      const isThisEcoManager = currentUser && _userProfile && (
        (_userProfile.full_name && _userProfile.full_name === eco.manager) ||
        userEcos.some(ue => ue.ecoId === eco.id) ||
        isUserAdmin(currentUser.email)
      );
      const isCurrentUser = isThisEcoManager;
      const isFounder = persona === 'founder';
      const isEcoMgr = persona === 'ecosystem_manager';

      let detailHtml = '<div style="max-width:800px"><button onclick="closePartnerEco()" style="display:flex;align-items:center;gap:6px;padding:8px 14px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);font-size:13px;cursor:pointer;margin-bottom:20px">← Back to Partner Ecosystems</button>';

      detailHtml += '<div style="background:var(--card);border:2px solid ' + eco.color + '33;border-radius:16px;padding:28px;margin-bottom:20px">';
      detailHtml += '<div style="display:flex;align-items:center;gap:16px;margin-bottom:20px;flex-wrap:wrap">';
      detailHtml += '<div style="width:60px;height:60px;border-radius:12px;background:' + eco.color + ';display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:800;color:white;flex-shrink:0">' + eco.shortName.charAt(0) + '</div>';
      detailHtml += '<div style="flex:1;min-width:200px"><div style="font-size:20px;font-weight:800;color:var(--text);margin-bottom:4px">' + eco.name + '</div>';
      detailHtml += '<div style="font-size:13px;color:var(--text-muted)">' + eco.org + '</div></div>';
      if (eco.claimed) detailHtml += '<span style="padding:6px 14px;background:#ecfdf5;color:#059669;border-radius:20px;font-size:12px;font-weight:600">✅ Active on Platform</span>';
      else detailHtml += '<span style="padding:6px 14px;background:#fef3c7;color:#92400e;border-radius:20px;font-size:12px;font-weight:600">🔓 Open — Claim as Manager</span>';
      detailHtml += '</div>';

      detailHtml += '<p style="font-size:14px;line-height:1.7;color:var(--text);margin-bottom:20px">' + eco.description + '</p>';

      detailHtml += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:20px">';
      detailHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center"><div style="font-size:20px;font-weight:800;color:' + eco.color + '">' + eco.startupCount + '</div><div style="font-size:11px;color:var(--text-muted);margin-top:4px">Startups Supported</div></div>';
      detailHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center"><div style="font-size:20px;font-weight:800;color:' + eco.color + '">' + eco.founded + '</div><div style="font-size:11px;color:var(--text-muted);margin-top:4px">Founded</div></div>';
      detailHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center"><div style="font-size:14px;font-weight:700;color:' + eco.color + '">📍 ' + eco.location + '</div><div style="font-size:11px;color:var(--text-muted);margin-top:4px">Location</div></div>';
      detailHtml += '<div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center"><div style="font-size:14px;font-weight:700;color:' + eco.color + '">' + eco.type + '</div><div style="font-size:11px;color:var(--text-muted);margin-top:4px">Program Type</div></div>';
      detailHtml += '</div>';

      detailHtml += '<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:700;color:var(--text);text-transform:uppercase;margin-bottom:8px">Focus Areas</div><div style="display:flex;flex-wrap:wrap;gap:6px">';
      eco.focus.forEach(f => { detailHtml += '<span style="padding:5px 12px;background:' + eco.color + '15;color:' + eco.color + ';border-radius:6px;font-size:12px;font-weight:500">' + f + '</span>'; });
      detailHtml += '</div></div>';

      detailHtml += '<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:700;color:var(--text);text-transform:uppercase;margin-bottom:8px">Program Highlights</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
      eco.highlights.forEach(h => { detailHtml += '<div style="display:flex;align-items:center;gap:8px;padding:10px 12px;background:var(--surface);border:1px solid var(--border);border-radius:8px;font-size:13px;color:var(--text)"><span style="color:' + eco.color + ';font-weight:700">✦</span> ' + h + '</div>'; });
      detailHtml += '</div></div>';

      detailHtml += '<div style="margin-bottom:20px"><div style="font-size:12px;font-weight:700;color:var(--text);text-transform:uppercase;margin-bottom:8px">Program Manager</div>';
      detailHtml += '<div style="display:flex;align-items:center;gap:12px;padding:14px;background:var(--surface);border:1px solid var(--border);border-radius:10px">';
      const _mgrIsOpen = !eco.claimed && /open|available|claim|tbd/i.test(eco.manager || '');
      const _mgrInitials = _mgrIsOpen ? '🔓' : (eco.manager||'').split(' ').map(w=>w[0]).join('').slice(0,3);
      detailHtml += '<div style="width:44px;height:44px;border-radius:50%;background:' + (_mgrIsOpen ? 'var(--hover)' : eco.color) + ';display:flex;align-items:center;justify-content:center;color:' + (_mgrIsOpen ? 'var(--text-muted)' : 'white') + ';font-weight:700;font-size:16px;border:' + (_mgrIsOpen ? '2px dashed var(--border)' : 'none') + '">' + _mgrInitials + '</div>';
      detailHtml += '<div style="flex:1"><div style="font-weight:700;color:' + (_mgrIsOpen ? 'var(--text-muted)' : 'var(--text)') + '">' + (_mgrIsOpen ? 'Available to claim' : eco.manager) + '</div><div style="font-size:12px;color:var(--text-muted)">' + eco.managerTitle + ' · ' + eco.org + '</div></div>';
      if (currentUser && isFounder) {
        detailHtml += '<button onclick="alert(\'Request introduction feature coming soon! For now, reach out to ' + eco.manager + ' directly.\')" style="padding:6px 12px;background:' + eco.color + ';color:white;border:none;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap">Request Intro</button>';
      }
      detailHtml += '</div></div>';

      // Action buttons
      detailHtml += '<div style="display:flex;gap:10px;flex-wrap:wrap;padding-top:16px;border-top:1px solid var(--border)">';
      if (eco.website) {
        detailHtml += '<button onclick="window.open(\'' + eco.website + '\',\'_blank\')" style="padding:12px 20px;background:var(--surface);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;font-weight:600;cursor:pointer">🌐 Visit Website</button>';
      }
      if (isFounder && !isThisEcoManager) {
        detailHtml += '<button onclick="alert(\'⏸️ Application flow is on hold while we gather founder feedback. In the meantime, reach out directly to ' + eco.manager + ' or apply through their website.\')" style="padding:12px 20px;background:#f59e0b;border:none;border-radius:8px;color:white;font-size:13px;font-weight:600;cursor:pointer">⏸️ Applications On Hold — Contact Directly</button>';
      }
      if (!eco.claimed && (isEcoMgr || isAdmin)) {
        detailHtml += '<button onclick="ecoClaimPartner(\'' + eco.id + '\')" style="padding:12px 20px;background:linear-gradient(135deg,#f59e0b,#d97706);border:none;border-radius:8px;color:white;font-size:13px;font-weight:600;cursor:pointer">🔑 Claim as Manager</button>';
      }
      if (eco.claimed && isCurrentUser) {
        detailHtml += '<button onclick="go(\'ecosystem_ws\')" style="padding:12px 20px;background:var(--green);border:none;border-radius:8px;color:white;font-size:13px;font-weight:600;cursor:pointer">📊 Open Your Workspace</button>';
      }
      detailHtml += '</div></div></div>';
      return detailHtml;
    }

    // Grid view
    const _caCount = PARTNER_ECOSYSTEMS.filter(e => e.country === 'CA').length;
    const _openCount = PARTNER_ECOSYSTEMS.filter(e => !e.claimed).length;
    let html = '<div><div class="page-hdr"><h1>🤝 Partner Ecosystems</h1><p>' + PARTNER_ECOSYSTEMS.length + ' programs on the platform — including <strong>' + _caCount + ' Canadian AgTech ecosystems</strong> pre-loaded and ready to claim. One platform for the entire Canadian ecosystem — no more patchwork, just streamlined efficiency across every region.</p>' +
      '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:14px">' +
        '<span style="padding:6px 14px;background:#ecfdf5;color:#059669;border:1px solid #a7f3d0;border-radius:20px;font-size:12px;font-weight:600">🇨🇦 ' + _caCount + ' Canadian programs</span>' +
        '<span style="padding:6px 14px;background:#fef3c7;color:#92400e;border:1px solid #fcd34d;border-radius:20px;font-size:12px;font-weight:600">🔓 ' + _openCount + ' open to claim</span>' +
        '<span style="padding:6px 14px;background:#eff6ff;color:#1e40af;border:1px solid #bfdbfe;border-radius:20px;font-size:12px;font-weight:600">✨ Free for program managers</span>' +
      '</div></div>';

    // "List Your Ecosystem" CTA
    html += '<div style="background:linear-gradient(135deg,#f0fdf4,#ecfdf5);border:2px solid var(--green-mid);border-radius:14px;padding:20px;margin-bottom:20px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px">';
    html += '<div style="flex:1;min-width:200px"><div style="font-size:15px;font-weight:700;color:var(--text);margin-bottom:4px">Run an AgTech program?</div><div style="font-size:13px;color:var(--text-muted)">List your accelerator, incubator, or innovation hub on FounderOps Center. Get a verified profile, Ecosystem Workspace, and cross-network intelligence.</div></div>';
    html += '<button onclick="openListEcosystemForm()" style="padding:12px 24px;background:linear-gradient(135deg,var(--green),#059669);color:#fff;border:none;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;white-space:nowrap;box-shadow:0 4px 12px rgba(22,163,74,.25)">List Your Ecosystem →</button>';
    html += '</div>';

    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:16px">';
    PARTNER_ECOSYSTEMS.forEach(eco => {
      html += '<div style="background:var(--card);border:2px solid ' + eco.color + '22;border-radius:14px;padding:20px;cursor:pointer;transition:all .2s" onclick="openPartnerEco(\'' + eco.id + '\')" onmouseover="this.style.boxShadow=\'0 8px 20px ' + eco.color + '22\';this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.boxShadow=\'\';this.style.transform=\'translateY(0)\'">';

      // Header
      html += '<div style="display:flex;align-items:center;gap:12px;margin-bottom:14px">';
      html += '<div style="width:48px;height:48px;border-radius:10px;background:' + eco.color + ';display:flex;align-items:center;justify-content:center;font-size:20px;font-weight:800;color:white;flex-shrink:0">' + eco.shortName.charAt(0) + '</div>';
      html += '<div style="flex:1;min-width:0"><div style="font-size:15px;font-weight:700;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + eco.shortName + '</div>';
      html += '<div style="font-size:11px;color:var(--text-muted)">' + eco.org + '</div></div>';
      if (eco.claimed) html += '<span style="padding:3px 8px;background:#ecfdf5;color:#059669;border-radius:10px;font-size:10px;font-weight:600">Active</span>';
      else html += '<span style="padding:3px 8px;background:#fef3c7;color:#92400e;border-radius:10px;font-size:10px;font-weight:600">Open</span>';
      html += '</div>';

      // Info
      html += '<div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">📍 ' + eco.location + ' · ' + eco.type + '</div>';

      // Focus tags
      html += '<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:12px">';
      eco.focus.slice(0, 3).forEach(f => { html += '<span style="padding:3px 8px;background:' + eco.color + '12;color:' + eco.color + ';border-radius:4px;font-size:10px;font-weight:500">' + f + '</span>'; });
      if (eco.focus.length > 3) html += '<span style="padding:3px 8px;background:var(--surface);border:1px solid var(--border);border-radius:4px;font-size:10px;color:var(--text-muted)">+' + (eco.focus.length - 3) + '</span>';
      html += '</div>';

      // Manager
      const _cardMgrOpen = !eco.claimed && /open|available|claim|tbd/i.test(eco.manager || '');
      const _cardInitials = _cardMgrOpen ? '🔓' : (eco.manager||'').split(' ').map(w=>w[0]).join('').slice(0,3);
      html += '<div style="display:flex;align-items:center;gap:8px;padding:10px;background:var(--surface);border:1px solid var(--border);border-radius:8px;margin-bottom:12px">';
      html += '<div style="width:28px;height:28px;border-radius:50%;background:' + (_cardMgrOpen ? 'var(--hover)' : eco.color) + ';display:flex;align-items:center;justify-content:center;color:' + (_cardMgrOpen ? 'var(--text-muted)' : 'white') + ';font-weight:700;font-size:10px;border:' + (_cardMgrOpen ? '1px dashed var(--border)' : 'none') + '">' + _cardInitials + '</div>';
      html += '<div><div style="font-size:12px;font-weight:600;color:' + (_cardMgrOpen ? 'var(--text-muted)' : 'var(--text)') + '">' + (_cardMgrOpen ? 'Available to claim' : eco.manager) + '</div><div style="font-size:10px;color:var(--text-muted)">' + eco.managerTitle + '</div></div></div>';

      // Stats
      html += '<div style="display:flex;gap:16px;font-size:11px;color:var(--text-muted)">';
      html += '<span><strong style="color:var(--text)">' + eco.startupCount + '</strong> startups</span>';
      html += '<span>Est. <strong style="color:var(--text)">' + eco.founded + '</strong></span>';
      html += '</div>';

      // Footer
      html += '<div style="margin-top:12px;color:' + eco.color + ';font-size:12px;font-weight:600">View Details →</div>';
      html += '</div>';
    });
    html += '</div></div>';
    return html;
  }

  let tabHtml = '<div style="display:flex;gap:8px;margin-bottom:20px;border-bottom:1px solid var(--border);padding-bottom:12px;flex-wrap:wrap" class="accel-tabs"><button onclick="setAccelTab(\'partners\')" style="padding:10px 16px;border:none;background:' + (_accelTab === 'partners' ? 'var(--green)' : 'transparent') + ';color:' + (_accelTab === 'partners' ? 'white' : 'var(--text-muted)') + ';border-radius:6px;cursor:pointer;font-weight:600;font-size:13px;transition:all .2s">🤝 Partner Ecosystems</button><button onclick="setAccelTab(\'browse\')" style="padding:10px 16px;border:none;background:' + (_accelTab === 'browse' ? 'var(--green)' : 'transparent') + ';color:' + (_accelTab === 'browse' ? 'white' : 'var(--text-muted)') + ';border-radius:6px;cursor:pointer;font-weight:600;font-size:13px;transition:all .2s">Browse Programs</button><button onclick="setAccelTab(\'profile\')" style="padding:10px 16px;border:none;background:' + (_accelTab === 'profile' ? 'var(--green)' : 'transparent') + ';color:' + (_accelTab === 'profile' ? 'white' : 'var(--text-muted)') + ';border-radius:6px;cursor:pointer;font-weight:600;font-size:13px;transition:all .2s">My Application Profile</button><button onclick="setAccelTab(\'tracker\')" style="padding:10px 16px;border:none;background:' + (_accelTab === 'tracker' ? 'var(--green)' : 'transparent') + ';color:' + (_accelTab === 'tracker' ? 'white' : 'var(--text-muted)') + ';border-radius:6px;cursor:pointer;font-weight:600;font-size:13px;transition:all .2s">Application Tracker</button></div>';

  if(_accelTab === 'partners') return tabHtml + renderPartnerEcosystems();
  if(_accelTab === 'profile') return tabHtml + renderProfile();
  if(_accelTab === 'tracker') return tabHtml + renderTracker();
  return tabHtml + renderBrowse();
}

