// ── USER TRACKING ─────────────────────────────────────────────────
// Platform admin state now lives in Supabase (profiles.is_platform_admin).
// Workspaces live in public.workspaces + public.workspace_members.
const RUSSELL_EMAIL = 'russellcolevop@gmail.com'; // root-owner protection only
let currentUser = null;
let isAdmin = false;
let sessionPageViews = [];
let _assumedUser = null; // admin impersonation state
let _userWorkspaces = []; // [{id, slug, name, workspace_type, owner_id, role, status}]
let _activeWorkspaceId = null;

function getLogins(){ return JSON.parse(localStorage.getItem('agtech_logins')||'[]'); }
function saveLogins(l){ localStorage.setItem('agtech_logins', JSON.stringify(l)); }

// Platform-admin check reads from the current user's loaded profile.
// Called synchronously across the UI, so it falls back to false when _userProfile
// hasn't loaded yet; the login flow re-evaluates `isAdmin` after the profile fetch.
function isUserAdmin(_emailIgnored){
  if (_userProfile && _userProfile.is_platform_admin === true) return true;
  // Legacy safety net: locally-approved admins (ops-only, persists across reloads).
  try {
    const legacy = JSON.parse(localStorage.getItem('agtech_admin_list')||'[]');
    if (currentUser && legacy.includes(currentUser.email)) return true;
  } catch(e){}
  return false;
}

// Workspace helpers
function hasWorkspaceAccess(workspaceType){
  if (!_userWorkspaces || _userWorkspaces.length === 0) return false;
  if (!workspaceType) return _userWorkspaces.some(w => w.status === 'active');
  return _userWorkspaces.some(w => w.status === 'active' && w.workspace_type === workspaceType);
}
function isWorkspaceMember(workspaceId){
  return !!(_userWorkspaces||[]).find(w => w.id === workspaceId && w.status === 'active');
}
function getActiveWorkspace(){
  if (!_userWorkspaces || _userWorkspaces.length === 0) return null;
  if (_activeWorkspaceId) {
    const w = _userWorkspaces.find(x => x.id === _activeWorkspaceId);
    if (w) return w;
  }
  // Default: first ecosystem workspace, else first workspace
  return _userWorkspaces.find(w => w.workspace_type === 'ecosystem') || _userWorkspaces[0];
}
function getActiveWorkspaceId(){
  const w = getActiveWorkspace();
  return w ? w.id : null;
}

// Loads all workspaces the current user is an active member of.
// Called from the login flow right after _userProfile is fetched.
async function loadUserWorkspaces(){
  _userWorkspaces = [];
  _activeWorkspaceId = null;
  if (!currentUser || !_supabase) return;
  try {
    const { data, error } = await _supabase
      .from('workspace_members')
      .select('role, status, workspace_id, workspaces:workspaces!inner(id, slug, name, workspace_type, owner_id, email_domain, description)')
      .eq('user_id', currentUser.id)
      .eq('status', 'active');
    if (error) { console.warn('loadUserWorkspaces error', error); return; }
    _userWorkspaces = (data||[]).map(row => ({
      id: row.workspaces.id,
      slug: row.workspaces.slug,
      name: row.workspaces.name,
      workspace_type: row.workspaces.workspace_type,
      owner_id: row.workspaces.owner_id,
      email_domain: row.workspaces.email_domain,
      description: row.workspaces.description,
      role: row.role,
      status: row.status,
    }));
    if (_userWorkspaces.length > 0) _activeWorkspaceId = (getActiveWorkspace()||{}).id || null;
  } catch(e) {
    console.warn('loadUserWorkspaces threw', e);
  }
}

// ── CLAIM FLOW ───────────────────────────────────────────────
// Works for all workspace types (ecosystem, investor, founder, advisor, other).
// Invites are stored in public.workspace_invites and redeemed via RPC claim_workspace(p_code).

// Stash a ?claim=<code> from the URL at page load (before auth kicks in).
// We hold it in memory + localStorage so it survives the OAuth round-trip.
let _pendingClaimCode = null;
(function captureClaimCode(){
  try {
    const p = new URLSearchParams(location.search);
    const code = p.get('claim');
    if (code && /^[A-Z0-9]{4,16}$/i.test(code.trim())) {
      _pendingClaimCode = code.trim().toUpperCase();
      localStorage.setItem('foc_pending_claim', _pendingClaimCode);
      // Clean URL so the code doesn't linger in history
      p.delete('claim');
      const next = location.pathname + (p.toString() ? '?' + p.toString() : '') + location.hash;
      history.replaceState({}, '', next);
    } else if (localStorage.getItem('foc_pending_claim')) {
      _pendingClaimCode = localStorage.getItem('foc_pending_claim');
    }
  } catch(e){ console.warn('captureClaimCode failed', e); }
})();

// Call claim_workspace RPC. Returns { ok, workspace?, errorCode?, message? }.
async function claimWorkspaceByCode(code){
  if (!_supabase) return { ok:false, errorCode:'NO_CLIENT', message:'Supabase not ready' };
  if (!currentUser) return { ok:false, errorCode:'NOT_SIGNED_IN', message:'Please sign in first' };
  try {
    const { data, error } = await _supabase.rpc('claim_workspace', { p_code: code });
    if (error) {
      const msg = error.message || '';
      const ec = /INVITE_NOT_FOUND/.test(msg) ? 'INVITE_NOT_FOUND'
              : /INVITE_EXPIRED/.test(msg) ? 'INVITE_EXPIRED'
              : /INVITE_EXHAUSTED/.test(msg) ? 'INVITE_EXHAUSTED'
              : /INVITE_EMAIL_MISMATCH/.test(msg) ? 'INVITE_EMAIL_MISMATCH'
              : /INVITE_DOMAIN_MISMATCH/.test(msg) ? 'INVITE_DOMAIN_MISMATCH'
              : 'ERROR';
      return { ok:false, errorCode:ec, message:msg };
    }
    return { ok:true, workspace:data };
  } catch(e) {
    return { ok:false, errorCode:'EXCEPTION', message:String(e) };
  }
}

// Call auto_join_by_domain RPC — attaches caller to any workspace whose
// email_domain matches their sign-in email, or any open domain-scoped invite.
async function autoJoinByDomain(){
  if (!_supabase || !currentUser) return 0;
  try {
    const { data, error } = await _supabase.rpc('auto_join_by_domain');
    if (error) { console.warn('auto_join_by_domain error', error); return 0; }
    return typeof data === 'number' ? data : 0;
  } catch(e) { console.warn('auto_join_by_domain threw', e); return 0; }
}

// Consume a pending claim after sign-in. Called right after loadUserWorkspaces().
async function consumePendingClaim(){
  const code = _pendingClaimCode || localStorage.getItem('foc_pending_claim');
  if (!code || !currentUser) return;
  const res = await claimWorkspaceByCode(code);
  if (res.ok) {
    _pendingClaimCode = null;
    localStorage.removeItem('foc_pending_claim');
    // Refresh memberships so the UI unlocks the newly-joined workspace.
    await loadUserWorkspaces();
    const ws = res.workspace || {};
    toast('✅ Joined workspace: ' + (ws.name || 'Workspace'));
  } else {
    // Surface a dismissible error but keep the code so the user can retry after
    // signing in with the right email (e.g. for email- or domain-gated invites).
    const friendly = {
      INVITE_NOT_FOUND: 'That invite code is invalid or has been revoked.',
      INVITE_EXPIRED: 'That invite code has expired.',
      INVITE_EXHAUSTED: 'That invite code has reached its use limit.',
      INVITE_EMAIL_MISMATCH: 'This invite is for a different email address. Sign in with the invited account.',
      INVITE_DOMAIN_MISMATCH: 'This invite requires an email from a specific company domain.',
    }[res.errorCode] || ('Could not claim workspace: ' + (res.message || res.errorCode));
    toast('⚠️ ' + friendly, 6000);
    // On permanent failures, drop the cached code so it doesn't keep firing.
    if (res.errorCode === 'INVITE_NOT_FOUND' || res.errorCode === 'INVITE_EXPIRED' || res.errorCode === 'INVITE_EXHAUSTED') {
      _pendingClaimCode = null;
      localStorage.removeItem('foc_pending_claim');
    }
  }
}

// Create an invite for a workspace via RPC. Returns the invite row.
async function createWorkspaceInvite(opts){
  if (!_supabase) return { ok:false, message:'Supabase not ready' };
  const body = {
    p_workspace_id: opts.workspace_id,
    p_role:         opts.role || 'member',
    p_email:        opts.email || null,
    p_email_domain: opts.email_domain || null,
    p_max_uses:     opts.max_uses || 1,
    p_expires_in:   opts.expires_in || null, // e.g. '7 days'
  };
  try {
    const { data, error } = await _supabase.rpc('create_invite', body);
    if (error) return { ok:false, message: error.message };
    return { ok:true, invite:data };
  } catch(e) { return { ok:false, message:String(e) }; }
}

// Revoke an invite via RPC.
async function revokeWorkspaceInvite(inviteId){
  if (!_supabase) return false;
  try {
    const { data, error } = await _supabase.rpc('revoke_invite', { p_invite_id: inviteId });
    if (error) { console.warn('revoke_invite error', error); return false; }
    return !!data;
  } catch(e) { return false; }
}

// Create a workspace from scratch via RPC.
async function createWorkspaceRPC(opts){
  if (!_supabase) return { ok:false, message:'Supabase not ready' };
  try {
    const { data, error } = await _supabase.rpc('create_workspace', {
      p_name:           opts.name,
      p_workspace_type: opts.workspace_type || 'ecosystem',
      p_email_domain:   opts.email_domain || null,
      p_description:    opts.description || '',
    });
    if (error) return { ok:false, message: error.message };
    return { ok:true, workspace:data };
  } catch(e) { return { ok:false, message:String(e) }; }
}

// Build a shareable claim URL for a code.
function buildClaimUrl(code){
  return location.origin + location.pathname + '?claim=' + encodeURIComponent(code);
}

// Render the Workspaces & Invites admin panel.
async function renderWorkspacesAdmin(){
  const root = document.getElementById('workspaces-admin-root');
  if (!root) return;
  if (!_supabase) { root.innerHTML = '<div class="card">Supabase not initialized.</div>'; return; }
  // Platform admin sees all; others see only those they own or are admin of
  let wsQuery = _supabase.from('workspaces').select('id, slug, name, workspace_type, owner_id, email_domain, description, created_at').order('created_at', { ascending: false });
  const { data: workspaces, error: wsErr } = await wsQuery;
  if (wsErr) { root.innerHTML = `<div class="card">Error loading workspaces: ${wsErr.message}</div>`; return; }
  const { data: invites } = await _supabase.from('workspace_invites').select('id, workspace_id, claim_code, email, email_domain, role, max_uses, uses, expires_at, revoked_at, created_at').order('created_at', { ascending: false });
  const byWs = {};
  (invites || []).forEach(i => { (byWs[i.workspace_id] = byWs[i.workspace_id] || []).push(i); });

  const esc = (s) => (s == null ? '' : String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])));
  const typeOptions = ['ecosystem','investor','founder','advisor','other'].map(t => `<option value="${t}">${t}</option>`).join('');

  let html = '';
  // Create workspace form (platform admin only)
  if (isUserAdmin()) {
    html += `<div class="card" style="margin-bottom:18px"><h3 style="margin-top:0">➕ Create Workspace</h3>
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px">
        <input id="new-ws-name" placeholder="Workspace name (e.g. Picketa)" style="padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text)" />
        <select id="new-ws-type" style="padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text)">${typeOptions}</select>
        <input id="new-ws-domain" placeholder="Email domain (optional, e.g. picketa.com)" style="padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text)" />
      </div>
      <textarea id="new-ws-desc" placeholder="Description (optional)" style="margin-top:10px;width:100%;padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--surface);color:var(--text);min-height:60px"></textarea>
      <button onclick="handleCreateWorkspaceClick()" class="btn btn-primary" style="margin-top:10px">Create Workspace</button>
    </div>`;
  }

  if (!workspaces || workspaces.length === 0) {
    html += '<div class="card">No workspaces yet. Create one above to get started.</div>';
    root.innerHTML = html;
    return;
  }

  workspaces.forEach(w => {
    const wsInvites = byWs[w.id] || [];
    const activeInvites = wsInvites.filter(i => !i.revoked_at && (!i.expires_at || new Date(i.expires_at) > new Date()) && i.uses < i.max_uses);
    html += `<div class="card" style="margin-bottom:16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:12px;flex-wrap:wrap">
        <div>
          <h3 style="margin:0">${esc(w.name)} <span style="font-size:12px;color:var(--text-muted);font-weight:400">· ${esc(w.workspace_type)}</span></h3>
          <div style="font-size:12px;color:var(--text-muted);margin-top:4px">slug: <code>${esc(w.slug)}</code>${w.email_domain ? ' · domain: <code>' + esc(w.email_domain) + '</code>' : ''}</div>
          ${w.description ? '<p style="margin:8px 0 0;color:var(--text-muted);font-size:13px">' + esc(w.description) + '</p>' : ''}
        </div>
      </div>
      <details style="margin-top:12px"><summary style="cursor:pointer;font-weight:600;color:var(--green)">➕ Generate invite link</summary>
        <div style="margin-top:10px;display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px">
          <select id="inv-role-${w.id}" style="padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text)">
            <option value="member">Member</option><option value="admin">Admin</option><option value="viewer">Viewer</option><option value="owner">Owner</option>
          </select>
          <input id="inv-email-${w.id}" placeholder="Email (optional, email-gated)" style="padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text)" />
          <input id="inv-domain-${w.id}" placeholder="Domain (optional, e.g. acme.com)" style="padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text)" />
          <input id="inv-uses-${w.id}" type="number" min="1" value="1" placeholder="Max uses" style="padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text)" />
          <select id="inv-exp-${w.id}" style="padding:8px;border:1px solid var(--border);border-radius:6px;background:var(--surface);color:var(--text)">
            <option value="">Never expires</option><option value="1 day">1 day</option><option value="7 days">7 days</option><option value="30 days">30 days</option><option value="90 days">90 days</option>
          </select>
        </div>
        <button onclick="handleCreateInviteClick('${w.id}')" class="btn btn-primary" style="margin-top:10px">Generate link</button>
        <div id="inv-out-${w.id}" style="margin-top:10px;font-size:13px"></div>
      </details>
      <div style="margin-top:12px">
        <div style="font-size:12px;font-weight:600;color:var(--text-muted);margin-bottom:6px">Active invites (${activeInvites.length})</div>
        ${activeInvites.length === 0 ? '<div style="font-size:12px;color:var(--text-muted)">No active invites.</div>' : activeInvites.map(i => {
          const url = buildClaimUrl(i.claim_code);
          return `<div style="padding:10px;border:1px solid var(--border);border-radius:8px;margin-bottom:6px;font-size:12px;background:var(--surface)">
            <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap">
              <code style="font-weight:700">${esc(i.claim_code)}</code>
              <span style="color:var(--text-muted)">${esc(i.role)}${i.email ? ' · ' + esc(i.email) : ''}${i.email_domain ? ' · @' + esc(i.email_domain) : ''} · ${i.uses}/${i.max_uses} uses${i.expires_at ? ' · exp ' + new Date(i.expires_at).toLocaleDateString() : ''}</span>
              <button onclick="navigator.clipboard.writeText('${url}').then(() => toast('📋 Link copied'))" class="btn btn-small">Copy link</button>
              <button onclick="handleRevokeInviteClick('${i.id}')" class="btn btn-small" style="color:var(--red)">Revoke</button>
            </div>
            <div style="margin-top:4px;color:var(--text-muted);word-break:break-all">${esc(url)}</div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
  });

  root.innerHTML = html;
}

// UI click handlers
async function handleCreateWorkspaceClick(){
  const name = (document.getElementById('new-ws-name')||{}).value || '';
  const type = (document.getElementById('new-ws-type')||{}).value || 'ecosystem';
  const domain = (document.getElementById('new-ws-domain')||{}).value || '';
  const desc = (document.getElementById('new-ws-desc')||{}).value || '';
  if (!name.trim()) { toast('⚠️ Name is required'); return; }
  const res = await createWorkspaceRPC({ name, workspace_type: type, email_domain: domain, description: desc });
  if (!res.ok) { toast('⚠️ ' + res.message); return; }
  toast('✅ Workspace created: ' + (res.workspace && res.workspace.name || name));
  await loadUserWorkspaces();
  renderWorkspacesAdmin();
}

async function handleCreateInviteClick(wsId){
  const role = (document.getElementById('inv-role-'+wsId)||{}).value || 'member';
  const email = (document.getElementById('inv-email-'+wsId)||{}).value || '';
  const domain = (document.getElementById('inv-domain-'+wsId)||{}).value || '';
  const uses = parseInt((document.getElementById('inv-uses-'+wsId)||{}).value || '1', 10) || 1;
  const exp = (document.getElementById('inv-exp-'+wsId)||{}).value || '';
  const res = await createWorkspaceInvite({
    workspace_id: wsId, role, email, email_domain: domain, max_uses: uses, expires_in: exp || null
  });
  const out = document.getElementById('inv-out-'+wsId);
  if (!res.ok) { if (out) out.innerHTML = '<span style="color:var(--red)">⚠️ ' + res.message + '</span>'; return; }
  const url = buildClaimUrl(res.invite.claim_code);
  if (out) out.innerHTML = '<div style="padding:10px;border:1px solid var(--green);border-radius:8px;background:rgba(0,200,100,.08)"><div style="font-weight:700;margin-bottom:4px">✅ Invite created</div><div style="word-break:break-all;font-family:monospace;font-size:12px">' + url + '</div><button onclick="navigator.clipboard.writeText(\'' + url + '\').then(() => toast(\'📋 Link copied\'))" class="btn btn-small" style="margin-top:6px">Copy link</button></div>';
  setTimeout(renderWorkspacesAdmin, 400);
}

async function handleRevokeInviteClick(inviteId){
  if (!confirm('Revoke this invite? Anyone with the link will no longer be able to use it.')) return;
  const ok = await revokeWorkspaceInvite(inviteId);
  if (ok) { toast('✅ Invite revoked'); renderWorkspacesAdmin(); }
  else { toast('⚠️ Could not revoke invite'); }
}

// First-login auto-join: if the user has zero workspaces, try domain auto-join.
async function maybeAutoJoinOnFirstLogin(){
  if (!currentUser) return;
  if (_userWorkspaces && _userWorkspaces.length > 0) return;
  const joined = await autoJoinByDomain();
  if (joined > 0) {
    await loadUserWorkspaces();
    toast('✅ Auto-joined ' + joined + ' workspace' + (joined === 1 ? '' : 's') + ' from your email domain');
  }
}

// ── DYNAMIC ECOSYSTEM MANAGER ACCESS ─────────────────────────
// Tracks which users have claimed/been approved as ecosystem managers
// Stored per-user: { userId, email, ecoId, ecoName, claimedAt }
function getEcoManagers(){ return JSON.parse(localStorage.getItem('foc_eco_managers') || '[]'); }
function saveEcoManagers(list){ localStorage.setItem('foc_eco_managers', JSON.stringify(list)); }
function registerEcoManager(userId, email, ecoId, ecoName){
  const list = getEcoManagers();
  if (list.find(m => m.userId === userId && m.ecoId === ecoId)) return; // already registered
  list.push({ userId, email, ecoId, ecoName, claimedAt: new Date().toISOString() });
  saveEcoManagers(list);
}
function isClaimedEcoManager(userIdOrEmail){
  if (!userIdOrEmail) return false;
  const list = getEcoManagers();
  return list.some(m => m.userId === userIdOrEmail || m.email === userIdOrEmail);
}
function getUserEcosystems(userIdOrEmail){
  if (!userIdOrEmail) return [];
  const list = getEcoManagers();
  return list.filter(m => m.userId === userIdOrEmail || m.email === userIdOrEmail);
}

function avatarHtml(email, method){
  const initials = method==='google' ? 'G' : email.slice(0,2).toUpperCase();
  const bg = method==='google' ? '#4285f4' : 'var(--green)';
  const icon = method==='google' ? `<svg width="14" height="14" viewBox="0 0 24 24"><path fill="#fff" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#fff" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#fff" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/><path fill="#fff" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>` : initials;
  return `<div style="width:28px;height:28px;border-radius:50%;background:${bg};display:inline-flex;align-items:center;justify-content:center;color:#fff;font-size:11px;font-weight:700;cursor:pointer;border:2px solid rgba(255,255,255,.3);flex-shrink:0" title="${email}" onclick="openModal('signin-modal')">${icon}</div>`;
}

async function signIn(method){
  if(method === 'google'){
    const { error } = await _supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: window.location.origin,
        queryParams: { prompt: 'select_account' }
      }
    });
    if(error) toast('Sign in error: ' + error.message);
    return;
  }
  // Email magic link fallback
  const email = (document.getElementById('signin-email')||{}).value?.trim() ||
                (document.getElementById('onboard-email')||{}).value?.trim() || '';
  if(!email){ toast('Please enter your email address'); return; }
  if(!/\S+@\S+\.\S+/.test(email)){ toast('Please enter a valid email address'); return; }
  const { error } = await _supabase.auth.signInWithOtp({
    email, options: { emailRedirectTo: window.location.origin }
  });
  if(error){ toast('Error: ' + error.message); return; }
  toast('✅ Magic link sent! Check your email to sign in.');
  closeModal('signin-modal');
}

function trackPage(page){
  sessionPageViews.push({page, ts: new Date().toISOString()});
  if(currentUser){
    const logins = getLogins();
    const idx = logins.findIndex(l=>l.id===currentUser.id);
    if(idx>-1){ logins[idx].pages = sessionPageViews; saveLogins(logins); }
  }
}

// ── ADMIN ─────────────────────────────────────────────────────────
function goAdmin(){
  if(!currentUser){
    toast('Please sign in first to access the admin panel');
    openModal('signin-modal');
    return;
  }
  if(isUserAdmin(currentUser.email)){
    isAdmin = true;
    go('admin', null);
  } else {
    toast('❌ Admin access is restricted — contact russellcolevop@gmail.com');
  }
}

function approveAdmin(email){
  const admins = JSON.parse(localStorage.getItem('agtech_admin_list')||'[]');
  if(!admins.includes(email)){ admins.push(email); localStorage.setItem('agtech_admin_list', JSON.stringify(admins)); }
  toast('✅ Admin access granted to ' + email);
  go('admin', null);
}

function revokeAdmin(email){
  if(email === RUSSELL_EMAIL){ toast('Cannot revoke primary admin'); return; }
  const admins = JSON.parse(localStorage.getItem('agtech_admin_list')||'[]');
  localStorage.setItem('agtech_admin_list', JSON.stringify(admins.filter(e=>e!==email)));
  toast('🔒 Admin access revoked for ' + email);
  go('admin', null);
}

// ── ADMIN IMPERSONATION (Assume User) ───────────────────────────
function assumeUser(userId) {
  if (!isAdmin) { toast('Admin access required'); return; }
  const target = _allProfiles.find(p => p.id === userId);
  if (!target) { toast('User not found'); return; }
  // Store real admin state
  _assumedUser = {
    id: target.id,
    email: target.email,
    name: target.full_name || target.email,
    profile: { ...target },
    _realProfile: _userProfile,
    _realAdminState: true
  };
  // Swap the active profile to the assumed user's profile
  _userProfile = { ...target };
  // Apply their persona UI
  applyPersonaUI(_userProfile);
  toast('👁️ Now viewing as: ' + (target.full_name || target.email) + ' — click the purple banner to exit');
  // Navigate to overview (their default landing)
  go('overview', null);
}

function exitAssumeUser() {
  if (!_assumedUser) return;
  // Restore real admin profile
  _userProfile = _assumedUser._realProfile;
  _assumedUser = null;
  // Re-apply admin persona
  applyPersonaUI(_userProfile);
  toast('✅ Returned to admin view');
  go('admin', null);
}

function getAssumeUserBanner() {
  if (!_assumedUser) return '';
  return `<div id="assume-user-banner" onclick="exitAssumeUser()" style="position:fixed;top:0;left:0;right:0;z-index:9999;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;padding:8px 20px;display:flex;align-items:center;justify-content:center;gap:12px;cursor:pointer;font-size:13px;font-weight:600;box-shadow:0 2px 12px rgba(99,102,241,.4)">
    <span>👁️ Viewing as: <strong>${_assumedUser.name}</strong> (${_assumedUser.email})</span>
    <span style="padding:3px 12px;background:rgba(255,255,255,.2);border-radius:4px;font-size:11px;font-weight:700">CLICK TO EXIT</span>
    <span style="font-size:10px;opacity:.7">Read-only impersonation — changes still save to your admin account</span>
  </div>`;
}

function submitFeedback(){
  const type = (document.getElementById('fb-type')||{}).value || 'General Feedback';
  const msg = (document.getElementById('fb-msg')||{}).value || '';
  trackEvent('feedback_submitted', { feedback_type: type, has_message: !!msg.trim() });
  if(!msg.trim()){ toast('Please write some feedback first'); return; }
  const fromName = currentUser ? currentUser.name : 'Guest';
  const fromEmail = currentUser ? currentUser.email : 'Anonymous';
  const subject = encodeURIComponent('AgTech Ops Center Feedback: ' + type);
  const body = encodeURIComponent(
    'Feedback Type: ' + type + '\n' +
    'From: ' + fromName + ' (' + fromEmail + ')' + '\n' +
    'Submitted: ' + new Date().toLocaleString() + '\n\n' +
    '---\n\n' + msg
  );
  window.open('mailto:russellcolevop@gmail.com?subject=' + subject + '&body=' + body, '_blank');
  closeModal('feedback-modal');
  document.getElementById('fb-msg').value = '';
  toast('📧 Email client opened — hit Send to submit your feedback');
  // Grant first_feedback badge
  if (currentUser && _userProfile && !((_userProfile.badges||[]).includes('first_feedback'))) {
    grantBadge(currentUser.id, 'first_feedback');
  }
}

function exportCSV(){
  const logins = getLogins();
  if(!logins.length){ toast('No login data to export yet'); return; }
  const rows = [['ID','Email','Method','Timestamp','Pages Viewed']];
  logins.forEach(l=>rows.push([l.id, l.email, l.method, l.ts, (l.pages||[]).map(p=>p.page).join('|')]));
  const csv = rows.map(r=>r.map(c=>`"${c}"`).join(',')).join('\n');
  const a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,'+encodeURIComponent(csv);
  a.download = 'agtech_users_'+new Date().toISOString().slice(0,10)+'.csv';
  a.click();
  toast('📥 CSV exported');
}

// ══════════════════════════════════════════════════════════════
// SUPABASE PROFILE CRUD
// ══════════════════════════════════════════════════════════════
let _userProfile = null;
let _allProfiles = []; // admin cache

async function loadProfile(userId) {
  const { data, error } = await _supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
  if (error) { console.error('loadProfile error:', error); return null; }
  return data;
}

async function upsertProfile(profileData) {
  const { data, error } = await _supabase.from('profiles').upsert(profileData, { onConflict: 'id' }).select().single();
  if (error) console.error('upsertProfile error:', error);
  return { data, error };
}

async function loadAllProfiles() {
  const { data, error } = await _supabase.from('profiles').select('*').order('created_at', { ascending: false });
  if (error) { console.error('loadAllProfiles error:', error); return []; }
  return data || [];
}

// ── Supabase Deal Management ──
async function loadSupabaseDeals() {
  try {
    const { data, error } = await _supabase.from('agtech_deals').select('*').order('created_at', { ascending: false });
    if (error) { console.warn('agtech_deals table not found or error:', error.message); return []; }
    return (data || []).map(d => ({
      co: d.company, amt: d.amount_display || ('$' + (d.amount_m||0) + 'M'), amtNum: d.amount_m || 0,
      round: d.round, date: d.deal_date || '', lead: d.lead_investor || 'Undisclosed',
      sector: d.sector, desc: d.description || '', geo: d.geo_label || '', region: d.region || ''
    }));
  } catch(e) { console.warn('loadSupabaseDeals:', e); return []; }
}

async function saveSupabaseDeal(deal) {
  const payload = {
    company: deal.co, amount_m: deal.amtNum || 0, amount_display: deal.amt,
    round: deal.round, deal_date: deal.date, lead_investor: deal.lead,
    sector: deal.sector, description: deal.desc, geo_label: deal.geo, region: deal.region,
    added_by: currentUser?.id || null
  };
  if (deal.id) {
    const { error } = await _supabase.from('agtech_deals').update(payload).eq('id', deal.id);
    if (error) { toast('Error updating deal: ' + error.message); return false; }
  } else {
    const { error } = await _supabase.from('agtech_deals').insert(payload);
    if (error) { toast('Error saving deal: ' + error.message); return false; }
  }
  toast('Deal saved!');
  _supabaseDeals = await loadSupabaseDeals();
  render('admin');
  return true;
}

async function deleteSupabaseDeal(id) {
  if (!confirm('Delete this deal?')) return;
  const { error } = await _supabase.from('agtech_deals').delete().eq('id', id);
  if (error) { toast('Error: ' + error.message); return; }
  toast('Deal deleted');
  _supabaseDeals = await loadSupabaseDeals();
  render('admin');
}

async function seedDealsToSupabase() {
  if (!confirm('Seed ' + INVESTOR_DEALS.length + ' deals to Supabase? This will add them to the agtech_deals table.')) return;
  let ok = 0;
  for (const d of INVESTOR_DEALS) {
    const payload = {
      company: d.co, amount_m: d.amtNum || 0, amount_display: d.amt,
      round: d.round, deal_date: d.date, lead_investor: d.lead,
      sector: d.sector, description: d.desc, geo_label: d.geo, region: d.region,
      added_by: currentUser?.id || null
    };
    const { error } = await _supabase.from('agtech_deals').insert(payload);
    if (!error) ok++;
  }
  toast(ok + '/' + INVESTOR_DEALS.length + ' deals seeded to Supabase');
  _supabaseDeals = await loadSupabaseDeals();
  render('admin');
}

function submitNewDeal() {
  const co = document.getElementById('deal-co')?.value?.trim();
  if (!co) { toast('Company name is required'); return; }
  const amtNum = parseFloat(document.getElementById('deal-amt')?.value) || 0;
  const deal = {
    co,
    amt: amtNum ? '$' + amtNum + 'M' : 'Undisclosed',
    amtNum,
    round: document.getElementById('deal-round')?.value || '',
    sector: document.getElementById('deal-sector')?.value || '',
    region: document.getElementById('deal-region')?.value || '',
    lead: document.getElementById('deal-lead')?.value?.trim() || 'Undisclosed',
    date: document.getElementById('deal-date')?.value?.trim() || '',
    geo: document.getElementById('deal-geo')?.value?.trim() || '',
    desc: document.getElementById('deal-desc')?.value?.trim() || ''
  };
  saveSupabaseDeal(deal);
}

async function updateAdminNotes(userId, notes, tags) {
  const { error } = await _supabase.from('profiles').update({ admin_notes: notes, admin_tags: tags }).eq('id', userId);
  if (error) console.error('updateAdminNotes error:', error);
  return !error;
}

async function blockUser(userId, reason) {
  const { error } = await _supabase.from('profiles').update({ blocked: true, blocked_reason: reason || '', blocked_at: new Date().toISOString() }).eq('id', userId);
  if (error) { console.error('blockUser error:', error); toast('Error blocking user'); return false; }
  // Update cache
  const p = _allProfiles.find(x => x.id === userId);
  if (p) { p.blocked = true; p.blocked_reason = reason; p.blocked_at = new Date().toISOString(); }
  toast('🚫 User blocked');
  render('admin');
  return true;
}

async function unblockUser(userId) {
  const { error } = await _supabase.from('profiles').update({ blocked: false, blocked_reason: '', blocked_at: null }).eq('id', userId);
  if (error) { console.error('unblockUser error:', error); toast('Error unblocking user'); return false; }
  const p = _allProfiles.find(x => x.id === userId);
  if (p) { p.blocked = false; p.blocked_reason = ''; p.blocked_at = null; }
  toast('✅ User unblocked');
  render('admin');
  return true;
}

function promptBlockUser(userId, userName) {
  const reason = prompt('Block ' + userName + '?\n\nOptionally provide a reason (or leave blank):');
  if (reason === null) return; // cancelled
  blockUser(userId, reason);
}

async function deleteUser(userId, userName) {
  if (!confirm('⚠️ Permanently delete ' + userName + '?\n\nThis will wipe their profile data and block the account. They can re-register with a fresh account.\n\nThis cannot be undone.')) return;
  if (!confirm('Are you absolutely sure you want to delete ' + userName + '?')) return;
  // Wipe profile data + block + mark deleted (update works within RLS; delete may not)
  const wiped = {
    full_name: '[deleted]', persona: '', organization: '', job_title: '', linkedin_url: '',
    location: '', company_name: '', company_stage: '', what_building: '', funding_status: '',
    team_size: '', biggest_needs: [], investment_stages: [], check_size: '', deal_interests: '',
    expertise_areas: [], institution: '', research_focus: '', service_type: '',
    agtech_focus: [], goals_platform: '', goals_general: '', how_heard: '',
    avatar_url: '', badges: [], tier: 'explorer', profile_completeness: 0,
    blocked: true, blocked_reason: 'DELETED_BY_ADMIN', blocked_at: new Date().toISOString(),
    onboarding_complete: false
  };
  const { error } = await _supabase.from('profiles').update(wiped).eq('id', userId);
  if (error) { console.error('deleteUser error:', error); toast('❌ Error deleting user: ' + error.message); return; }
  // Remove from local cache so they disappear from admin view
  _allProfiles = _allProfiles.filter(x => x.id !== userId);
  toast('🗑️ ' + userName + ' deleted');
  render('admin');
}

