const INTRO_LAUNCH_THRESHOLD = 50;

// ── NOTIFICATIONS ────────────────────────────────────────────────
function getNotifications() {
  const notifs = [];
  if (!currentUser || !_userProfile) return notifs;
  const p = _userProfile;

  // 1. Profile not set up (only show if not already complete)
  if (!p.onboarding_complete) {
    notifs.push({ icon:'👤', title:'Complete your profile', desc:'Set up your profile so Russell can connect you with the right people.', action:'profile', priority:1 });
  }

  // 2. Profile needs review (pre-created account)
  if (p.needs_review) {
    notifs.push({ icon:'📋', title:'Review your profile', desc:'Russell pre-loaded your profile. Please review it and make any changes.', action:'profile', priority:1 });
  }

  // 3. Monthly check-in reminder
  const lastCheckin = p.last_checkin ? new Date(p.last_checkin) : (p.created_at ? new Date(p.created_at) : null);
  const daysSince = lastCheckin ? Math.floor((Date.now() - lastCheckin.getTime()) / 864e5) : 0;
  if (p.onboarding_complete && daysSince > 30) {
    notifs.push({ icon:'📋', title:'Monthly check-in due', desc:p.last_checkin ? 'Last check-in was ' + daysSince + ' days ago. Quick update to keep your profile current.' : 'You haven\'t completed your first check-in yet. It only takes a minute.', action:'profile', priority:1 });
  }

  // 4. Pending connection outcome reports
  if (_userIntros && _userIntros.length) {
    const pendingOutcomes = _userIntros.filter(i => {
      if (i.status !== 'introduced') return false;
      const d = (Date.now() - new Date(i.introduced_at || i.created_at).getTime()) / 864e5;
      return d > 14;
    });
    if (pendingOutcomes.length) {
      notifs.push({ icon:'🤝', title:pendingOutcomes.length + ' connection' + (pendingOutcomes.length > 1 ? 's' : '') + ' need feedback', desc:'Share how your introduction' + (pendingOutcomes.length > 1 ? 's' : '') + ' went so we can keep improving matches.', action:'connections', priority:2 });
    }
  }

  // 5. New suggested intros waiting for action
  if (_userIntros && _userIntros.length) {
    const suggested = _userIntros.filter(i => i.status === 'suggested');
    if (suggested.length) {
      notifs.push({ icon:'✨', title:suggested.length + ' new connection' + (suggested.length > 1 ? 's' : '') + ' suggested', desc:'Russell has suggested ' + (suggested.length > 1 ? 'some introductions' : 'an introduction') + ' for you. Review and accept.', action:'connections', priority:2 });
    }
  }

  // 6. New introductions made (user notified that Russell introduced them)
  if (_userIntros && _userIntros.length) {
    const recentIntros = _userIntros.filter(i => i.status === 'introduced' && i.introduced_at && (Date.now() - new Date(i.introduced_at).getTime()) < 7 * 864e5);
    if (recentIntros.length) {
      notifs.push({ icon:'🤝', title:recentIntros.length + ' new introduction' + (recentIntros.length > 1 ? 's' : '') + ' made', desc:'Russell has introduced you to ' + (recentIntros.length > 1 ? 'some people' : 'someone') + '. Check your Active Intros.', action:'connections', priority:1 });
    }
  }

  // 7. Admin: User-requested intros needing action
  if (isAdmin && typeof _introductions !== 'undefined' && _introductions && _introductions.length) {
    const userRequested = _introductions.filter(i => i.status === 'suggested' && i.requested_by && i.requested_by !== currentUser.id);
    if (userRequested.length) {
      notifs.push({ icon:'📩', title:userRequested.length + ' intro request' + (userRequested.length > 1 ? 's' : '') + ' from users', desc:'Users have requested introductions. Review and facilitate in My Connections.', action:'connections', priority:1 });
    }
  }

  // 8. Admin: New ecosystem listing applications
  if (isAdmin && _ecoListings.length) {
    const pendingEcoListings = _ecoListings.filter(l => l.status === 'pending');
    if (pendingEcoListings.length) {
      notifs.push({ icon:'🏗️', title:pendingEcoListings.length + ' new ecosystem listing application' + (pendingEcoListings.length > 1 ? 's' : ''), desc:'Review ' + (pendingEcoListings.length > 1 ? 'these programs' : 'this program') + ' in the Ecosystems tab.', action:'admin_eco', priority:1 });
    }
  }

  // 9. Admin: New venture studio submissions — route to admin venture studio tab
  if (isAdmin && _ventureSubmissions.length) {
    const lastSeen = localStorage.getItem('foc_vs_last_seen') || '0';
    const unseenNew = _ventureSubmissions.filter(s => s.status === 'New' && new Date(s.createdAt || 0).getTime() > parseInt(lastSeen));
    if (unseenNew.length) {
      notifs.push({ icon:'🚀', title:unseenNew.length + ' new Venture Studio submission' + (unseenNew.length > 1 ? 's' : ''), desc:'Review ' + (unseenNew.length > 1 ? 'these ideas' : 'this idea') + ' in the Venture Studio tab.', action:'admin_venture', priority:1 });
    }
  }

  // Sort by priority (lower = more urgent)
  notifs.sort((a, b) => a.priority - b.priority);
  return notifs;
}

function updateNotifBell() {
  const bell = document.getElementById('notif-bell');
  const badge = document.getElementById('notif-badge');
  const navBadge = document.getElementById('nav-action-badge');
  if (!bell || !badge) return;

  if (!currentUser || !_userProfile) {
    bell.style.display = 'none';
    if (navBadge) navBadge.style.display = 'none';
    return;
  }

  const notifs = getNotifications();
  bell.style.display = '';
  if (notifs.length > 0) {
    badge.style.display = 'flex';
    badge.textContent = notifs.length;
    if (navBadge) { navBadge.style.display = 'inline-flex'; const nc = document.getElementById('nav-action-count'); if (nc) nc.textContent = notifs.length; }
  } else {
    badge.style.display = 'none';
    if (navBadge) navBadge.style.display = 'none';
  }
}

function calcCompleteness(p) {
  if (!p) return 0;
  const required = ['full_name','persona','linkedin_url','location'];
  const personaFields = {
    founder: ['company_name','company_stage','what_building','funding_status'],
    investor: ['investment_stages','check_size'],
    farmer: ['location'],
    advisor: ['expertise_areas'],
    researcher: ['institution','research_focus'],
    industry_pro: ['organization','job_title'],
    service_provider: ['service_type'],
    government: ['organization']
  };
  const extra = personaFields[p.persona] || [];
  const all = [...required, ...extra];
  let filled = 0;
  for (const f of all) {
    const v = p[f];
    if (Array.isArray(v) ? v.length > 0 : (v && String(v).trim())) filled++;
  }
  return Math.round((filled / all.length) * 100);
}

function getBadgesForPersona(persona) {
  return [...COMMON_BADGES, ...(PERSONA_BADGES[persona] || [])];
}

function calcBadges(p) {
  if (!p) return [];
  const defs = getBadgesForPersona(p.persona);
  return defs.filter(b => {
    if (b.check) return b.check(p); // common badges with check function
    if (b.autoCheck && b.autoCheck(p)) return true; // persona badges with auto-check
    return !!(p.badges && p.badges.includes(b.id)); // manually granted
  }).map(b => b.id);
}

function calcTier(badges) {
  let tier = 'explorer';
  for (const t of TIER_DEFS) {
    if (badges.length >= t.min) tier = t.id;
  }
  return tier;
}

function tierDef(tierId) { return TIER_DEFS.find(t => t.id === tierId) || TIER_DEFS[0]; }
function tierHtml(tierId) { const t = tierDef(tierId); return `<span class="tier-badge tier-${t.id}">${t.icon} ${t.label}</span>`; }

function completenessBarHtml(pct) {
  const cls = pct < 50 ? 'low' : pct < 100 ? 'med' : 'high';
  return `<div class="completeness-bar"><div class="completeness-fill ${cls}" style="width:${pct}%"></div></div>`;
}

function getMissingFields(p) {
  if (!p) return [];
  const labels = {
    full_name:'Full Name', persona:'Persona', linkedin_url:'LinkedIn URL', location:'Location',
    company_name:'Company Name', company_stage:'Company Stage', what_building:'What You\'re Building',
    funding_status:'Funding Status', investment_stages:'Investment Stages', check_size:'Check Size',
    expertise_areas:'Expertise Areas', institution:'Institution', research_focus:'Research Focus',
    organization:'Organization', job_title:'Job Title', service_type:'Service Type'
  };
  const required = ['full_name','persona','linkedin_url','location'];
  const personaFields = {
    founder:['company_name','company_stage','what_building','funding_status'],
    investor:['investment_stages','check_size'], farmer:['location'],
    advisor:['expertise_areas'], researcher:['institution','research_focus'],
    industry_pro:['organization','job_title'], service_provider:['service_type'],
    government:['organization']
  };
  const extra = personaFields[p.persona] || [];
  const all = [...required, ...extra];
  return all.filter(f => { const v = p[f]; return !(Array.isArray(v) ? v.length > 0 : (v && String(v).trim())); }).map(f => labels[f] || f);
}

function badgesGridHtml(earnedBadges, persona) {
  const defs = getBadgesForPersona(persona);
  const earnedCount = defs.filter(b => earnedBadges.includes(b.id)).length;
  const totalCount = defs.length;
  return `<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">
    <span style="font-size:12px;font-weight:800;color:var(--text)">${earnedCount}/${totalCount} milestones</span>
    <div style="flex:1;height:4px;background:var(--hover);border-radius:2px;overflow:hidden"><div style="height:100%;width:${Math.round(earnedCount/totalCount*100)}%;background:var(--green);border-radius:2px;transition:width .4s"></div></div>
  </div>
  <div style="display:flex;flex-wrap:wrap;gap:8px">${defs.map(b => {
    const earned = earnedBadges.includes(b.id);
    const isAuto = !!b.check;
    const clickAction = !earned && !isAuto ? `onclick="openBadgeClaim('${b.id}')"` : '';
    const tipText = earned
      ? `<strong style="color:var(--green)">✅ Earned!</strong><br>${b.desc}`
      : isAuto
        ? `<strong>${b.label}</strong><br>${b.desc}<br><em style='color:var(--text-faint)'>Auto-earned when conditions are met</em>`
        : `<strong>${b.label}</strong><br>${b.desc}<br><em style='color:var(--green)'>Click to claim this milestone →</em>`;
    return `<span class="badge-item ${earned?'earned':'locked'}" ${clickAction}><span class="badge-icon">${b.icon}</span> ${b.label}<span class="badge-tip">${tipText}</span></span>`;
  }).join('')}</div>`;
}

async function syncProfileMeta(profile) {
  if (!profile) return profile;
  const completeness = calcCompleteness(profile);
  const autoBadges = calcBadges(profile);
  // Merge auto-earned + manually-granted badges (preserve any previously granted persona badge)
  const allKnownIds = getBadgesForPersona(profile.persona).map(b => b.id);
  const existingManual = (profile.badges || []).filter(b => allKnownIds.includes(b));
  const merged = [...new Set([...autoBadges, ...existingManual])];
  const tier = calcTier(merged);
  const needsUpdate = completeness !== profile.profile_completeness || tier !== profile.tier || JSON.stringify(merged.sort()) !== JSON.stringify((profile.badges||[]).sort());
  if (needsUpdate) {
    const { error } = await _supabase.from('profiles').update({
      profile_completeness: completeness,
      badges: merged,
      tier: tier,
      verified_at: completeness >= 100 && !profile.verified_at ? new Date().toISOString() : profile.verified_at
    }).eq('id', profile.id);
    if (!error) {
      profile.profile_completeness = completeness;
      profile.badges = merged;
      profile.tier = tier;
      if (completeness >= 100 && !profile.verified_at) profile.verified_at = new Date().toISOString();
    }
  }
  return profile;
}

function profileVerificationBanner(p) {
  if (!p || !p.onboarding_complete) return '';
  const completeness = calcCompleteness(p);
  if (completeness >= 100) return '';
  const created = new Date(p.created_at || Date.now());
  const hoursElapsed = (Date.now() - created.getTime()) / 36e5;
  const hoursLeft = Math.max(0, Math.round(24 - hoursElapsed));
  if (hoursElapsed >= 24) {
    return `<div class="verification-banner danger">
      <span style="font-size:20px">⚠️</span>
      <div><strong>Profile Incomplete — Account at risk</strong><br>
      <span style="font-size:12px">Your profile is ${completeness}% complete. Complete it now to avoid suspension. We require quality, verified profiles to maintain a trusted network.</span><br>
      <button onclick="go('profile')" style="margin-top:6px;padding:6px 16px;background:#dc2626;color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer">Complete Profile Now</button></div>
    </div>`;
  }
  if (hoursElapsed >= 12) {
    return `<div class="verification-banner warning">
      <span style="font-size:20px">⏰</span>
      <div><strong>Complete your profile — ${hoursLeft}h remaining</strong><br>
      <span style="font-size:12px">Your profile is ${completeness}% complete. Finish it within 24 hours of sign-up to stay active on the platform.</span><br>
      <button onclick="go('profile')" style="margin-top:6px;padding:6px 16px;background:#d97706;color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:700;cursor:pointer">Complete Profile</button></div>
    </div>`;
  }
  return '';
}

async function checkAutoSuspend(profile) {
  // Never auto-suspend if user already completed onboarding wizard successfully
  if (!profile) return false;
  if (profile.onboarding_complete) return false;
  // Only auto-suspend users who signed up but never finished the wizard
  const created = new Date(profile.created_at || Date.now());
  const hoursElapsed = (Date.now() - created.getTime()) / 36e5;
  if (hoursElapsed >= 48 && !profile.blocked) {
    await blockUser(profile.id, 'Auto-suspended: profile onboarding not completed within 48 hours. Please sign in and complete your profile to regain access.');
    return true;
  }
  if (hoursElapsed >= 24 && !profile.suspension_warned_at) {
    await _supabase.from('profiles').update({ suspension_warned_at: new Date().toISOString() }).eq('id', profile.id);
    profile.suspension_warned_at = new Date().toISOString();
  }
  return false;
}

