function openBadgeClaim(badgeId) {
  if (!currentUser || !_userProfile) { toast('Sign in to claim milestones'); return; }
  const persona = _userProfile.persona;
  const defs = getBadgesForPersona(persona);
  const badge = defs.find(b => b.id === badgeId);
  if (!badge) return;
  const evidence = BADGE_EVIDENCE[badgeId];
  const existingEvidence = (_userProfile.badge_evidence || {})[badgeId] || '';

  const html = `<div class="badge-claim-overlay" onclick="if(event.target===this)this.remove()">
    <div class="badge-claim-box">
      <div style="text-align:center;margin-bottom:16px">
        <div style="font-size:40px;margin-bottom:8px">${badge.icon}</div>
        <h3 style="margin:0 0 4px;font-size:18px">${badge.label}</h3>
        <p style="font-size:12px;color:var(--text-muted);margin:0">${badge.desc}</p>
      </div>
      ${evidence ? `
        <label style="font-size:13px;font-weight:700;color:var(--text);display:block;margin-bottom:6px">${evidence.label}</label>
        <textarea id="badge-claim-evidence" style="width:100%;min-height:80px;padding:10px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:13px;resize:vertical;font-family:inherit" placeholder="${evidence.placeholder}">${existingEvidence}</textarea>
      ` : `<p style="font-size:13px;color:var(--text-muted)">Ready to claim this milestone?</p>`}
      <div style="display:flex;gap:10px;margin-top:16px;justify-content:flex-end">
        <button onclick="this.closest('.badge-claim-overlay').remove()" style="padding:10px 20px;background:var(--hover);border:1px solid var(--border);border-radius:8px;font-size:13px;cursor:pointer;color:var(--text)">Cancel</button>
        <button onclick="submitBadgeClaim('${badgeId}')" style="padding:10px 20px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">🏅 Claim Milestone</button>
      </div>
    </div>
  </div>`;
  document.body.insertAdjacentHTML('beforeend', html);
}

async function submitBadgeClaim(badgeId) {
  const evidenceEl = document.getElementById('badge-claim-evidence');
  const evidenceText = evidenceEl ? evidenceEl.value.trim() : '';
  // Save evidence to profile
  const existingEvidence = _userProfile.badge_evidence || {};
  existingEvidence[badgeId] = evidenceText;
  // Grant badge + save evidence
  const badges = [...new Set([...(_userProfile.badges||[]), badgeId])];
  const tier = calcTier(badges);
  const { error } = await _supabase.from('profiles').update({
    badges, tier, badge_evidence: existingEvidence
  }).eq('id', currentUser.id);
  if (!error) {
    _userProfile.badges = badges;
    _userProfile.tier = tier;
    _userProfile.badge_evidence = existingEvidence;
    const badge = getBadgesForPersona(_userProfile.persona).find(b => b.id === badgeId);
    toast('🏅 Milestone claimed: ' + (badge ? badge.label : badgeId));
    render(currentPage);
  } else {
    toast('❌ Error claiming badge');
  }
  // Remove overlay
  document.querySelector('.badge-claim-overlay')?.remove();
}

async function grantBadge(userId, badgeId) {
  const p = _allProfiles.find(x => x.id === userId) || _userProfile;
  if (!p) return;
  const badges = [...new Set([...(p.badges||[]), badgeId])];
  const tier = calcTier(badges);
  const { error } = await _supabase.from('profiles').update({ badges, tier }).eq('id', userId);
  if (!error) { p.badges = badges; p.tier = tier; toast('🏅 Badge granted: ' + (BADGE_DEFS.find(b=>b.id===badgeId)||{}).label); }
  else toast('Error granting badge');
}

async function revokeBadge(userId, badgeId) {
  const p = _allProfiles.find(x => x.id === userId) || _userProfile;
  if (!p) return;
  const badges = (p.badges||[]).filter(b => b !== badgeId);
  const tier = calcTier(badges);
  const { error } = await _supabase.from('profiles').update({ badges, tier }).eq('id', userId);
  if (!error) { p.badges = badges; p.tier = tier; toast('Badge revoked'); }
}

async function updateIntroTierPref(userId, tierPref) {
  const { error } = await _supabase.from('profiles').update({ intro_tier_pref: tierPref }).eq('id', userId);
  if (!error) {
    const p = _allProfiles.find(x => x.id === userId) || _userProfile;
    if (p) p.intro_tier_pref = tierPref;
    toast('Intro preference updated to: ' + tierDef(tierPref).label + '+');
  }
}

