async function grantRoadmapAccess(userId) {
  const p = _allProfiles.find(x => x.id === userId);
  if (!p) return;
  const tags = (p.admin_tags || []).filter(t => t !== 'roadmap_access');
  tags.push('roadmap_access');
  const { error } = await _supabase.from('profiles').update({ admin_tags: tags }).eq('id', userId);
  if (error) { console.error('grantRoadmap error:', error); toast('Error granting access'); return; }
  p.admin_tags = tags;
  toast('🗺️ Roadmap access granted to ' + (p.full_name || p.email));
  render('admin');
}

async function revokeRoadmapAccess(userId) {
  const p = _allProfiles.find(x => x.id === userId);
  if (!p) return;
  const tags = (p.admin_tags || []).filter(t => t !== 'roadmap_access');
  const { error } = await _supabase.from('profiles').update({ admin_tags: tags }).eq('id', userId);
  if (error) { console.error('revokeRoadmap error:', error); toast('Error revoking access'); return; }
  p.admin_tags = tags;
  toast('🔒 Roadmap access revoked for ' + (p.full_name || p.email));
  render('admin');
}

