async function grantInvestorAccess(userId) {
  const p = _allProfiles.find(x => x.id === userId);
  if (!p) return;
  const tags = (p.admin_tags || []).filter(t => t !== 'investor_access');
  tags.push('investor_access');
  const { error } = await _supabase.from('profiles').update({ admin_tags: tags }).eq('id', userId);
  if (error) { console.error('grantInvestor error:', error); toast('Error granting access'); return; }
  p.admin_tags = tags;
  toast('💼 Investor access granted to ' + (p.full_name || p.email));
  render('admin');
}

async function revokeInvestorAccess(userId) {
  const p = _allProfiles.find(x => x.id === userId);
  if (!p) return;
  const tags = (p.admin_tags || []).filter(t => t !== 'investor_access');
  const { error } = await _supabase.from('profiles').update({ admin_tags: tags }).eq('id', userId);
  if (error) { console.error('revokeInvestor error:', error); toast('Error revoking access'); return; }
  p.admin_tags = tags;
  toast('🔒 Investor access revoked for ' + (p.full_name || p.email));
  render('admin');
}

// ══════════════════════════════════════════════════════════════
// AUTONOMOUS MATCHING ENGINE
// ══════════════════════════════════════════════════════════════
let _introductions = [];
let adminTab = 'directory'; // 'directory' | 'connections' | 'roadmap' | 'investor'

async function loadIntroductions() {
  const { data, error } = await _supabase.from('introductions').select('*').order('created_at', { ascending: false });
  if (error) { console.error('loadIntros error:', error); return []; }
  return data || [];
}

async function createIntroduction(personA, personB, score, reasons) {
  const { data, error } = await _supabase.from('introductions').insert({
    person_a: personA, person_b: personB, match_score: score, match_reasons: reasons, status: 'suggested'
  }).select().single();
  if (error) { console.error('createIntro error:', error); return null; }
  return data;
}

async function updateIntroStatus(introId, status, notes) {
  const update = { status };
  if (notes !== undefined) update.admin_notes = notes;
  if (status === 'introduced') update.introduced_at = new Date().toISOString();
  if (status === 'connected') update.connected_at = new Date().toISOString();
  const { error } = await _supabase.from('introductions').update(update).eq('id', introId);
  if (error) { console.error('updateIntro error:', error); toast('Error updating'); return; }
  toast(status === 'introduced' ? '🤝 Marked as introduced' : status === 'connected' ? '✅ Connection confirmed!' : '📝 Updated');
  _introductions = await loadIntroductions();
  render('admin');
}

// ── SCORING ALGORITHM ──
function computeMatches(profiles) {
  const active = profiles.filter(p => !p.blocked && p.onboarding_complete);
  const tierOrder = ['explorer','builder','operator','leader'];
  const matches = [];

  for (let i = 0; i < active.length; i++) {
    for (let j = i + 1; j < active.length; j++) {
      const a = active[i], b = active[j];
      // Respect intro tier preferences — skip if either party's tier is below the other's minimum
      const aTier = tierOrder.indexOf(a.tier || 'explorer');
      const bTier = tierOrder.indexOf(b.tier || 'explorer');
      const aPref = tierOrder.indexOf(a.intro_tier_pref || 'explorer');
      const bPref = tierOrder.indexOf(b.intro_tier_pref || 'explorer');
      if (bTier < aPref || aTier < bPref) continue; // Tier gate
      const result = scoreMatch(a, b);
      if (result.score >= 20) {
        matches.push({ a, b, score: result.score, reasons: result.reasons });
      }
    }
  }
  return matches.sort((x, y) => y.score - x.score);
}

function scoreMatch(a, b) {
  let score = 0;
  const reasons = [];

  // Founder + Investor (high value)
  if ((a.persona === 'founder' && b.persona === 'investor') || (a.persona === 'investor' && b.persona === 'founder')) {
    const founder = a.persona === 'founder' ? a : b;
    const investor = a.persona === 'investor' ? a : b;
    score += 30;
    reasons.push('Founder-Investor match');
    if ((founder.biggest_needs || []).includes('Funding')) { score += 20; reasons.push('Founder actively seeking funding'); }
    const fStage = founder.company_stage;
    const iStages = (investor.investment_stages || []).map(s => s.toLowerCase());
    if (fStage === 'idea' && iStages.some(s => s.includes('pre-seed'))) { score += 15; reasons.push('Stage alignment: Pre-Seed'); }
    if (fStage === 'mvp' && iStages.some(s => s.includes('seed'))) { score += 15; reasons.push('Stage alignment: Seed'); }
    if (fStage === 'revenue' && iStages.some(s => s.includes('series a'))) { score += 15; reasons.push('Stage alignment: Series A'); }
    if (fStage === 'scaling' && iStages.some(s => s.includes('series b') || s.includes('growth'))) { score += 15; reasons.push('Stage alignment: Growth'); }
  }

  // Founder + Farmer (pilot opportunity)
  if ((a.persona === 'founder' && b.persona === 'farmer') || (a.persona === 'farmer' && b.persona === 'founder')) {
    const founder = a.persona === 'founder' ? a : b;
    const farmer = a.persona === 'farmer' ? a : b;
    score += 25;
    reasons.push('Founder-Farmer pilot opportunity');
    if (farmer.open_to_collab) { score += 20; reasons.push('Farmer open to piloting'); }
    if ((founder.biggest_needs || []).includes('Customers / Pilots')) { score += 15; reasons.push('Founder needs pilots'); }
    if ((farmer.biggest_needs || []).includes('Trying new technology')) { score += 10; reasons.push('Farmer wants new tech'); }
  }

  // Founder + Advisor
  if ((a.persona === 'founder' && b.persona === 'advisor') || (a.persona === 'advisor' && b.persona === 'founder')) {
    const founder = a.persona === 'founder' ? a : b;
    const advisor = a.persona === 'advisor' ? a : b;
    score += 20;
    reasons.push('Founder-Advisor match');
    if ((founder.biggest_needs || []).includes('Mentorship')) { score += 15; reasons.push('Founder seeking mentorship'); }
    // Check expertise overlap with needs
    const expertiseToNeed = {
      'Finance & Fundraising': 'Funding',
      'Marketing & Growth': 'Go-to-Market Strategy',
      'Legal & IP': 'Regulatory Guidance'
    };
    for (const [exp, need] of Object.entries(expertiseToNeed)) {
      if ((advisor.expertise_areas || []).includes(exp) && (founder.biggest_needs || []).includes(need)) {
        score += 10;
        reasons.push(`Expertise match: ${exp}`);
      }
    }
  }

  // Founder + Service Provider
  if ((a.persona === 'founder' && b.persona === 'service_provider') || (a.persona === 'service_provider' && b.persona === 'founder')) {
    score += 15;
    reasons.push('Founder-Service Provider match');
    const sp = a.persona === 'service_provider' ? a : b;
    if (sp.startup_experience) { score += 10; reasons.push('Service provider has startup experience'); }
  }

  // Investor + Farmer (due diligence / market validation)
  if ((a.persona === 'investor' && b.persona === 'farmer') || (a.persona === 'farmer' && b.persona === 'investor')) {
    score += 10;
    reasons.push('Investor-Farmer market insight');
  }

  // Researcher + Founder (tech transfer)
  if ((a.persona === 'researcher' && b.persona === 'founder') || (a.persona === 'founder' && b.persona === 'researcher')) {
    const researcher = a.persona === 'researcher' ? a : b;
    score += 15;
    reasons.push('Research-Founder tech transfer');
    if (researcher.open_to_collab) { score += 10; reasons.push('Researcher open to collaboration'); }
  }

  // AgTech focus overlap (bonus for any pair)
  const aFocus = new Set(a.agtech_focus || []);
  const bFocus = new Set(b.agtech_focus || []);
  const overlap = [...aFocus].filter(f => bFocus.has(f));
  if (overlap.length > 0) {
    score += Math.min(overlap.length * 5, 15);
    reasons.push(`Shared focus: ${overlap.slice(0,3).join(', ')}`);
  }

  // Location match (bonus)
  if (a.location && b.location && a.location.toLowerCase().includes(b.location.split(',')[0].toLowerCase().trim())) {
    score += 5;
    reasons.push('Same region');
  }

  return { score: Math.min(score, 100), reasons };
}

// ── SMART CONNECTIONS PAGE (ADMIN MONITORING DASHBOARD) ──
function pgConnections() {
  if (!_allProfiles.length) {
    loadAllProfiles().then(p => { _allProfiles = p; return loadIntroductions(); }).then(i => { _introductions = i; render('admin'); });
    return `<div style="text-align:center;padding:40px"><div style="font-size:32px;margin-bottom:12px">⏳</div><p>Loading ecosystem connections...</p></div>`;
  }

  const trackedIntros = _introductions;

  // Calculate stats for monitoring dashboard
  const activeUsers = _allProfiles.filter(p => !p.blocked && p.onboarding_complete).length;
  const mutualAccepts = trackedIntros.filter(i => i.status === 'mutual_accept').length;
  const introduced = trackedIntros.filter(i => i.status === 'introduced').length;
  const connected = trackedIntros.filter(i => i.status === 'connected').length;
  const declined = trackedIntros.filter(i => i.status === 'declined').length;
  const successRate = introduced + connected + declined > 0 ? Math.round((connected / (introduced + connected + declined)) * 100) : 0;
  const thisMonthIntros = trackedIntros.filter(i => new Date(i.created_at) >= new Date(new Date().getFullYear(), new Date().getMonth(), 1)).length;

  // Split intros by pipeline stage
  const emailPending = trackedIntros.filter(i => i.status === 'mutual_accept');
  const inProgress = trackedIntros.filter(i => i.status === 'introduced');
  const connectedIntros = trackedIntros.filter(i => i.status === 'connected');
  const failedIntros = trackedIntros.filter(i => ['declined','outcome_reported'].includes(i.status));

  // Stats cards
  const statsHtml = `<div class="admin-stat-row" style="margin-bottom:18px">
    <div class="admin-mini-stat"><div class="ams-val">${activeUsers}</div><div class="ams-lbl">Active Users</div></div>
    <div class="admin-mini-stat"><div class="ams-val">${thisMonthIntros}</div><div class="ams-lbl">Matches Made (Month)</div></div>
    <div class="admin-mini-stat"><div class="ams-val">${mutualAccepts}</div><div class="ams-lbl">Mutual Accepts Pending Email</div></div>
    <div class="admin-mini-stat"><div class="ams-val">${connected}</div><div class="ams-lbl">Introductions Completed</div></div>
    <div class="admin-mini-stat"><div class="ams-val">${successRate}%</div><div class="ams-lbl">Success Rate</div></div>
  </div>`;

  // Pipeline: Mutual Accepts (Need Email)
  const emailCards = emailPending.map(intro => {
    const pA = _allProfiles.find(p => p.id === intro.person_a);
    const pB = _allProfiles.find(p => p.id === intro.person_b);
    if (!pA || !pB) return '';
    const aName = pA.full_name || pA.email;
    const bName = pB.full_name || pB.email;
    return `<div class="admin-user-card" style="padding:14px;border-left:4px solid var(--green)">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap">
        <div style="flex:1">
          <div style="font-size:12px;font-weight:600;margin-bottom:4px">
            <span class="admin-tag tag-${pA.persona}">${personaIcon(pA.persona)} ${aName}</span>
            <span style="color:var(--text-faint);margin:0 4px">↔</span>
            <span class="admin-tag tag-${pB.persona}">${personaIcon(pB.persona)} ${bName}</span>
          </div>
          <div style="font-size:11px;color:var(--text-muted)">${(intro.match_reasons || []).join(', ')}</div>
        </div>
        <div style="background:var(--green);color:#fff;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:700">${intro.match_score || 0}%</div>
      </div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        <button onclick="sendIntroEmail('${intro.id}')" style="padding:6px 14px;background:var(--green);color:#fff;border:none;border-radius:6px;font-size:11px;font-weight:700;cursor:pointer">📧 Send Introduction Email</button>
        <span style="font-size:9px;color:var(--text-faint);padding:6px 0">${new Date(intro.created_at).toLocaleDateString('en-US',{month:'short',day:'numeric'})}</span>
      </div>
    </div>`;
  }).join('');

  // Pipeline: Introduced (In Progress)
  const inProgressCards = inProgress.map(intro => {
    const pA = _allProfiles.find(p => p.id === intro.person_a);
    const pB = _allProfiles.find(p => p.id === intro.person_b);
    if (!pA || !pB) return '';
    const aName = pA.full_name || pA.email;
    const bName = pB.full_name || pB.email;
    const daysSince = Math.floor((Date.now() - new Date(intro.introduced_at || intro.created_at).getTime()) / 864e5);
    return `<div class="admin-user-card" style="padding:14px;border-left:4px solid #3b82f6">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap">
        <div style="flex:1">
          <div style="font-size:12px;font-weight:600;margin-bottom:4px">
            <span class="admin-tag tag-${pA.persona}">${personaIcon(pA.persona)} ${aName}</span>
            <span style="color:var(--text-faint);margin:0 4px">↔</span>
            <span class="admin-tag tag-${pB.persona}">${personaIcon(pB.persona)} ${bName}</span>
          </div>
          <div style="font-size:10px;color:var(--text-faint)">${daysSince} day${daysSince!==1?'s':''} since introduction</div>
        </div>
        <div style="background:#3b82f6;color:#fff;padding:3px 10px;border-radius:12px;font-size:11px;font-weight:700">${intro.match_score || 0}%</div>
      </div>
    </div>`;
  }).join('');

  // Pipeline: Connected
  const connectedCards = connectedIntros.map(intro => {
    const pA = _allProfiles.find(p => p.id === intro.person_a);
    const pB = _allProfiles.find(p => p.id === intro.person_b);
    if (!pA || !pB) return '';
    const aName = pA.full_name || pA.email;
    const bName = pB.full_name || pB.email;
    return `<div class="admin-user-card" style="padding:14px;border-left:4px solid var(--green)">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <div style="flex:1">
          <div style="font-size:12px;font-weight:600">
            <span class="admin-tag tag-${pA.persona}">${personaIcon(pA.persona)} ${aName}</span>
            <span style="color:var(--text-faint);margin:0 4px">↔</span>
            <span class="admin-tag tag-${pB.persona}">${personaIcon(pB.persona)} ${bName}</span>
          </div>
        </div>
        <span style="font-size:12px;font-weight:700;color:var(--green)">✅ Connected</span>
      </div>
    </div>`;
  }).join('');

  // Pipeline: Failed/Declined
  const failedCards = failedIntros.map(intro => {
    const pA = _allProfiles.find(p => p.id === intro.person_a);
    const pB = _allProfiles.find(p => p.id === intro.person_b);
    if (!pA || !pB) return '';
    const aName = pA.full_name || pA.email;
    const bName = pB.full_name || pB.email;
    return `<div class="admin-user-card" style="padding:14px;border-left:4px solid #ef4444;opacity:.7">
      <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <div style="flex:1">
          <div style="font-size:12px;font-weight:600">
            <span class="admin-tag tag-${pA.persona}">${personaIcon(pA.persona)} ${aName}</span>
            <span style="color:var(--text-faint);margin:0 4px">↔</span>
            <span class="admin-tag tag-${pB.persona}">${personaIcon(pB.persona)} ${bName}</span>
          </div>
        </div>
        <span style="font-size:12px;font-weight:700;color:#ef4444">❌ ${intro.status === 'declined' ? 'Declined' : 'Reported'}</span>
      </div>
    </div>`;
  }).join('');

  return `<div class="page-hdr">
    <h1>🤝 Introduction Monitoring Dashboard</h1>
    <p>Track AI-matched introductions through each stage of the pipeline. Algorithm recommends → Both users accept → Email sent → Monitor outcomes.</p>
  </div>
  ${statsHtml}

  <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(350px,1fr));gap:14px">
    <div class="card">
      <h3 style="margin-top:0;color:var(--green)">📩 Mutual Accepts (Need Email)</h3>
      <div style="font-size:11px;color:var(--text-muted);margin-bottom:12px">${mutualAccepts} introductions ready to send.</div>
      ${emailCards ? emailCards : '<div style="text-align:center;padding:20px;color:var(--text-faint)"><p>No pending emails</p></div>'}
    </div>

    <div class="card">
      <h3 style="margin-top:0;color:#3b82f6">🤝 Introduced (In Progress)</h3>
      <div style="font-size:11px;color:var(--text-muted);margin-bottom:12px">${introduced} introductions awaiting outcomes.</div>
      ${inProgressCards ? inProgressCards : '<div style="text-align:center;padding:20px;color:var(--text-faint)"><p>No introductions in progress</p></div>'}
    </div>

    <div class="card">
      <h3 style="margin-top:0;color:var(--green)">✅ Connected</h3>
      <div style="font-size:11px;color:var(--text-muted);margin-bottom:12px">${connected} successful introductions.</div>
      ${connectedCards ? connectedCards : '<div style="text-align:center;padding:20px;color:var(--text-faint)"><p>No connections yet</p></div>'}
    </div>

    ${failedIntros.length > 0 ? `<div class="card">
      <h3 style="margin-top:0;color:#ef4444">❌ Declined/No Response</h3>
      <div style="font-size:11px;color:var(--text-muted);margin-bottom:12px">${failedIntros.length} outcomes.</div>
      ${failedCards}
    </div>` : ''}
  </div>`;
}

async function makeIntro(aId, bId, score, reasons) {
  const intro = await createIntroduction(aId, bId, score, typeof reasons === 'string' ? JSON.parse(reasons) : reasons);
  if (intro) {
    _introductions.unshift(intro);
    toast('🤝 Introduction created! Now go make the connection.');
    render('admin');
  }
}

async function saveIntroLater(aId, bId, score, reasons) {
  const intro = await createIntroduction(aId, bId, score, typeof reasons === 'string' ? JSON.parse(reasons) : reasons);
  if (intro) {
    _introductions.unshift(intro);
    toast('📌 Saved for later');
    render('admin');
  }
}

// ══════════════════════════════════════════════════════════════
// USER-FACING CONNECTIONS PAGE
// ══════════════════════════════════════════════════════════════
let _userIntros = []; // intros involving the current user
let connTab = 'discover'; // 'discover' | 'active' | 'history'

async function loadUserIntros() {
  if (!currentUser) return [];
  const { data, error } = await _supabase.from('introductions').select('*')
    .or(`person_a.eq.${currentUser.id},person_b.eq.${currentUser.id}`)
    .order('created_at', { ascending: false });
  if (error) { console.error('loadUserIntros:', error); return []; }
  return data || [];
}

function getIntroPauseStatus(p) {
  // Check if user has pending outcome reports (intros marked 'introduced' > 30 days ago with no outcome)
  if (!p || !_userIntros.length) return { paused: false, pendingCount: 0 };
  const now = Date.now();
  const pending = _userIntros.filter(i => {
    if (i.status !== 'introduced') return false;
    const introDate = new Date(i.introduced_at || i.created_at).getTime();
    const daysSince = (now - introDate) / 864e5;
    return daysSince > 30 && !i.outcome_a && !i.outcome_b;
  });
  return { paused: pending.length > 0, pendingCount: pending.length };
}

function getOtherPerson(intro) {
  if (!currentUser) return null;
  const otherId = intro.person_a === currentUser.id ? intro.person_b : intro.person_a;
  return _allProfiles.find(p => p.id === otherId);
}

function introStatusPipeline(status) {
  const steps = ['suggested','introduced','outcome','connected'];
  const labels = { suggested:'Suggested', introduced:'Introduced', outcome:'Reviewed', connected:'Connected' };
  const icons = { suggested:'💡', introduced:'🤝', outcome:'📝', connected:'✅' };
  // Map new statuses to old pipeline steps for compatibility
  let mappedStatus = status;
  if (status === 'pending_both') mappedStatus = 'suggested';
  if (status === 'mutual_accept') mappedStatus = 'suggested';
  const current = status === 'declined' ? -1 : steps.indexOf(mappedStatus === 'connected' ? 'connected' : mappedStatus === 'outcome_reported' ? 'outcome' : mappedStatus);

  return `<div class="ii-timeline">${steps.map((s, i) => {
    const cls = i < current ? 'done' : i === current ? 'active' : 'pending';
    const sep = i < steps.length - 1 ? `<div class="ii-line ${i < current ? 'done' : ''}"></div>` : '';
    return `<div class="ii-step"><div class="ii-dot ${cls}">${i <= current ? icons[s] : (i+1)}</div><div class="ii-label">${labels[s]}</div></div>${sep}`;
  }).join('')}</div>`;
}

function getIntroCountThisMonth(userId) {
  if (!_userIntros) return 0;
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
  return _userIntros.filter(i =>
    (i.person_a === userId || i.person_b === userId) &&
    i.status !== 'declined' &&
    new Date(i.created_at) >= monthStart
  ).length;
}

function getUserTier(profile) {
  // Founding members get permanent elevated tier
  if (profile.tier === 'founding_member' || (profile.badges || []).includes('founding_member')) return 'founding_member';
  // Use existing tier logic from TIER_DEFS
  const badges = (profile.badges || []).length;
  let tier = 'explorer';
  for (const t of TIER_DEFS) {
    if (badges >= t.min) tier = t.id;
  }
  return tier;
}

async function sendIntroEmail(introId) {
  // Get the intro record
  const intro = _userIntros.find(i => i.id === introId) || _introductions?.find(i => i.id === introId);
  if (!intro) return;

  // Get both user profiles
  const profileA = _allProfiles.find(p => p.id === intro.person_a);
  const profileB = _allProfiles.find(p => p.id === intro.person_b);
  if (!profileA || !profileB) return;

  const nameA = profileA.full_name || profileA.email;
  const nameB = profileB.full_name || profileB.email;
  const reasons = (intro.match_reasons || []).join(', ');

  // Build email body
  const subject = `Introduction: ${nameA} ↔ ${nameB} | FounderOps Center`;
  const body = `Hi ${nameA.split(' ')[0]} and ${nameB.split(' ')[0]},\n\nI'm excited to introduce you both! The FounderOps Center platform identified you as a strong match based on: ${reasons}.\n\n${nameA} — ${profileA.persona || 'AgTech professional'} ${profileA.company ? 'at ' + profileA.company : ''}\n${nameB} — ${profileB.persona || 'AgTech professional'} ${profileB.company ? 'at ' + profileB.company : ''}\n\nI'll leave it to you both to find a time to connect. Feel free to reply-all to this thread.\n\nBest,\nRussell Cole\nFounder, FounderOps Center`;

  // Update intro status to mutual_accept -> introduced
  await _supabase.from('introductions').update({
    status: 'introduced',
    introduced_at: new Date().toISOString(),
    admin_notes: 'Auto-matched. Email sent via mailto.'
  }).eq('id', introId);

  // Open mailto link for Russell to send
  const mailto = `mailto:${profileA.email},${profileB.email}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  window.open(mailto, '_blank');

  toast('📧 Email draft opened. Send to complete the introduction.');
  render('admin');
}

function connTabBar(active) {
  const tabs = [
    { id:'discover', icon:'🔍', label:'Discover' },
    { id:'active', icon:'🤝', label:'Active Intros' },
    { id:'history', icon:'📋', label:'History' }
  ];
  return `<div style="display:flex;gap:4px;background:var(--hover);padding:4px;border-radius:10px;margin-bottom:18px;overflow-x:auto">
    ${tabs.map(t => `<button onclick="setConnTab('${t.id}')" style="flex:1;padding:9px 16px;border:none;border-radius:8px;font-size:12px;font-weight:${active===t.id?'700':'500'};cursor:pointer;background:${active===t.id?'var(--surface)':'none'};color:${active===t.id?'var(--text)':'var(--text-muted)'};white-space:nowrap;display:flex;align-items:center;justify-content:center;gap:5px;${active===t.id?'box-shadow:0 1px 4px rgba(0,0,0,.08)':''}">${t.icon} ${t.label}</button>`).join('')}
  </div>`;
}

function pgUserConnections() {
  if (!currentUser) return `<div class="admin-lock"><h2>🤝 Sign In Required</h2><p>Sign in to discover connections in the AgTech ecosystem.</p>
    <button onclick="openModal('signin-modal')" style="padding:11px 24px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">Sign In</button></div>`;

  const p = _userProfile;
  if (!p || !p.onboarding_complete) return `<div class="admin-lock"><h2>🤝 Complete Your Profile First</h2><p>Finish your profile to unlock connections and introductions.</p>
    <button onclick="showWizard()" style="padding:11px 24px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">Set Up Profile →</button></div>`;

  // Load data if needed
  if (!_allProfiles.length || !_userIntros.length) {
    const promises = [];
    if (!_allProfiles.length) promises.push(loadAllProfiles().then(r => { _allProfiles = r; }));
    promises.push(loadUserIntros().then(r => { _userIntros = r; }));
    if (promises.length) {
      Promise.all(promises).then(() => render('connections'));
      return `<div style="text-align:center;padding:40px"><div style="font-size:32px;margin-bottom:12px">⏳</div><p>Loading your connections...</p></div>`;
    }
  }

  const pauseStatus = getIntroPauseStatus(p);
  let pauseBanner = '';
  if (pauseStatus.paused) {
    pauseBanner = `<div class="intro-pause-banner">
      <div style="font-size:28px">⏸️</div>
      <div style="flex:1">
        <div style="font-size:13px;font-weight:700;color:#ef4444;margin-bottom:2px">Intro Requests Paused</div>
        <div style="font-size:12px;color:var(--text-muted)">You have ${pauseStatus.pendingCount} introduction${pauseStatus.pendingCount!==1?'s':''} awaiting your outcome report. Complete them to request new introductions.</div>
        <button onclick="setConnTab('active')" style="margin-top:6px;padding:6px 14px;background:#ef4444;color:#fff;border:none;border-radius:6px;font-size:11px;font-weight:700;cursor:pointer">Review Now →</button>
      </div>
    </div>`;
  }

  // Active intros count for tab badge
  const activeCount = _userIntros.filter(i => ['suggested','introduced','pending'].includes(i.status)).length;
  const pendingOutcomeCount = _userIntros.filter(i => {
    if (i.status !== 'introduced') return false;
    const d = (Date.now() - new Date(i.introduced_at || i.created_at).getTime()) / 864e5;
    return d > 14;
  }).length;

  let content = '';
  if (connTab === 'discover') content = connDiscoverTab(p, pauseStatus);
  else if (connTab === 'active') content = connActiveTab(p);
  else content = connHistoryTab(p);

  return `<div class="page-hdr">
    <h1>🤝 My Connections</h1>
    <p>Discover relevant people in the ecosystem, request introductions, and track your interactions.</p>
  </div>
  ${pauseBanner}
  ${connTabBar(connTab)}
  ${content}`;
}

function connFallbackBrowse(active, pauseStatus) {
  let html = '<div class="conn-empty"><div class="ce-icon">🌱</div>';
  html += '<p>No strong matches right now, but that doesn\'t mean there\'s no one worth talking to.</p>';
  html += '<p style="margin-top:8px;font-size:13px;color:var(--text-muted)">Browse the people already in the ecosystem below. As more people join and complete their profiles, smarter matches will appear here automatically.</p>';
  if (active.length > 0) {
    html += '<div style="margin-top:16px"><h4 style="font-size:13px;font-weight:700;margin-bottom:10px;color:var(--text)">👥 People in the Ecosystem</h4>';
    html += '<div class="conn-discover-grid">';
    active.slice(0, 12).forEach(o => {
      const td = tierDef(o.tier || 'explorer');
      const oBadges = calcBadges(o);
      const badgeDefs = getBadgesForPersona(o.persona);
      const pills = oBadges.slice(0, 4).map(bid => {
        const bdef = badgeDefs.find(b => b.id === bid);
        return bdef ? '<span style="font-size:9px;padding:2px 7px;border-radius:99px;background:rgba(34,197,94,.08);color:var(--green);font-weight:600;border:1px solid rgba(34,197,94,.15)">' + bdef.icon + ' ' + bdef.label + '</span>' : '';
      }).filter(Boolean).join('');
      const overflow = oBadges.length > 4 ? '<span style="font-size:9px;padding:2px 7px;color:var(--text-faint)">+' + (oBadges.length - 4) + ' more</span>' : '';
      html += '<div class="conn-card">';
      html += '<div class="cc-hdr">';
      html += '<div class="cc-avatar">' + (o.avatar_url ? '<img src="' + o.avatar_url + '">' : (o.full_name || '?')[0].toUpperCase()) + '</div>';
      html += '<div>';
      html += '<div class="cc-name">' + (o.full_name || 'Anonymous') + ' <span style="font-size:11px;color:' + td.color + ';font-weight:600">' + td.icon + '</span></div>';
      html += '<div class="cc-meta">' + personaIcon(o.persona) + ' ' + personaLabel(o.persona) + (o.organization ? ' · ' + o.organization : '') + (o.location ? ' · ' + o.location : '') + '</div>';
      html += '</div></div>';
      if (pills) html += '<div style="display:flex;flex-wrap:wrap;gap:4px;margin:6px 0">' + pills + overflow + '</div>';
      html += '<div class="cc-actions">';
      html += '<button class="conn-btn primary" ' + (pauseStatus.paused ? 'disabled title="Complete pending outcome reports first"' : '') + ' onclick="requestIntro(\'' + o.id + '\',1,[&quot;Part of the AgTech ecosystem&quot;])">🤝 Request Intro</button>';
      html += '</div></div>';
    });
    html += '</div></div>';
  } else {
    html += '<p style="margin-top:12px;font-size:12px;color:var(--text-faint)">You\'re one of the first here. Invite someone you think would benefit from being part of this network.</p>';
  }
  html += '</div>';
  return html;
}

function connDiscoverTab(p, pauseStatus) {
  // Guard: ensure data is loaded before rendering
  if (!_allProfiles.length) return `<div style="text-align:center;padding:40px"><div style="font-size:32px;margin-bottom:12px">⏳</div><p>Loading matches...</p></div>`;

  const tierOrder = ['explorer','builder','operator','leader'];
  const myTier = tierOrder.indexOf(p.tier || 'explorer');
  const active = _allProfiles.filter(pr => !pr.blocked && pr.onboarding_complete && pr.id !== p.id && pr.blocked_reason !== 'DELETED_BY_ADMIN');

  // Get matches for this user specifically
  const matches = [];
  for (const other of active) {
    const otherTier = tierOrder.indexOf(other.tier || 'explorer');
    const otherPref = tierOrder.indexOf(other.intro_tier_pref || 'explorer');
    const meetsOtherPref = myTier >= otherPref;
    const result = scoreMatch(p, other);
    if (result.score >= 5) {
      matches.push({ other, score: result.score, reasons: result.reasons, meetsOtherPref, tierGap: otherPref - myTier });
    }
  }
  // If no scored matches, show all active users as potential connections
  if (matches.length === 0 && active.length > 0) {
    for (const other of active) {
      const otherTier = tierOrder.indexOf(other.tier || 'explorer');
      const otherPref = tierOrder.indexOf(other.intro_tier_pref || 'explorer');
      const meetsOtherPref = myTier >= otherPref;
      matches.push({ other, score: 1, reasons: ['Part of the AgTech ecosystem'], meetsOtherPref, tierGap: otherPref - myTier });
    }
  }
  matches.sort((a, b) => b.score - a.score);

  // Track intro limits
  const myTierObj = TIER_DEFS.find(t => t.id === (p.tier || 'explorer'));
  const introLimit = INTRO_LIMITS[getUserTier(p)] || 1;
  const introCountThisMonth = getIntroCountThisMonth(p.id);
  const remainingIntros = Math.max(0, introLimit - introCountThisMonth);

  // Split into different categories
  const existingPairs = new Set(_userIntros.map(i => [i.person_a, i.person_b].sort().join('|')));
  const pendingBothAccept = _userIntros.filter(i => i.status === 'pending_both');
  const matchedNotRequested = matches.filter(m => !existingPairs.has([p.id, m.other.id].sort().join('|')) && m.meetsOtherPref);
  const tierGated = matches.filter(m => !m.meetsOtherPref && !existingPairs.has([p.id, m.other.id].sort().join('|')));

  // Launch threshold gate banner
  const totalMembers = _allProfiles.length;
  const introNetworkLive = totalMembers >= INTRO_LAUNCH_THRESHOLD;
  const launchBanner = !introNetworkLive ? `<div style="background:linear-gradient(135deg,#0f172a,#1e293b);border:1px solid var(--green-mid);border-radius:12px;padding:20px;margin-bottom:18px;text-align:center">
    <div style="font-size:24px;margin-bottom:8px">🚀</div>
    <div style="font-size:15px;font-weight:800;color:white;margin-bottom:6px">Intro Network Launches at ${INTRO_LAUNCH_THRESHOLD} Members</div>
    <div style="font-size:12px;color:#94a3b8;margin-bottom:12px">${totalMembers} of ${INTRO_LAUNCH_THRESHOLD} members joined — ${INTRO_LAUNCH_THRESHOLD - totalMembers} more to go!</div>
    <div style="height:8px;background:rgba(255,255,255,.1);border-radius:4px;overflow:hidden;max-width:300px;margin:0 auto 12px">
      <div style="height:100%;width:${Math.round(totalMembers/INTRO_LAUNCH_THRESHOLD*100)}%;background:var(--green);border-radius:4px;transition:width 0.3s"></div>
    </div>
    <div style="font-size:11px;color:#64748b">Share the platform to unlock introductions sooner. Founding members get <strong style="color:var(--green)">10 intros/month</strong> permanently.</div>
  </div>` : '';

  // Stat bar
  const statsHtml = `${launchBanner}<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px;margin-bottom:18px">
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center">
      <div style="font-size:22px;font-weight:800;color:${remainingIntros > 0 ? 'var(--green)' : '#ef4444'}">${introNetworkLive ? remainingIntros : '🔒'}</div>
      <div style="font-size:11px;color:var(--text-muted);font-weight:600">${introNetworkLive ? 'Remaining Intros' : 'Intros Locked'}</div>
      <div style="font-size:9px;color:var(--text-faint);margin-top:2px">${introNetworkLive ? introCountThisMonth + ' of ' + introLimit + ' used' : 'Launches at ' + INTRO_LAUNCH_THRESHOLD + ' members'}</div>
    </div>
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center">
      <div style="font-size:22px;font-weight:800;color:#f59e0b">${pendingBothAccept.length}</div>
      <div style="font-size:11px;color:var(--text-muted);font-weight:600">Waiting for You</div>
    </div>
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center">
      <div style="font-size:22px;font-weight:800;color:#3b82f6">${_userIntros.filter(i=>['introduced','mutual_accept'].includes(i.status)).length}</div>
      <div style="font-size:11px;color:var(--text-muted);font-weight:600">Active Intros</div>
    </div>
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center">
      <div style="font-size:22px;font-weight:800;color:#7c3aed">${_userIntros.filter(i=>i.status==='connected').length}</div>
      <div style="font-size:11px;color:var(--text-muted);font-weight:600">Connected</div>
    </div>
  </div>`;

  // Build recommended matches cards
  const recommendedCards = matchedNotRequested.slice(0, 10).map(m => {
    const o = m.other;
    const scoreColor = m.score >= 60 ? 'var(--green)' : m.score >= 40 ? '#f59e0b' : '#94a3b8';
    const td = tierDef(o.tier || 'explorer');
    const oBadges = calcBadges(o);
    const badgeDefs = getBadgesForPersona(o.persona);
    const badgePills = oBadges.slice(0, 4).map(bid => {
      const bdef = badgeDefs.find(b => b.id === bid);
      return bdef ? `<span style="font-size:9px;padding:2px 7px;border-radius:99px;background:rgba(34,197,94,.08);color:var(--green);font-weight:600;border:1px solid rgba(34,197,94,.15)">${bdef.icon} ${bdef.label}</span>` : '';
    }).filter(Boolean).join('');
    const badgeOverflow = oBadges.length > 4 ? `<span style="font-size:9px;padding:2px 7px;color:var(--text-faint)">+${oBadges.length - 4} more</span>` : '';

    return `<div class="conn-card">
      <div class="cc-score" style="background:${scoreColor}">${m.score}%</div>
      <div class="cc-hdr">
        <div class="cc-avatar">${o.avatar_url ? `<img src="${o.avatar_url}">` : (o.full_name||'?')[0].toUpperCase()}</div>
        <div>
          <div class="cc-name">${o.full_name || 'Anonymous'} <span style="font-size:11px;color:${td.color};font-weight:600">${td.icon}</span></div>
          <div class="cc-meta">${personaIcon(o.persona)} ${personaLabel(o.persona)}${o.organization ? ' · ' + o.organization : ''}${o.location ? ' · ' + o.location : ''}</div>
        </div>
      </div>
      ${badgePills ? `<div style="display:flex;flex-wrap:wrap;gap:4px;margin:6px 0">${badgePills}${badgeOverflow}</div>` : ''}
      <div class="cc-reasons">${m.reasons.map(r => `<span class="cc-reason">${r}</span>`).join('')}</div>
      ${o.persona === 'founder' && o.what_building ? `<div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;padding:8px;background:var(--hover);border-radius:6px"><strong style="color:var(--text)">Building:</strong> ${o.what_building.substring(0,120)}${o.what_building.length>120?'...':''}</div>` : ''}
      ${o.persona === 'investor' && o.check_size ? `<div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;line-height:1.5;padding:8px;background:var(--hover);border-radius:6px"><strong style="color:var(--text)">Check Size:</strong> ${o.check_size}${o.investment_stages?.length ? ' · Stages: ' + o.investment_stages.join(', ') : ''}</div>` : ''}
      <div class="cc-actions">
        <button class="conn-btn primary" ${remainingIntros <= 0 ? 'disabled title="Monthly intro limit reached"' : pauseStatus.paused ? 'disabled title="Complete pending outcome reports first"' : ''} onclick="acceptIntroMatch('${o.id}',${m.score},${JSON.stringify(m.reasons).replace(/"/g,'&quot;')})">✅ Accept</button>
        <button class="conn-btn secondary" onclick="declineIntroMatch('${o.id}')">❌ Pass</button>
      </div>
    </div>`;
  }).join('');

  // Pending responses section (shows where we accepted but they haven't)
  let pendingSection = '';
  if (pendingBothAccept.length > 0) {
    pendingSection = `<div class="card" style="margin-top:18px;border-left:4px solid #f59e0b">
      <h3 style="margin-top:0">📩 Pending Responses</h3>
      <p style="font-size:12px;color:var(--text-muted);margin-bottom:12px">You've accepted these matches. Waiting for them to accept too.</p>
      <div style="display:flex;flex-direction:column;gap:10px">
        ${pendingBothAccept.map(intro => {
          const other = getOtherPerson(intro);
          if (!other) return '';
          const td = tierDef(other.tier || 'explorer');
          return `<div style="padding:12px;background:var(--surface);border:1px solid var(--border);border-radius:8px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px">
            <div style="display:flex;align-items:center;gap:8px">
              <div style="width:32px;height:32px;border-radius:50%;background:var(--hover);display:flex;align-items:center;justify-content:center;font-size:14px">${other.avatar_url ? `<img src="${other.avatar_url}" style="width:100%;height:100%;border-radius:50%;object-fit:cover">` : (other.full_name||'?')[0].toUpperCase()}</div>
              <div>
                <div style="font-size:12px;font-weight:600;color:var(--text)">${other.full_name || 'Anonymous'} <span style="font-size:10px;color:${td.color}">${td.icon}</span></div>
                <div style="font-size:11px;color:var(--text-muted)">⏳ Waiting for acceptance...</div>
              </div>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
  }

  // Browse all members section
  let browseSection = '';
  if (matchedNotRequested.length > 10) {
    browseSection = `<div class="card" style="margin-top:18px">
      <h3 style="margin-top:0">✨ Browse All Members</h3>
      <p style="font-size:12px;color:var(--text-muted);margin-bottom:12px">Explore the full ecosystem. You can also discover and accept matches manually here.</p>
      ${connFallbackBrowse(active, pauseStatus)}
    </div>`;
  }

  // Tier-gated teaser
  let tierGatedHtml = '';
  if (tierGated.length > 0) {
    const uniqueTierGated = tierGated.slice(0, 6);
    tierGatedHtml = `<div class="card" style="margin-top:18px">
      <h3>🔒 Unlock More Connections</h3>
      <p style="font-size:12px;color:var(--text-muted);margin-bottom:14px">${tierGated.length} potential match${tierGated.length!==1?'es':''} require a higher tier. Claim more milestones on your profile to level up and unlock these connections.</p>
      <div class="conn-discover-grid">
        ${uniqueTierGated.map(m => {
          const o = m.other;
          const neededTier = tierDef(o.intro_tier_pref || 'explorer');
          return `<div class="conn-card locked">
            <div class="cc-hdr">
              <div class="cc-avatar" style="background:var(--border)">🔒</div>
              <div>
                <div class="cc-name" style="filter:blur(4px)">${o.full_name || 'Anonymous'}</div>
                <div class="cc-meta">${personaIcon(o.persona)} ${personaLabel(o.persona)}${o.location ? ' · ' + o.location : ''}</div>
              </div>
            </div>
            <div class="conn-tier-gate">
              <div style="font-size:11px;font-weight:700;color:#f59e0b">${neededTier.icon} Requires ${neededTier.label} tier or above</div>
              <div style="font-size:10px;color:var(--text-faint);margin-top:3px">You need ${Math.max(0, neededTier.min - (calcBadges(p).length))} more badge${Math.max(0, neededTier.min - (calcBadges(p).length))!==1?'s':''} to unlock</div>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
  }

  return `${statsHtml}
  <div class="card">
    <h3>🤝 Recommended For You</h3>
    <p style="font-size:12px;color:var(--text-muted);margin-bottom:14px">AI-matched based on your persona, stage, needs, focus areas, and location. Accept a recommendation and the other person will be notified. When they accept too, we'll make the introduction.</p>
    ${recommendedCards ? `<div class="conn-discover-grid">${recommendedCards}</div>` : connFallbackBrowse(active, pauseStatus)}
  </div>
  ${pendingSection}
  ${browseSection}
  ${tierGatedHtml}`;
}

function connActiveTab(p) {
  const active = _userIntros.filter(i => ['suggested','introduced','pending','pending_both','mutual_accept'].includes(i.status));
  if (!active.length) return `<div class="conn-empty"><div class="ce-icon">🤝</div><p>No active introductions right now.<br>Head to the <strong>Discover</strong> tab to find relevant connections!</p></div>`;

  const now = Date.now();
  return `<div class="card">
    <h3 style="margin-bottom:4px">Active Introductions</h3>
    <p style="font-size:12px;color:var(--text-muted);margin-bottom:16px">Track your introductions from request through connection. Report outcomes to keep your intro privileges active.</p>
    <div class="intro-pipeline">
      ${active.map(intro => {
        const other = getOtherPerson(intro);
        if (!other) return '';
        const td = tierDef(other.tier || 'explorer');
        const introDate = new Date(intro.introduced_at || intro.created_at);
        const daysSince = Math.floor((now - introDate.getTime()) / 864e5);
        const needsOutcome = intro.status === 'introduced' && daysSince > 14;
        const urgentOutcome = intro.status === 'introduced' && daysSince > 30;
        const reasons = intro.match_reasons || [];

        // Determine status badge
        let statusBadge = '';
        if (intro.status === 'pending_both') {
          const iAmA = intro.person_a === currentUser.id;
          const iAccepted = iAmA ? intro.accepted_a : intro.accepted_b;
          const theyAccepted = iAmA ? intro.accepted_b : intro.accepted_a;
          if (iAccepted && !theyAccepted) {
            statusBadge = `<div class="ii-status" style="background:rgba(245,158,11,.1);color:#f59e0b">⏳ Waiting for them</div>`;
          } else if (!iAccepted) {
            statusBadge = `<div class="ii-status" style="background:rgba(59,130,246,.1);color:#3b82f6">❓ Action needed</div>`;
          }
        } else if (intro.status === 'mutual_accept') {
          statusBadge = `<div class="ii-status" style="background:rgba(34,197,94,.1);color:var(--green)">🎉 Email pending</div>`;
        } else {
          statusBadge = `<div class="ii-status" style="background:${intro.status==='suggested'?'rgba(245,158,11,.1);color:#f59e0b':intro.status==='introduced'?'rgba(59,130,246,.1);color:#3b82f6':'rgba(148,163,184,.1);color:var(--text-faint)'}">${intro.status === 'suggested' ? '⏳ Pending' : intro.status === 'introduced' ? '🤝 Introduced' : '📋 In Progress'}</div>`;
        }

        return `<div class="intro-item" style="${urgentOutcome ? 'border-color:rgba(239,68,68,.4);background:rgba(239,68,68,.02)' : needsOutcome ? 'border-color:rgba(245,158,11,.3);background:rgba(245,158,11,.02)' : ''}">
          <div class="ii-hdr">
            <div class="ii-persons">
              <span class="ii-person">${other.avatar_url ? `<img src="${other.avatar_url}" style="width:18px;height:18px;border-radius:50%">` : personaIcon(other.persona)} ${other.full_name || 'Anonymous'} <span style="color:${td.color};font-size:10px">${td.icon}</span></span>
              ${other.organization ? `<span style="font-size:10px;color:var(--text-faint)">${other.organization}</span>` : ''}
            </div>
            ${statusBadge}
          </div>

          ${introStatusPipeline(intro.status)}

          <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px">
            ${reasons.map(r => `<span style="font-size:10px;padding:2px 8px;background:var(--hover);border-radius:10px;color:var(--text-muted)">${r}</span>`).join('')}
          </div>

          <div style="display:flex;align-items:center;gap:8px;font-size:11px;color:var(--text-faint);margin-bottom:${needsOutcome ? '8' : '0'}px">
            <span>📅 ${introDate.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}</span>
            <span>·</span>
            <span>${daysSince} day${daysSince!==1?'s':''} ago</span>
            ${intro.match_score ? `<span>·</span><span>Match: ${intro.match_score}%</span>` : ''}
          </div>

          ${needsOutcome ? `<div class="outcome-form" id="outcome-form-${intro.id}">
            <div style="font-size:12px;font-weight:700;color:${urgentOutcome ? '#ef4444' : '#f59e0b'};margin-bottom:8px">${urgentOutcome ? '🚨 Outcome report overdue — your intro requests will be paused until you report' : '⏰ How did this intro go? Report to keep your intro privileges active'}</div>
            <div style="margin-bottom:8px">
              <div style="font-size:11px;font-weight:600;color:var(--text);margin-bottom:6px">How would you rate this connection?</div>
              <div class="outcome-stars" id="stars-${intro.id}">
                ${[1,2,3,4,5].map(n => `<span class="star" data-val="${n}" onclick="setOutcomeStars('${intro.id}',${n})">☆</span>`).join('')}
              </div>
            </div>
            <div style="margin-bottom:8px">
              <div style="font-size:11px;font-weight:600;color:var(--text);margin-bottom:4px">What happened?</div>
              <select id="outcome-type-${intro.id}" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text);margin-bottom:6px">
                <option value="">Select outcome...</option>
                <option value="meeting_scheduled">📅 Meeting scheduled</option>
                <option value="had_meeting">💬 Had a meeting</option>
                <option value="ongoing_discussion">🔄 Ongoing discussion</option>
                <option value="collaboration_started">🤝 Collaboration started</option>
                <option value="investment_discussion">💰 Investment discussion</option>
                <option value="pilot_started">🌱 Pilot started</option>
                <option value="couldnt_schedule">📅 Couldn't find a time to meet</option>
                <option value="meeting_cancelled">🚫 Meeting didn't happen</option>
                <option value="no_fit">❌ Not a fit right now</option>
                <option value="no_response">📭 No response from other party</option>
              </select>
            </div>
            <textarea id="outcome-notes-${intro.id}" placeholder="Brief notes on how it went (optional)..."></textarea>
            <div style="display:flex;gap:8px;margin-top:8px">
              <button class="conn-btn primary" onclick="submitOutcome('${intro.id}')">Submit Report</button>
              ${!urgentOutcome ? `<button class="conn-btn secondary" onclick="document.getElementById('outcome-form-${intro.id}').style.display='none'">Later</button>` : ''}
            </div>
          </div>` : ''}
        </div>`;
      }).join('')}
    </div>
  </div>`;
}

function connHistoryTab(p) {
  const completed = _userIntros.filter(i => ['connected','declined','outcome_reported'].includes(i.status));
  if (!completed.length) return `<div class="conn-empty"><div class="ce-icon">📋</div><p>Your completed introductions will appear here.<br>Each interaction builds your network reputation.</p></div>`;

  return `<div class="card">
    <h3 style="margin-bottom:4px">Connection History</h3>
    <p style="font-size:12px;color:var(--text-muted);margin-bottom:16px">Past introductions and their outcomes. Quality interactions improve your ecosystem standing.</p>
    <div class="intro-pipeline">
      ${completed.map(intro => {
        const other = getOtherPerson(intro);
        if (!other) return '';
        const td = tierDef(other.tier || 'explorer');
        const introDate = new Date(intro.created_at);
        const statusEmoji = intro.status === 'connected' ? '✅' : intro.status === 'declined' ? '❌' : '📝';
        const statusLabel = intro.status === 'connected' ? 'Connected' : intro.status === 'declined' ? 'Declined' : 'Reported';
        const statusColor = intro.status === 'connected' ? 'var(--green)' : intro.status === 'declined' ? '#ef4444' : '#3b82f6';
        const stars = intro.outcome_rating || 0;

        return `<div class="intro-item">
          <div class="ii-hdr">
            <div class="ii-persons">
              <span class="ii-person">${personaIcon(other.persona)} ${other.full_name || 'Anonymous'} <span style="color:${td.color};font-size:10px">${td.icon}</span></span>
            </div>
            <span style="font-size:12px;font-weight:700;color:${statusColor}">${statusEmoji} ${statusLabel}</span>
          </div>
          <div style="display:flex;align-items:center;gap:12px;font-size:11px;color:var(--text-faint);margin-top:4px">
            <span>📅 ${introDate.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}</span>
            ${intro.match_score ? `<span>Match: ${intro.match_score}%</span>` : ''}
            ${stars > 0 ? `<span>${'★'.repeat(stars)}${'☆'.repeat(5-stars)}</span>` : ''}
            ${intro.outcome_type ? `<span style="padding:2px 8px;background:var(--hover);border-radius:10px">${intro.outcome_type.replace(/_/g,' ')}</span>` : ''}
          </div>
          ${intro.outcome_notes ? `<div style="font-size:11px;color:var(--text-muted);margin-top:6px;font-style:italic;padding:6px 10px;background:var(--hover);border-radius:6px">"${intro.outcome_notes}"</div>` : ''}
        </div>`;
      }).join('')}
    </div>
  </div>`;
}

let _outcomeStars = {};
function setOutcomeStars(introId, val) {
  _outcomeStars[introId] = val;
  const container = document.getElementById('stars-' + introId);
  if (container) {
    container.querySelectorAll('.star').forEach(s => {
      s.textContent = parseInt(s.dataset.val) <= val ? '★' : '☆';
      s.style.color = parseInt(s.dataset.val) <= val ? '#f59e0b' : 'var(--text-faint)';
    });
  }
}

async function requestIntro(otherId, score, reasons) {
  trackEvent('intro_requested', { target_id: otherId, match_score: score, reasons });

  // Check if intro network has launched (member threshold gate)
  const totalMembers = _allProfiles.length;
  if (totalMembers < INTRO_LAUNCH_THRESHOLD) {
    trackEvent('intro_blocked_threshold', { total_members: totalMembers, threshold: INTRO_LAUNCH_THRESHOLD });
    const remaining = INTRO_LAUNCH_THRESHOLD - totalMembers;
    toast(`🚀 Intro network launches at ${INTRO_LAUNCH_THRESHOLD} members — ${remaining} more to go! Invite others to unlock.`);
    return;
  }

  const pause = getIntroPauseStatus(_userProfile);
  if (pause.paused) { trackEvent('intro_blocked_pause'); toast('⏸️ Complete pending outcome reports first'); return; }

  const other = _allProfiles.find(p => p.id === otherId);
  if (!other) return;

  // Create introduction record (admin will facilitate)
  const reasonsParsed = typeof reasons === 'string' ? JSON.parse(reasons) : reasons;
  const { data, error } = await _supabase.from('introductions').insert({
    person_a: currentUser.id,
    person_b: otherId,
    match_score: score,
    match_reasons: reasonsParsed,
    status: 'suggested',
    requested_by: currentUser.id,
    requested_at: new Date().toISOString()
  }).select().single();

  if (error) {
    console.error('requestIntro error:', error);
    const msg = error.message || '';
    if (msg.includes('policy') || msg.includes('permission')) toast('❌ Permission denied — try signing out and back in');
    else if (msg.includes('duplicate') || msg.includes('unique')) toast('❌ You\'ve already requested this introduction');
    else if (msg.includes('network') || msg.includes('fetch')) toast('❌ Network error — check your connection');
    else toast('❌ Error requesting intro — please try again');
    return;
  }
  _userIntros.unshift(data);
  if (_introductions) _introductions.unshift(data);
  toast('🤝 Introduction requested! Russell will connect you soon.');
  connTab = 'active';
  render('connections');
}

async function acceptIntroMatch(otherId, score, reasons) {
  const pause = getIntroPauseStatus(_userProfile);
  if (pause.paused) { toast('⏸️ Complete pending outcome reports first'); return; }

  // Check if this intro already exists
  const existingIntro = _userIntros.find(i =>
    (i.person_a === currentUser.id && i.person_b === otherId) ||
    (i.person_a === otherId && i.person_b === currentUser.id)
  );

  const reasonsParsed = typeof reasons === 'string' ? JSON.parse(reasons) : reasons;

  if (existingIntro) {
    // If intro exists and they haven't accepted yet, mark us as accepted
    if (existingIntro.status === 'pending_both') {
      // Check if the OTHER user has accepted
      const iAmA = existingIntro.person_a === currentUser.id;
      const theyAccepted = iAmA ? existingIntro.accepted_b : existingIntro.accepted_a;

      if (theyAccepted) {
        // Both have accepted! Trigger email
        const update = { status: 'mutual_accept', [iAmA ? 'accepted_a' : 'accepted_b']: true };
        const { error } = await _supabase.from('introductions').update(update).eq('id', existingIntro.id);
        if (error) { console.error('acceptIntroMatch error:', error); toast('❌ Error accepting match'); return; }
        Object.assign(existingIntro, update);
        toast('🎉 Mutual match! Introduction email is ready.');
        render('connections');
      } else {
        // Just mark us as accepted, waiting for them
        const update = { [currentUser.id === existingIntro.person_a ? 'accepted_a' : 'accepted_b']: true };
        const { error } = await _supabase.from('introductions').update(update).eq('id', existingIntro.id);
        if (error) { console.error('acceptIntroMatch error:', error); toast('❌ Error accepting match'); return; }
        Object.assign(existingIntro, update);
        toast('✅ You accepted! Waiting for ' + (_allProfiles.find(p => p.id === otherId)?.full_name || 'them') + ' to accept.');
        render('connections');
      }
    }
  } else {
    // Create new intro with pending_both status and mark us as accepted
    const { data, error } = await _supabase.from('introductions').insert({
      person_a: currentUser.id,
      person_b: otherId,
      match_score: score,
      match_reasons: reasonsParsed,
      status: 'pending_both',
      accepted_a: true,
      accepted_b: false,
      created_at: new Date().toISOString()
    }).select().single();

    if (error) {
      console.error('acceptIntroMatch error:', error);
      const msg = error.message || '';
      if (msg.includes('policy') || msg.includes('permission')) toast('❌ Permission denied — try signing out and back in');
      else if (msg.includes('duplicate') || msg.includes('unique')) toast('❌ You\'ve already interacted with this person');
      else if (msg.includes('network') || msg.includes('fetch')) toast('❌ Network error — check your connection');
      else toast('❌ Error accepting match — please try again');
      return;
    }
    _userIntros.unshift(data);
    if (_introductions) _introductions.unshift(data);
    toast('✅ You accepted! Waiting for ' + (_allProfiles.find(p => p.id === otherId)?.full_name || 'them') + ' to accept.');
    render('connections');
  }
}

async function declineIntroMatch(otherId) {
  const existing = _userIntros.find(i =>
    (i.person_a === currentUser.id && i.person_b === otherId) ||
    (i.person_a === otherId && i.person_b === currentUser.id)
  );

  if (existing && existing.status === 'pending_both') {
    // Mark as declined
    const { error } = await _supabase.from('introductions').update({
      status: 'declined',
      declined_by: [currentUser.id]
    }).eq('id', existing.id);
    if (error) { console.error('declineIntroMatch error:', error); toast('❌ Error declining match'); return; }
    Object.assign(existing, { status: 'declined' });
  } else {
    // Create a declined record so we don't keep showing this person
    await _supabase.from('introductions').insert({
      person_a: currentUser.id,
      person_b: otherId,
      status: 'declined',
      declined_by: [currentUser.id],
      created_at: new Date().toISOString()
    }).select();
  }
  toast('👋 Noted. We won\'t show this person again.');
  render('connections');
}

async function submitOutcome(introId) {
  const typeEl = document.getElementById('outcome-type-' + introId);
  const notesEl = document.getElementById('outcome-notes-' + introId);
  const outcomeType = typeEl ? typeEl.value : '';
  const outcomeNotes = notesEl ? notesEl.value.trim() : '';
  const stars = _outcomeStars[introId] || 0;

  if (!outcomeType) { toast('Please select an outcome type'); return; }

  const isMyA = _userIntros.find(i => i.id === introId)?.person_a === currentUser.id;
  const update = {
    status: outcomeType === 'no_fit' || outcomeType === 'no_response' ? 'declined' : outcomeType === 'collaboration_started' || outcomeType === 'investment_discussion' || outcomeType === 'pilot_started' ? 'connected' : 'outcome_reported',
    outcome_type: outcomeType,
    outcome_notes: outcomeNotes,
    outcome_rating: stars,
    outcome_reported_at: new Date().toISOString()
  };
  // Store which party reported
  if (isMyA) update.outcome_a = true; else update.outcome_b = true;

  const { error } = await _supabase.from('introductions').update(update).eq('id', introId);
  if (error) { console.error('submitOutcome error:', error); toast('❌ Error saving outcome'); return; }

  // Update local data
  const local = _userIntros.find(i => i.id === introId);
  if (local) Object.assign(local, update);
  const adminLocal = _introductions?.find(i => i.id === introId);
  if (adminLocal) Object.assign(adminLocal, update);

  delete _outcomeStars[introId];
  toast(update.status === 'connected' ? '✅ Connection confirmed! Great work.' : update.status === 'declined' ? '📝 Thanks for the feedback.' : '📝 Outcome recorded. Keep connecting!');
  render('connections');
}

// ── ROUTER ────────────────────────────────────────────────────────
function pgRoadmapStandalone() {
  // For non-admin users with roadmap access
  if (!currentUser) return guestGateCard('roadmap');
  const hasAccess = isAdmin || (_userProfile && (_userProfile.admin_tags||[]).includes('roadmap_access'));
  if (!hasAccess) return `<div style="text-align:center;padding:60px 24px"><div style="font-size:48px;margin-bottom:16px">🔒</div><h2>Roadmap Access Required</h2><p style="color:var(--text-muted)">This section is invite-only. Contact Russell if you'd like access.</p></div>`;
  return `<div class="page-hdr"><h1>🗺️ Product Roadmap</h1><p>Strategic feature initiatives for FounderOps Center.</p></div>` + pgRoadmap();
}

