function hubAccordion(id, icon, title, count, content) {
  const open = _hubOpen[id];
  return `<div class="hub-accordion ${open ? 'open' : ''}">
    <div class="ha-header" onclick="hubToggle('${id}')">
      <span class="ha-icon">${icon}</span>
      <span class="ha-title">${title}</span>
      <span class="ha-count">${count}</span>
      <span class="ha-arrow">▼</span>
    </div>
    <div class="ha-body">${content}</div>
  </div>`;
}

function pgCommunityHub() {
  if (!currentUser) return guestGateCard('hub');

  // ── Mentors section (with search/filters) ──
  const mentorContent = hubMentorContent();

  // ── Communities section ──
  const commContent = `<div class="ac-grid">${HUB_COMMUNITIES.map(c => `
    <div class="ac-card">
      <div class="ac-icon">${c.icon}</div>
      <div class="ac-title">${c.name}</div>
      <div class="ac-org">${c.by}</div>
      <div style="margin-bottom:10px"><span class="ac-tag type">${c.type}</span></div>
      <div class="ac-desc">${c.desc}</div>
      <a href="${c.url}" target="_blank" rel="noopener" class="ac-btn primary">Join →</a>
    </div>`).join('')}</div>`;

  // ── Newsletters section ──
  const nlContent = `<div class="nl-grid">${HUB_NEWSLETTERS.map(n => {
    if (n.isHeader) return `<div class="nl-card" style="grid-column:1/-1;background:rgba(22,163,74,.04);border-color:rgba(22,163,74,.2)">
      <div class="nl-top">
        <div class="nl-emoji">${n.icon}</div>
        <div><div class="nl-name" style="color:var(--green)">${n.name}</div><div class="nl-by">${n.by}</div></div>
      </div>
      <div class="nl-desc">${n.desc}</div>
    </div>`;
    return `<div class="nl-card">
      <div class="nl-top">
        <div class="nl-emoji">${n.icon}</div>
        <div><div class="nl-name">${n.name}</div><div class="nl-by">${n.by}</div></div>
      </div>
      <div class="nl-freq">${n.freq}</div>
      <div class="nl-desc">${n.desc}</div>
      <a href="${n.url}" target="_blank" rel="noopener" class="ac-btn primary" style="text-align:center;justify-content:center">📩 Subscribe →</a>
    </div>`;
  }).join('')}</div>`;

  // ── Events section ──
  const evContent = `<div class="ac-grid">${HUB_EVENTS.map(e => `
    <div class="ac-card">
      <div class="ac-icon">${e.icon}</div>
      <div class="ac-title">${e.name}</div>
      <div class="ac-org">${e.location}</div>
      <div style="margin-bottom:10px"><span class="ac-tag event">📅 ${e.date}</span></div>
      <div class="ac-desc">${e.desc}</div>
      <a href="${e.url}" target="_blank" rel="noopener" class="ac-btn primary">Learn More →</a>
    </div>`).join('')}</div>`;

  // ── Podcasts section ──
  const podContent = `<div class="ac-grid">${HUB_PODCASTS.map(p => {
    const podUrl = LINKS[p.name] || '';
    return `<div class="ac-card" style="display:flex;flex-direction:column">
      <div class="ac-icon">${p.icon}</div>
      <div class="ac-title">${p.name}</div>
      <div style="margin-bottom:10px"><span class="ac-tag type">${p.type}</span><span class="ac-tag persona">${p.tag}</span></div>
      <div class="ac-desc" style="flex:1">${p.desc}</div>
      ${podUrl ? '<a href="'+podUrl+'" target="_blank" rel="noopener" class="ac-btn primary" style="margin-top:auto">Listen →</a>' : ''}
    </div>`;
  }).join('')}</div>`;

  // ── Thought Leaders section ──
  const leadContent = `<div class="ac-grid">${HUB_LEADERS.map(p => {
    const initials = p.n.split(' ').map(w=>w[0]).join('');
    const liUrl = LINKS[p.n] || '';
    return `<div class="ac-card" style="display:flex;flex-direction:column">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
        <div style="width:38px;height:38px;border-radius:50%;background:linear-gradient(135deg,#16a34a,#22c55e);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;color:#fff;flex-shrink:0">${initials}</div>
        <div style="min-width:0">
          <div class="ac-title" style="margin-bottom:0">${p.n}</div>
          <div class="ac-org">${p.r}</div>
        </div>
      </div>
      <div style="margin-bottom:8px"><span class="ac-tag type">${p.f}</span></div>
      <div class="ac-desc" style="flex:1">${p.d}</div>
      ${liUrl ? '<a href="'+liUrl+'" target="_blank" rel="noopener" class="ac-btn primary" style="margin-top:auto">Follow / Connect →</a>' : ''}
    </div>`;
  }).join('')}</div>`;

  return `<div class="page-hdr"><h1>🌐 Community Hub</h1>
    <p>Your front door to the entire AgTech ecosystem — people, communities, events, and resources.</p></div>
    ${hubAccordion('mentors', '🤝', 'People Directory — Mentors & Advisors', MENTORS.length, mentorContent)}
    ${hubAccordion('communities', '🌐', 'Communities & Working Groups', HUB_COMMUNITIES.length, commContent)}
    ${hubAccordion('events', '📅', 'Events & Conferences', HUB_EVENTS.length, evContent)}
    ${hubAccordion('newsletters', '📰', 'Newsletters & Media', HUB_NEWSLETTERS.length, nlContent)}
    ${hubAccordion('podcasts', '🎙️', 'Podcasts & Video', HUB_PODCASTS.length, podContent)}
    ${hubAccordion('leaders', '🌟', 'Thought Leaders to Follow', HUB_LEADERS.length, leadContent)}`;
}

function hubMentorContent() {
  const countryFlags = {US:'🇺🇸',CA:'🇨🇦',IN:'🇮🇳',AU:'🇦🇺',UK:'🇬🇧',CH:'🇨🇭',EU:'🇪🇺',SG:'🇸🇬',BR:'🇧🇷',NZ:'🇳🇿',USA:'🇺🇸',Canada:'🇨🇦',India:'🇮🇳',Australia:'🇦🇺'};
  const avatarColors = ['#FF6B6B','#4ECDC4','#45B7D1','#FFA07A','#98D8C8','#F7DC6F','#BB8FCE','#85C1E2','#F8B88B','#82E0AA'];
  function getInitials(name){ return name.split(' ').slice(0,2).map(n=>n[0]).join('').toUpperCase(); }
  function getAvatarColor(name){ let h=0;for(let i=0;i<name.length;i++){h=((h<<5)-h)+name.charCodeAt(i);h=h&h;} return avatarColors[Math.abs(h)%avatarColors.length]; }

  const agAreas = [...new Set(MENTORS.map(m=>m.agExpertise).filter(Boolean))].sort();
  const countries = [...new Set(MENTORS.map(m=>m.country).filter(Boolean))].sort();
  const availOpts = ['Yes','Limited'];
  const compOpts = [...new Set(MENTORS.map(m=>m.comp).filter(Boolean))].sort();

  const searchLower = mentorSearch.toLowerCase();
  const filtered = MENTORS.filter(m => {
    if (mentorFilter && m.agExpertise !== mentorFilter) return false;
    if (mentorCountry && m.country !== mentorCountry) return false;
    if (window._hubCompFilter && m.comp !== window._hubCompFilter) return false;
    if (window._hubAvailFilter && m.available !== window._hubAvailFilter) return false;
    if (searchLower) {
      const haystack = (m.name + ' ' + m.firm + ' ' + m.expertise + ' ' + (m.focusAreas||'') + ' ' + (m.agExpertise||'')).toLowerCase();
      return haystack.includes(searchLower);
    }
    return true;
  });

  const availColor = { Yes:'#16a34a', Limited:'#d97706' };
  const availCount = MENTORS.filter(m=>m.available==='Yes').length;

  // Detail view if mentor selected
  if (_selectedMentor) {
    const m = MENTORS.find(x=>x.id===_selectedMentor);
    if (!m) { _selectedMentor = null; }
    else {
      const flag = countryFlags[m.country]||'';
      const initials = getInitials(m.name);
      const avatarColor = getAvatarColor(m.name);
      let aClr = '#ef4444'; let aTxt = 'Limited';
      if(m.available==='Yes'){aClr='#22c55e';aTxt='Available Now';}
      else if(m.available==='Limited'){aClr='#eab308';aTxt='Limited Availability';}
      const focusTags = m.focusAreas ? m.focusAreas.split(',').map(fa => `<span style="display:inline-block;background:var(--hover);color:var(--text);padding:4px 10px;border-radius:6px;font-size:12px;margin:0 6px 6px 0">${fa.trim()}</span>`).join('') : '';
      const linkedinBtn = m.linkedin ? `<a href="${m.linkedin}" target="_blank" rel="noopener" style="display:inline-block;background:#0a66c2;color:white;padding:10px 16px;border-radius:8px;text-decoration:none;font-weight:600;font-size:13px;margin-right:10px">LinkedIn ↗</a>` : '';

      return `<a href="#" onclick="closeMentorInHub();return false" style="color:var(--green);text-decoration:none;font-size:13px;margin-bottom:16px;display:inline-block">← Back to People Directory</a>
        <div style="display:flex;align-items:flex-start;gap:20px;margin-bottom:24px">
          <div style="width:72px;height:72px;border-radius:50%;background:${avatarColor};display:flex;align-items:center;justify-content:center;color:white;font-weight:bold;font-size:24px;flex-shrink:0">${initials}</div>
          <div style="flex:1">
            <h2 style="margin:0 0 4px;font-size:22px;color:var(--text)">${m.name}</h2>
            <p style="margin:0 0 10px;color:var(--text-muted);font-size:14px">${m.firm}</p>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
              <span style="display:inline-flex;align-items:center;gap:4px;background:${aClr}20;color:${aClr};padding:5px 12px;border-radius:20px;font-size:11px;font-weight:600"><span style="width:7px;height:7px;background:${aClr};border-radius:50%"></span>${aTxt}</span>
              <span style="background:var(--hover);color:var(--text);padding:5px 12px;border-radius:20px;font-size:11px;font-weight:600">${m.comp}</span>
              <span style="background:var(--hover);color:var(--text);padding:5px 12px;border-radius:20px;font-size:11px;font-weight:600">${flag} ${m.country}</span>
            </div>
          </div>
        </div>
        <div class="card" style="padding:18px;margin-bottom:14px">
          <h3 style="margin:0 0 10px;font-size:14px;font-weight:600;color:var(--text)">About & Experience</h3>
          <p style="margin:0;color:var(--text);line-height:1.6;font-size:13px">${m.experience}</p>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
          <div class="card" style="padding:18px">
            <h3 style="margin:0 0 10px;font-size:14px;font-weight:600;color:var(--text)">Areas of Expertise</h3>
            <p style="margin:0 0 10px;color:var(--text);line-height:1.6;font-size:12px">${m.expertise}</p>
            <div style="margin-top:10px;padding-top:10px;border-top:1px solid var(--border)">${focusTags}</div>
            ${m.agExpertise ? `<div style="margin-top:10px;padding:6px 12px;background:var(--hover);border-radius:8px;font-size:11px;color:var(--text);font-weight:600">🌾 ${m.agExpertise}</div>` : ''}
          </div>
          <div class="card" style="padding:18px">
            <h3 style="margin:0 0 10px;font-size:14px;font-weight:600;color:var(--text)">Startups Worked With</h3>
            <p style="margin:0;color:var(--text);line-height:1.6;font-size:12px">${m.startups}</p>
          </div>
        </div>
        <div class="card" style="padding:18px;margin-bottom:14px">
          <h3 style="margin:0 0 12px;font-size:14px;font-weight:600;color:var(--text)">Connect</h3>
          <div style="display:flex;gap:10px;flex-wrap:wrap">
            ${linkedinBtn}
            ${currentUser ? `<button onclick="requestMentorIntro(${m.id})" style="background:var(--green);color:white;padding:10px 16px;border:none;border-radius:8px;font-weight:600;font-size:13px;cursor:pointer">🤝 Request Introduction</button>` : `<button onclick="openModal('signin-modal')" style="background:var(--green);color:white;padding:10px 16px;border:none;border-radius:8px;font-weight:600;font-size:13px;cursor:pointer">Sign in to Request Intro</button>`}
          </div>
        </div>
        <div style="padding:10px 14px;background:rgba(100,116,139,.05);border-radius:8px;border-left:3px solid var(--text-muted);font-size:10px;color:var(--text-muted)">
          <strong>Source:</strong> Western Growers Center for Innovation & Technology — AgTech Startup Mentor List (CC BY 4.0)
        </div>`;
    }
  }

  return `
    <!-- Stats bar -->
    <div style="display:flex;gap:12px;margin-bottom:16px;flex-wrap:wrap">
      <div style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--text-muted)"><span style="font-size:16px;font-weight:800;color:var(--green)">${MENTORS.length}</span> people</div>
      <div style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--text-muted)"><span style="width:8px;height:8px;border-radius:50%;background:#16a34a"></span> ${availCount} available now</div>
      <div style="display:flex;align-items:center;gap:6px;font-size:12px;color:var(--text-muted)">📍 ${countries.length} countries</div>
    </div>
    <!-- Filters -->
    <div style="display:flex;gap:8px;margin-bottom:16px;flex-wrap:wrap;align-items:center">
      <input type="text" placeholder="🔍 Search by name, expertise, focus..." value="${mentorSearch}" oninput="mentorSearch=this.value;clearTimeout(window._mentorDebounce);window._mentorDebounce=setTimeout(()=>{render('hub');setTimeout(()=>{const i=document.querySelector('input[placeholder*=Search\\ by\\ name]');if(i){i.focus();i.setSelectionRange(i.value.length,i.value.length)}},20)},300)" style="flex:1;min-width:200px;padding:9px 14px;border:1px solid var(--border);border-radius:8px;font-size:12px;background:var(--surface);color:var(--text)">
      <select onchange="mentorFilter=this.value;render('hub')" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;font-size:11px;background:var(--surface);color:var(--text)">
        <option value="">All Ag Areas</option>
        ${agAreas.map(a => '<option value="'+a+'"'+(mentorFilter===a?' selected':'')+'>'+a+'</option>').join('')}
      </select>
      <select onchange="mentorCountry=this.value;render('hub')" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;font-size:11px;background:var(--surface);color:var(--text)">
        <option value="">All Countries</option>
        ${countries.map(c => '<option value="'+c+'"'+(mentorCountry===c?' selected':'')+'>'+c+'</option>').join('')}
      </select>
      <select onchange="window._hubAvailFilter=this.value;render('hub')" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;font-size:11px;background:var(--surface);color:var(--text)">
        <option value="" ${!window._hubAvailFilter?'selected':''}>Availability: All</option>
        <option value="Yes" ${window._hubAvailFilter==='Yes'?'selected':''}>Available Now</option>
        <option value="Limited" ${window._hubAvailFilter==='Limited'?'selected':''}>Limited</option>
      </select>
      <select onchange="window._hubCompFilter=this.value;render('hub')" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;font-size:11px;background:var(--surface);color:var(--text)">
        <option value="" ${!window._hubCompFilter?'selected':''}>Compensation: All</option>
        ${compOpts.map(c => '<option value="'+c+'"'+(window._hubCompFilter===c?' selected':'')+'>'+c+'</option>').join('')}
      </select>
      <span style="font-size:11px;color:var(--text-faint)">${filtered.length} of ${MENTORS.length}</span>
    </div>
    ${filtered.length === 0 ? '<div class="conn-empty"><div class="ce-icon">🔍</div><p>No people match your filters. Try broadening your search.</p></div>' :
    `<div class="ac-grid">${filtered.slice(0,60).map(m => {
      const initials = getInitials(m.name);
      const avatarColor = getAvatarColor(m.name);
      const aClr = availColor[m.available] || '#9ca3af';
      const flag = countryFlags[m.country]||'';
      const expertise = m.expertise.substring(0,90)+(m.expertise.length>90?'...':'');
      return `<div class="ac-card" style="display:flex;flex-direction:column;cursor:pointer" onclick="openMentorFromHub(${m.id})">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
          <div style="width:42px;height:42px;border-radius:50%;background:${avatarColor};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#fff;flex-shrink:0">${initials}</div>
          <div style="min-width:0;flex:1">
            <div class="ac-title" style="margin-bottom:0">${m.name}</div>
            <div class="ac-org">${m.firm}</div>
          </div>
          <div style="flex-shrink:0"><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${aClr}"></span></div>
        </div>
        <div style="margin-bottom:8px;display:flex;flex-wrap:wrap;gap:4px">
          ${m.agExpertise ? '<span class="ac-tag type">'+m.agExpertise+'</span>' : ''}
          ${m.country ? '<span class="ac-tag persona">'+flag+' '+m.country+'</span>' : ''}
          ${m.comp ? '<span class="ac-tag" style="background:var(--hover);color:var(--text-muted)">'+m.comp+'</span>' : ''}
        </div>
        <div class="ac-desc" style="flex:1;font-size:11px">${expertise}</div>
        <div style="display:flex;gap:6px;margin-top:10px">
          ${currentUser ? `<button onclick="event.stopPropagation();requestMentorIntro(${m.id})" style="flex:1;padding:7px 10px;background:var(--green);color:white;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer">🤝 Request Intro</button>` : `<button onclick="event.stopPropagation();openModal('signin-modal')" style="flex:1;padding:7px 10px;background:var(--green);color:white;border:none;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer">Sign in for Intro</button>`}
          ${m.linkedin ? `<a href="${m.linkedin}" target="_blank" rel="noopener" onclick="event.stopPropagation()" style="padding:7px 10px;background:#0a66c215;color:#0a66c2;border:none;border-radius:6px;font-size:11px;font-weight:600;text-decoration:none;display:flex;align-items:center">in</a>` : ''}
        </div>
      </div>`;
    }).join('')}</div>
    ${filtered.length > 60 ? '<p style="text-align:center;color:var(--text-muted);font-size:12px;margin-top:16px">Showing first 60 of '+filtered.length+'. Use search or filters to narrow down.</p>' : ''}`}`;
}

