function pgActionCenter() {
  if (!currentUser) return guestGateCard('action');
  const p = _userProfile || {};
  const persona = _adminPersonaOverride || p.persona || 'early-stage';
  const allRecs = PERSONA_RECS[persona] || PERSONA_RECS['early-stage'];
  // Filter out "Complete profile" rec if profile is already done
  const recs = allRecs.filter(r => {
    if (r.title && r.title.includes('Complete your FounderOps profile') && p.onboarding_complete) return false;
    return true;
  });

  // Filter accelerators — sort open/upcoming first
  const now = new Date();
  const sortedAccel = [...ACTION_ACCELERATORS].sort((a,b) => {
    const aOpen = a.status === 'open' ? 0 : 1;
    const bOpen = b.status === 'open' ? 0 : 1;
    return aOpen - bOpen;
  });

  const personaLabel = { 'early-stage':'Early-Stage Founder', 'growth-stage':'Growth-Stage Founder', 'investor':'Investor / Advisor', 'researcher':'Researcher' };

  // Pending notifications
  const notifs = getNotifications();
  const notifSection = notifs.length ? `<div class="ac-section" style="border-left:3px solid ${notifs[0].priority <= 1 ? '#ef4444' : '#f59e0b'}">
    <div class="ac-section-hdr"><h3>🔔 Pending Actions</h3><span class="ac-count">${notifs.length}</span></div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px">
      ${notifs.map(n => `<div class="rec-card" style="cursor:pointer;border-left:3px solid ${n.priority<=1?'#ef4444':n.priority<=2?'#f59e0b':'var(--green)'}" onclick="go('${n.action}')">
        <div class="rec-icon">${n.icon}</div>
        <div class="rec-body">
          <div class="rec-title">${n.title}</div>
          <div class="rec-sub">${n.desc}</div>
        </div>
        <div style="color:var(--green);font-size:14px">→</div>
      </div>`).join('')}
    </div>
  </div>` : '';

  return `<div class="page-hdr"><h1>🎯 Action Center</h1>
    <p>What you should be doing this week — personalized for you as ${personaLabel[persona] || 'an AgTech professional'}.</p></div>

    ${notifSection}

    ${isAdmin && _ventureSubmissions.length ? `<div class="ac-section" style="border-left:3px solid #16a34a">
      <div class="ac-section-hdr"><h3>🚀 Venture Studio Pipeline</h3><span class="ac-count">${_ventureSubmissions.length} total</span></div>
      <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:12px">
        <span style="background:#dbeafe;color:#1e40af;padding:4px 10px;border-radius:6px;font-size:12px;font-weight:600">${_ventureSubmissions.filter(s=>s.status==='New').length} New</span>
        <span style="background:#fef3c7;color:#92400e;padding:4px 10px;border-radius:6px;font-size:12px;font-weight:600">${_ventureSubmissions.filter(s=>s.status==='Under Review').length} Under Review</span>
        <span style="background:#dcfce7;color:#166534;padding:4px 10px;border-radius:6px;font-size:12px;font-weight:600">${_ventureSubmissions.filter(s=>s.status==='Approved').length} Approved</span>
      </div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px">
        ${_ventureSubmissions.slice(0,6).map(s => `<div class="rec-card" style="cursor:pointer;border-left:3px solid ${s.status==='New'?'#3b82f6':s.status==='Under Review'?'#f59e0b':'#16a34a'}" onclick="go('venture')">
          <div class="rec-icon">${s.status==='New'?'🆕':s.status==='Under Review'?'🔍':'✅'}</div>
          <div class="rec-body">
            <div class="rec-title">${s.name||'Unnamed Idea'}</div>
            <div class="rec-sub">${s.pitch||'No pitch provided'}</div>
          </div>
          <div style="color:var(--green);font-size:14px">→</div>
        </div>`).join('')}
      </div>
      ${_ventureSubmissions.length > 6 ? '<div style="text-align:center;margin-top:8px"><a href="#" onclick="go(\'venture\');return false" style="color:var(--green);font-size:13px;font-weight:600">View all '+_ventureSubmissions.length+' submissions →</a></div>' : ''}
    </div>` : ''}

    <div class="ac-section">
      <div class="ac-section-hdr"><h3>⚡ Recommended For You</h3></div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px">
        ${recs.map(r => {
          const clickAttr = r.url ? `style="cursor:pointer" onclick="window.open('${r.url}','_blank')"` :
                            r.scrollTo ? `style="cursor:pointer" onclick="document.getElementById('${r.scrollTo}')?.scrollIntoView({behavior:'smooth'})"` :
                            r.action ? `style="cursor:pointer" onclick="go('${r.action}')"` : '';
          return `<div class="rec-card" ${clickAttr}>
          <div class="rec-icon">${r.icon}</div>
          <div class="rec-body">
            <div class="rec-title">${r.title}</div>
            <div class="rec-sub">${r.sub}</div>
          </div>
          ${(r.action || r.url) ? '<div style="color:var(--green);font-size:14px">→</div>' : ''}
        </div>`;
        }).join('')}
      </div>
    </div>

    <div id="ac-accel-section">
      <div class="hub-accordion ${_accelOpen ? 'open' : ''}">
        <div class="ha-header" onclick="toggleAccelOpen()">
          <span class="ha-icon">🏆</span><span class="ha-title">Pitch Competitions & Accelerators</span>
          <span class="ha-count">${sortedAccel.length} programs</span><span class="ha-arrow">▼</span>
        </div>
        <div class="ha-body">
          <p style="font-size:12px;color:var(--text-muted);margin-bottom:16px;line-height:1.6">Apply to programs with open deadlines, or bookmark upcoming ones. AgTech-specific programs shown first.</p>
          <div class="ac-grid">${sortedAccel.map(a => {
            const statusTag = a.status === 'open' ? '<span class="ac-tag open">✅ Open / Rolling</span>'
              : a.status === 'closing' ? '<span class="ac-tag closing">⚠️ Closing Soon</span>'
              : '<span class="ac-tag deadline">🔍 Check Dates</span>';
            return `<div class="ac-card">
              <div class="ac-icon">${a.icon}</div>
              <div class="ac-title">${a.name}</div>
              <div class="ac-org">${a.org}</div>
              <div style="margin:8px 0;display:flex;flex-wrap:wrap;gap:4px">
                <span class="ac-tag type">${a.type}</span>
                ${statusTag}
                ${!a.agtech ? '<span class="ac-tag persona">General (AgTech-friendly)</span>' : ''}
              </div>
              <div class="ac-desc">${a.desc}</div>
              <div style="display:flex;align-items:center;justify-content:space-between;margin-top:auto">
                <span style="font-size:10px;color:var(--text-faint)">Deadline: ${a.deadline}</span>
                <a href="${a.url}" target="_blank" rel="noopener" class="ac-btn primary">Apply →</a>
              </div>
            </div>`; }).join('')}
          </div>
        </div>
      </div>
    </div>`;
}

