// ECOSYSTEM MANAGER WORKSPACE — Enterprise Grade
// Supabase-backed with localStorage fallback for demo mode
// ══════════════════════════════════════════════════════════════
let _ecoTab = 'wks_pipeline';
let _ecoPipelineFilter = 'all';
let _ecoStartups = [];
let _ecoApplications = [];
let _ecoActivityLog = [];
let _ecoSettings = null;
let _ecoUseSupabase = false;
let _ecoLoaded = false;
let _ecoDetailId = null;
let _ecoAppDetailId = null;

// ── DATA LAYER: Supabase with localStorage fallback ──
async function loadEcoData() {
  if (_ecoLoaded) return;
  // Try Supabase first
  if (currentUser) {
    try {
      const { data: startups, error: sErr } = await _supabase.from('eco_startups')
        .select('*').eq('manager_id', currentUser.id).order('created_at', { ascending: false });
      if (sErr) throw sErr;
      _ecoStartups = (startups || []).map(s => ({
        ...s, founder: s.founder_name, email: s.founder_email,
        mentors: s.mentor_names || [], milestones: s.milestones || [],
        joined: s.created_at ? s.created_at.split('T')[0] : ''
      }));

      const { data: apps } = await _supabase.from('eco_applications')
        .select('*').eq('manager_id', currentUser.id).order('submitted_at', { ascending: false });
      _ecoApplications = apps || [];

      const { data: activity } = await _supabase.from('eco_activity_log')
        .select('*').eq('manager_id', currentUser.id).order('created_at', { ascending: false }).limit(100);
      _ecoActivityLog = (activity || []).map(a => ({ text: a.action, ts: a.created_at }));

      const { data: settings } = await _supabase.from('eco_program_settings')
        .select('*').eq('manager_id', currentUser.id).maybeSingle();
      _ecoSettings = settings;
      // Phase B: apply saved rubric override if present
      try { applyRubric(_ecoSettings && _ecoSettings.rubric); } catch(e) { console.warn('applyRubric failed:', e); }

      _ecoUseSupabase = true;
      _ecoLoaded = true;
      console.log('✅ Ecosystem workspace: Supabase connected (' + _ecoStartups.length + ' startups)');
      return;
    } catch(e) {
      console.log('ℹ️ Ecosystem Supabase tables not ready, using localStorage demo mode:', e.message);
    }
  }

  // Fallback: localStorage demo mode
  try {
    _ecoStartups = JSON.parse(localStorage.getItem('foc_eco_startups') || '[]');
    _ecoApplications = JSON.parse(localStorage.getItem('foc_eco_applications') || '[]');
    _ecoActivityLog = JSON.parse(localStorage.getItem('foc_eco_activity') || '[]');
    _ecoSettings = JSON.parse(localStorage.getItem('foc_eco_settings') || 'null');
  } catch(e) { _ecoStartups = []; _ecoApplications = []; _ecoActivityLog = []; }

  // Seed demo data if empty
  if (_ecoStartups.length === 0) {
    const cohort = _ecoSettings?.cohort_name || 'Spring 2026';
    _ecoStartups = [
      { id:1, name:'CropSense AI', founder:'Sarah Chen', email:'sarah@cropsense.ai', stage:'mvp', sector:'Precision Agriculture', status:'active', cohort, joined:'2026-01-15', mentors:['Walt Duflock'], notes:'Computer vision for pest detection. Strong technical team.', milestones:[{name:'MVP Complete',done:true},{name:'First Pilot',done:true},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:65, source:'introduction' },
      { id:2, name:'AgriChain', founder:'Miguel Torres', email:'miguel@agrichain.io', stage:'idea', sector:'Supply Chain', status:'screening', cohort, joined:'2026-02-20', mentors:[], notes:'Blockchain-based traceability for organic produce.', milestones:[{name:'MVP Complete',done:false},{name:'First Pilot',done:false},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:20, source:'application' },
      { id:3, name:'SoilSync', founder:'Priya Patel', email:'priya@soilsync.com', stage:'revenue', sector:'Soil & Water Tech', status:'active', cohort:'Fall 2025', joined:'2025-09-01', mentors:['Bob Lawson','Lisa Chen'], notes:'IoT soil sensors with ML analytics. $45K MRR.', milestones:[{name:'MVP Complete',done:true},{name:'First Pilot',done:true},{name:'LOI Secured',done:true},{name:'Seed Round',done:false}], readiness:85, source:'introduction' },
      { id:4, name:'FarmBot Plus', founder:'James Wright', email:'james@farmbotplus.com', stage:'mvp', sector:'Robotics & Automation', status:'active', cohort, joined:'2026-01-10', mentors:['Walt Duflock'], notes:'Autonomous weeding robot for row crops. Hardware prototype v2.', milestones:[{name:'MVP Complete',done:true},{name:'First Pilot',done:false},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:45, source:'manual' },
      { id:5, name:'GreenVault', founder:'Amara Osei', email:'amara@greenvault.ag', stage:'idea', sector:'Sustainability / Climate', status:'graduated', cohort:'Fall 2025', joined:'2025-06-15', mentors:['Diana Torres'], notes:'Carbon credit marketplace for smallholder farms. Raised $1.2M seed.', milestones:[{name:'MVP Complete',done:true},{name:'First Pilot',done:true},{name:'LOI Secured',done:true},{name:'Seed Round',done:true}], readiness:100, source:'application' },
      { id:6, name:'AquaYield', founder:'Tom Baker', email:'tom@aquayield.co', stage:'mvp', sector:'Indoor / Vertical Farming', status:'paused', cohort, joined:'2026-02-01', mentors:[], notes:'Hydroponic nutrient optimization. Founder taking personal leave.', milestones:[{name:'MVP Complete',done:true},{name:'First Pilot',done:false},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:35, source:'manual' },
      { id:7, name:'Smart Crop System', founder:'Oleksandr (Alexander) Ivanov', email:'alexander.ivanov@smartcropsystem.com', stage:'idea', sector:'Precision Agriculture', status:'screening', cohort:'2027 Candidate', joined:'2026-04-05', mentors:[], notes:'Pitched for 2026 program season — strong potential but timing didn\'t work out. Confirmed for 2027 cohort consideration. Connected via Russell.', milestones:[{name:'MVP Complete',done:false},{name:'First Pilot',done:false},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:0, source:'introduction' }
    ];
    _ecoApplications = [
      { id:'app-1', company_name:'DroneHarvest', founder_name:'Kai Nakamura', founder_email:'kai@droneharvest.io', stage:'mvp', sector:'Robotics & Automation', pitch:'Autonomous drone swarms for precision crop monitoring and targeted spraying. Reduces chemical use by 40%.', team_size:'4', why_this_program:'Your mentor network in precision ag is exactly what we need to land our first commercial pilot.', status:'pending', submitted_at:'2026-03-28T14:30:00Z' },
      { id:'app-2', company_name:'BioTrace', founder_name:'Elena Rodriguez', founder_email:'elena@biotrace.ag', stage:'idea', sector:'AgBiotech', pitch:'Rapid soil microbiome analysis kit — results in 24hrs instead of 2 weeks. Lab-on-chip technology.', team_size:'2', why_this_program:'We need help transitioning from research to a commercial product. Your program has deep biotech expertise.', status:'pending', submitted_at:'2026-04-01T09:15:00Z' },
      { id:'app-3', company_name:'FeedOptix', founder_name:'David Okafor', founder_email:'david@feedoptix.com', stage:'revenue', sector:'Livestock Tech', pitch:'AI-powered livestock feed optimization. Currently deployed on 3 dairy farms, saving $2.3K/month per farm.', team_size:'6', why_this_program:'Looking to scale from dairy to poultry and swine. Need investor introductions and supply chain mentors.', status:'reviewing', submitted_at:'2026-03-15T11:00:00Z', reviewer_notes:'Strong traction. Schedule interview.' }
    ];
    saveEcoData();
  }
  _ecoLoaded = true;
}

async function saveEcoData() {
  if (_ecoUseSupabase && currentUser) {
    // Supabase saves happen per-operation (insert/update/delete)
    // localStorage is also updated as backup
  }
  try {
    localStorage.setItem('foc_eco_startups', JSON.stringify(_ecoStartups));
    localStorage.setItem('foc_eco_applications', JSON.stringify(_ecoApplications));
    localStorage.setItem('foc_eco_activity', JSON.stringify(_ecoActivityLog));
    if (_ecoSettings) localStorage.setItem('foc_eco_settings', JSON.stringify(_ecoSettings));
  } catch(e) {}
}

async function ecoAddActivity(text) {
  const entry = { text, ts: new Date().toISOString() };
  _ecoActivityLog.unshift(entry);
  if (_ecoActivityLog.length > 100) _ecoActivityLog = _ecoActivityLog.slice(0, 100);
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_activity_log').insert({ manager_id: currentUser.id, action: text });
  }
  saveEcoData();
}

function ecoSwitchTab(tab) { _ecoTab = tab; render('ecosystem_ws'); }
function ecoPipelineFilter(f) { _ecoPipelineFilter = f; render('ecosystem_ws'); }
function ecoShowDetail(id) { _ecoDetailId = id; render('ecosystem_ws'); }
function ecoCloseDetail() { _ecoDetailId = null; render('ecosystem_ws'); }
function ecoShowAppDetail(id) { _ecoAppDetailId = id; _ecoTab = 'applications'; render('ecosystem_ws'); }
function ecoCloseAppDetail() { _ecoAppDetailId = null; render('ecosystem_ws'); }

// ── Platform Founders Directory for Ecosystem Workspace ──
let _ecoSearchOpen = false;
let _ecoPlatformFounders = [];
let _ecoPlatformLoaded = false;
let _ecoPlatformFilter = '';

async function ecoToggleSearch() {
  _ecoSearchOpen = !_ecoSearchOpen;
  if (_ecoSearchOpen && !_ecoPlatformLoaded) {
    await ecoLoadPlatformFounders();
  }
  render('ecosystem_ws');
}

async function ecoLoadPlatformFounders() {
  _ecoPlatformFounders = [];
  if (_supabase) {
    // Load ALL profiles from the platform (not just founders — managers may want to see advisors/investors too).
    // Uses the public_profiles view (see supabase/migrations/20260418_profiles_read_access.sql)
    // which exposes safe columns only and filters blocked users. RLS on profiles itself stays locked to owner/admin.
    const { data, error } = await _supabase.from('public_profiles')
      .select('id, email, full_name, persona, company_name, what_building, location, company_stage, onboarding_complete')
      .eq('onboarding_complete', true)
      .order('full_name', { ascending: true });
    if (!error && data) _ecoPlatformFounders = data;
  }
  // Fallback to cached profiles
  if (_ecoPlatformFounders.length === 0 && _allProfiles?.length) {
    _ecoPlatformFounders = _allProfiles.filter(p => p.onboarding_complete);
  }
  _ecoPlatformLoaded = true;
}

async function ecoAddFromPlatform(profileId) {
  const p = _ecoPlatformFounders.find(r => r.id === profileId);
  if (!p) return;

  await ecoAddStartup({
    name: p.company_name || p.full_name + "'s Venture",
    founder: p.full_name,
    email: p.email,
    sector: p.what_building || 'General AgTech',
    stage: p.company_stage || 'idea',
    source: 'platform',
    notes: 'Added from platform profile. ' + (p.what_building ? 'Building: ' + p.what_building : '')
  });
  toast('✅ ' + p.full_name + ' added to your pipeline');
}

async function ecoAddAllFromPlatform() {
  const existingEmails = new Set(_ecoStartups.map(s => (s.email || '').toLowerCase()));
  const filtered = ecoGetFilteredPlatformFounders().filter(p => !existingEmails.has((p.email || '').toLowerCase()));
  if (filtered.length === 0) { toast('All visible founders are already in your pipeline'); return; }
  if (!confirm('Add ' + filtered.length + ' founder' + (filtered.length !== 1 ? 's' : '') + ' to your pipeline as leads?')) return;
  for (const p of filtered) {
    await ecoAddStartup({
      name: p.company_name || p.full_name + "'s Venture",
      founder: p.full_name, email: p.email,
      sector: p.what_building || 'General AgTech',
      stage: p.company_stage || 'idea',
      source: 'platform',
      notes: 'Added from platform profile. ' + (p.what_building ? 'Building: ' + p.what_building : '')
    });
  }
  toast('✅ Added ' + filtered.length + ' founders to your pipeline');
}

function ecoGetFilteredPlatformFounders() {
  const q = _ecoPlatformFilter.toLowerCase();
  // Exclude the current user from the list
  let list = _ecoPlatformFounders.filter(p => p.id !== currentUser?.id);
  if (q) {
    list = list.filter(p =>
      (p.full_name || '').toLowerCase().includes(q) ||
      (p.email || '').toLowerCase().includes(q) ||
      (p.company_name || '').toLowerCase().includes(q) ||
      (p.what_building || '').toLowerCase().includes(q) ||
      (p.persona || '').toLowerCase().includes(q)
    );
  }
  return list;
}

function ecoRenderSearch() {
  if (!_ecoSearchOpen) return '';
  const personaLabels = { founder: '🚀 Founder', investor: '💰 Investor', advisor: '🧠 Advisor', ecosystem_manager: '🏗️ Eco Manager', farmer: '🌾 Farmer', researcher: '🔬 Researcher', service_provider: '🔧 Service Provider' };
  const existingEmails = new Set(_ecoStartups.map(s => (s.email || '').toLowerCase()));
  const filtered = ecoGetFilteredPlatformFounders();
  const notAdded = filtered.filter(p => !existingEmails.has((p.email || '').toLowerCase()));

  let html = '<div style="background:var(--card);border:2px solid var(--green-mid);border-radius:14px;padding:20px;margin-bottom:16px">';
  html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px"><h3 style="margin:0;font-size:16px;font-weight:800;color:var(--text)">🌐 Platform Directory — ' + _ecoPlatformFounders.filter(p => p.id !== currentUser?.id).length + ' members</h3>';
  html += '<button onclick="ecoToggleSearch()" style="background:none;border:none;color:var(--text-faint);font-size:18px;cursor:pointer">&times;</button></div>';

  html += '<div style="display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap">';
  html += '<input id="eco-platform-filter" type="text" placeholder="Filter by name, company, email, persona..." oninput="_ecoPlatformFilter=this.value;render(\'ecosystem_ws\');setTimeout(()=>{const i=document.getElementById(\'eco-platform-filter\');if(i){i.focus();i.value=_ecoPlatformFilter;}},50)" value="' + (_ecoPlatformFilter || '') + '" style="flex:1;min-width:200px;padding:10px 14px;background:var(--surface);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;outline:none" />';
  if (notAdded.length > 0) {
    html += '<button onclick="ecoAddAllFromPlatform()" style="padding:10px 16px;background:linear-gradient(135deg,var(--green),#059669);color:#fff;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer;white-space:nowrap">+ Add All (' + notAdded.length + ')</button>';
  }
  html += '</div>';

  html += '<div style="font-size:11px;color:var(--text-muted);margin-bottom:10px">' + filtered.length + ' member' + (filtered.length !== 1 ? 's' : '') + ' shown' + (notAdded.length < filtered.length ? ' · ' + (filtered.length - notAdded.length) + ' already in pipeline' : '') + '</div>';

  if (filtered.length > 0) {
    html += '<div style="display:grid;gap:8px;max-height:400px;overflow-y:auto">';
    filtered.forEach(p => {
      const label = personaLabels[p.persona] || p.persona || 'Member';
      const inPipeline = existingEmails.has((p.email || '').toLowerCase());
      html += '<div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:var(--surface);border:1px solid ' + (inPipeline ? 'var(--green-mid)' : 'var(--border)') + ';border-radius:10px;opacity:' + (inPipeline ? '0.7' : '1') + '">';
      html += '<div style="width:36px;height:36px;border-radius:50%;background:var(--green);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;font-size:13px;flex-shrink:0">' + (p.full_name || '?').split(' ').map(w=>w[0]).join('').slice(0,2) + '</div>';
      html += '<div style="flex:1;min-width:0">';
      html += '<div style="font-weight:700;color:var(--text);font-size:13px">' + (p.full_name || 'Unknown') + '</div>';
      html += '<div style="font-size:11px;color:var(--text-muted)">' + (p.email || '') + (p.company_name ? ' · ' + p.company_name : '') + '</div>';
      html += '<div style="display:flex;gap:4px;margin-top:4px"><span style="padding:2px 6px;background:var(--hover);border-radius:4px;font-size:10px;color:var(--text-muted)">' + label + '</span>';
      if (p.location) html += '<span style="padding:2px 6px;background:var(--hover);border-radius:4px;font-size:10px;color:var(--text-muted)">📍 ' + p.location + '</span>';
      if (p.what_building) html += '<span style="padding:2px 6px;background:var(--hover);border-radius:4px;font-size:10px;color:var(--text-muted)">' + p.what_building.slice(0,40) + (p.what_building.length > 40 ? '...' : '') + '</span>';
      html += '</div></div>';
      if (inPipeline) {
        html += '<span style="padding:6px 12px;background:var(--hover);border-radius:8px;font-size:11px;font-weight:600;color:var(--text-muted)">✅ In Pipeline</span>';
      } else {
        html += '<button onclick="ecoAddFromPlatform(\'' + p.id + '\')" style="padding:6px 14px;background:var(--green);color:#fff;border:none;border-radius:8px;font-size:11px;font-weight:700;cursor:pointer;white-space:nowrap">+ Add to Pipeline</button>';
      }
      html += '</div>';
    });
    html += '</div>';
  } else if (!_ecoPlatformLoaded) {
    html += '<div style="text-align:center;padding:30px;color:var(--text-faint)">Loading platform members...</div>';
  } else {
    html += '<div style="text-align:center;padding:30px;color:var(--text-faint);font-size:13px">No members found' + (_ecoPlatformFilter ? ' matching "' + _ecoPlatformFilter + '"' : '') + '.</div>';
  }
  html += '</div>';
  return html;
}

async function ecoAddStartup(prefill) {
  let name, founder, email, sector;
  if (prefill) {
    name = prefill.name; founder = prefill.founder; email = prefill.email; sector = prefill.sector;
  } else {
    name = prompt('Startup name:');
    if (!name) return;
    founder = prompt('Founder name:') || 'TBD';
    email = prompt('Founder email:') || '';
    sector = prompt('Sector (e.g. Precision Agriculture, Supply Chain):') || 'General AgTech';
  }
  const cohort = _ecoSettings?.cohort_name || 'Spring 2026';
  const newStartup = {
    id: _ecoUseSupabase ? undefined : (Math.max(0, ..._ecoStartups.map(s=>s.id||0)) + 1),
    name, founder: founder, email: email, stage: prefill?.stage || 'idea', sector,
    status:'screening', cohort, joined: new Date().toISOString().split('T')[0],
    mentors:[], notes: prefill?.notes || '', source: prefill?.source || 'manual',
    milestones:[{name:'MVP Complete',done:false},{name:'First Pilot',done:false},{name:'LOI Secured',done:false},{name:'Seed Round',done:false}], readiness:0
  };

  if (_ecoUseSupabase && currentUser) {
    const { data, error } = await _supabase.from('eco_startups').insert({
      manager_id: currentUser.id, name, founder_name: founder, founder_email: email,
      stage: newStartup.stage, sector, status: 'screening', cohort,
      milestones: newStartup.milestones, readiness: 0, mentor_names: [],
      notes: newStartup.notes, source: newStartup.source
    }).select().single();
    if (!error && data) { newStartup.id = data.id; }
  }
  _ecoStartups.unshift(newStartup);
  ecoAddActivity('Added startup: ' + name + (prefill?.source === 'application' ? ' (from application)' : ''));
  saveEcoData();
  render('ecosystem_ws');
}

async function ecoUpdateStatus(id, newStatus) {
  const s = _ecoStartups.find(x => x.id === id);
  if (!s) return;
  const old = s.status;
  s.status = newStatus;
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_startups').update({ status: newStatus }).eq('id', id);
  }
  ecoAddActivity(s.name + ': ' + old + ' → ' + newStatus);
  saveEcoData();
  render('ecosystem_ws');
}

async function ecoToggleMilestone(startupId, milestoneIdx) {
  const s = _ecoStartups.find(x => x.id === startupId);
  if (!s || !s.milestones[milestoneIdx]) return;
  s.milestones[milestoneIdx].done = !s.milestones[milestoneIdx].done;
  s.readiness = Math.round((s.milestones.filter(m => m.done).length / s.milestones.length) * 100);
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_startups').update({ milestones: s.milestones, readiness: s.readiness }).eq('id', startupId);
  }
  ecoAddActivity(s.name + ': ' + (s.milestones[milestoneIdx].done ? '✅' : '⬜') + ' ' + s.milestones[milestoneIdx].name);
  saveEcoData();
  render('ecosystem_ws');
}

async function ecoAssignMentor(startupId) {
  const s = _ecoStartups.find(x => x.id === startupId);
  if (!s) return;
  const mentorName = prompt('Mentor name to assign to ' + s.name + ':');
  if (!mentorName || s.mentors.includes(mentorName)) return;
  s.mentors.push(mentorName);
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_startups').update({ mentor_names: s.mentors }).eq('id', startupId);
  }
  ecoAddActivity('Assigned ' + mentorName + ' → ' + s.name);
  saveEcoData();
  render('ecosystem_ws');
}

async function ecoRemoveMentor(startupId, mentorName) {
  const s = _ecoStartups.find(x => x.id === startupId);
  if (!s) return;
  s.mentors = s.mentors.filter(m => m !== mentorName);
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_startups').update({ mentor_names: s.mentors }).eq('id', startupId);
  }
  ecoAddActivity('Removed ' + mentorName + ' from ' + s.name);
  saveEcoData();
  render('ecosystem_ws');
}

async function ecoEditNotes(startupId) {
  const s = _ecoStartups.find(x => x.id === startupId);
  if (!s) return;
  const notes = prompt('Notes for ' + s.name + ':', s.notes);
  if (notes === null) return;
  s.notes = notes;
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_startups').update({ notes }).eq('id', startupId);
  }
  saveEcoData();
  render('ecosystem_ws');
}

// ── APPLICATION MANAGEMENT ──
async function ecoReviewApp(appId, decision) {
  const app = _ecoApplications.find(a => a.id === appId);
  if (!app) return;
  app.status = decision; // 'accepted', 'rejected', 'waitlisted', 'reviewing'
  app.reviewed_at = new Date().toISOString();
  if (_ecoUseSupabase && currentUser) {
    await _supabase.from('eco_applications').update({ status: decision, reviewed_at: app.reviewed_at, reviewer_notes: app.reviewer_notes }).eq('id', appId);
  }
  if (decision === 'accepted') {
    // Move to pipeline
    await ecoAddStartup({ name: app.company_name, founder: app.founder_name, email: app.founder_email, stage: app.stage || 'idea', sector: app.sector || 'General AgTech', source: 'application', notes: 'Applied: ' + (app.pitch || '').slice(0, 200) });
    toast('✅ ' + app.company_name + ' accepted and added to pipeline');
  } else if (decision === 'rejected') {
    toast('❌ ' + app.company_name + ' rejected');
  } else if (decision === 'waitlisted') {
    toast('⏳ ' + app.company_name + ' waitlisted');
  } else {
    toast('👁️ ' + app.company_name + ' marked as under review');
  }
  ecoAddActivity(app.company_name + ': application ' + decision);
  saveEcoData();
  _ecoAppDetailId = null;
  render('ecosystem_ws');
}

function ecoAppAddNote(appId) {
  const app = _ecoApplications.find(a => a.id === appId);
  if (!app) return;
  const note = prompt('Reviewer notes for ' + app.company_name + ':', app.reviewer_notes || '');
  if (note === null) return;
  app.reviewer_notes = note;
  saveEcoData();
  render('ecosystem_ws');
}

// ── PROGRAM SETTINGS ──
async function ecoSaveSettings() {
  const name = document.getElementById('eco-set-name')?.value || '';
  const type = document.getElementById('eco-set-type')?.value || '';
  const desc = document.getElementById('eco-set-desc')?.value || '';
  const website = document.getElementById('eco-set-web')?.value || '';
  const cohort = document.getElementById('eco-set-cohort')?.value || '';
  const deadline = document.getElementById('eco-set-deadline')?.value || '';
  const accepting = document.getElementById('eco-set-accepting')?.checked ?? true;

  _ecoSettings = {
    ..._ecoSettings,
    program_name: name, program_type: type, description: desc,
    website, cohort_name: cohort, application_deadline: deadline,
    accepting_applications: accepting
  };

  if (_ecoUseSupabase && currentUser) {
    const payload = { manager_id: currentUser.id, ..._ecoSettings };
    if (_ecoSettings.id) {
      await _supabase.from('eco_program_settings').update(payload).eq('id', _ecoSettings.id);
    } else {
      const { data } = await _supabase.from('eco_program_settings').upsert(payload, { onConflict: 'manager_id' }).select().single();
      if (data) _ecoSettings.id = data.id;
    }
  }
  saveEcoData();
  toast('✅ Program settings saved');
  ecoAddActivity('Updated program settings');
}

