// ── BULK STARTUP IMPORT ──
let _ecoBulkMode = false;
let _ecoBulkRows = [{ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' }];

function ecoBulkToggle() {
  _ecoBulkMode = !_ecoBulkMode;
  if (_ecoBulkMode) _ecoBulkRows = [{ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' }];
  render('ecosystem_ws');
}

function ecoBulkAddRow() {
  _ecoBulkRows.push({ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' });
  render('ecosystem_ws');
}

function ecoBulkRemoveRow(idx) {
  _ecoBulkRows.splice(idx, 1);
  if (_ecoBulkRows.length === 0) _ecoBulkRows = [{ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' }];
  render('ecosystem_ws');
}

function ecoBulkUpdateRow(idx, field, value) {
  if (_ecoBulkRows[idx]) _ecoBulkRows[idx][field] = value;
}

async function ecoBulkSubmit() {
  // Read from DOM in case render hasn't captured latest inputs
  _ecoBulkRows.forEach((row, i) => {
    const nameEl = document.getElementById('bulk-name-' + i);
    const founderEl = document.getElementById('bulk-founder-' + i);
    const emailEl = document.getElementById('bulk-email-' + i);
    const sectorEl = document.getElementById('bulk-sector-' + i);
    const stageEl = document.getElementById('bulk-stage-' + i);
    const notesEl = document.getElementById('bulk-notes-' + i);
    if (nameEl) row.name = nameEl.value;
    if (founderEl) row.founder = founderEl.value;
    if (emailEl) row.email = emailEl.value;
    if (sectorEl) row.sector = sectorEl.value;
    if (stageEl) row.stage = stageEl.value;
    if (notesEl) row.notes = notesEl.value;
  });

  const valid = _ecoBulkRows.filter(r => r.name.trim());
  if (valid.length === 0) { toast('⚠️ Add at least one startup name'); return; }
  let added = 0;
  for (const row of valid) {
    await ecoAddStartup({
      name: row.name.trim(),
      founder: row.founder.trim() || 'TBD',
      email: row.email.trim(),
      sector: row.sector.trim() || 'General AgTech',
      stage: row.stage || 'idea',
      notes: row.notes.trim(),
      source: 'bulk_import'
    });
    added++;
  }
  toast('✅ Imported ' + added + ' startup' + (added > 1 ? 's' : '') + ' to your pipeline');
  _ecoBulkMode = false;
  _ecoBulkRows = [{ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' }];
  render('ecosystem_ws');
}

function ecoBulkPasteCSV() {
  const raw = prompt('Paste CSV data (one startup per line).\nFormat: Name, Founder, Email, Sector, Stage\n\nExample:\nCropSense AI, Sarah Chen, sarah@cropsense.ai, Precision Agriculture, mvp\nAgriChain, Miguel Torres, miguel@agrichain.io, Supply Chain, idea');
  if (!raw) return;
  const lines = raw.split('\n').filter(l => l.trim());
  _ecoBulkRows = lines.map(line => {
    const parts = line.split(',').map(p => p.trim());
    return {
      name: parts[0] || '',
      founder: parts[1] || '',
      email: parts[2] || '',
      sector: parts[3] || 'General AgTech',
      stage: (parts[4] || 'idea').toLowerCase(),
      notes: ''
    };
  });
  if (_ecoBulkRows.length === 0) _ecoBulkRows = [{ name:'', founder:'', email:'', sector:'', stage:'idea', notes:'' }];
  render('ecosystem_ws');
}

// ── CLAIM PARTNER ECOSYSTEM ──
// Two paths: (1) Invite code → instant access (2) Verification request → admin approves
let _ecoClaimRequests = JSON.parse(localStorage.getItem('foc_eco_claim_requests') || '[]');

function saveClaimRequests() {
  localStorage.setItem('foc_eco_claim_requests', JSON.stringify(_ecoClaimRequests));
}

function ecoClaimPartner(ecoId) {
  const eco = PARTNER_ECOSYSTEMS.find(e => e.id === ecoId);
  if (!eco) return;
  if (!currentUser) {
    toast('🔐 Sign in first, then select Ecosystem Manager during onboarding');
    return;
  }
  const profile = _userProfile;
  if (!profile || profile.persona !== 'ecosystem_manager') {
    toast('ℹ️ Switch to Ecosystem Manager persona to claim this program. Use the admin persona switcher or re-onboard as Ecosystem Manager.');
    return;
  }

  // Check if already has a pending request
  const existing = _ecoClaimRequests.find(r => r.ecoId === ecoId && r.userId === currentUser.id && r.status === 'pending');
  if (existing) {
    toast('⏳ You already have a pending claim request for ' + eco.shortName + '. The platform admin will review it shortly.');
    return;
  }

  // Show claim modal with two paths
  _ecoClaimTarget = eco;
  openModal('eco-claim-modal');
}

let _ecoClaimTarget = null;

function ecoClaimWithCode() {
  if (!_ecoClaimTarget) return;
  const code = document.getElementById('eco-claim-code')?.value?.trim();
  if (!code) { toast('⚠️ Enter your invite code'); return; }
  if (code.toUpperCase() !== (_ecoClaimTarget.inviteCode || '').toUpperCase()) {
    toast('❌ Invalid invite code. Check the code sent by the platform admin, or submit a verification request instead.');
    return;
  }
  // Instant claim
  finalizeClaim(_ecoClaimTarget.id);
  closeModal('eco-claim-modal');
}

function ecoClaimRequestVerify() {
  if (!_ecoClaimTarget || !currentUser) return;
  const name = document.getElementById('eco-verify-name')?.value?.trim();
  const email = document.getElementById('eco-verify-email')?.value?.trim();
  const linkedin = document.getElementById('eco-verify-linkedin')?.value?.trim();
  const role = document.getElementById('eco-verify-role')?.value?.trim();
  const note = document.getElementById('eco-verify-note')?.value?.trim();

  if (!name || !email) { toast('⚠️ Please provide your name and email'); return; }
  if (!linkedin) { toast('⚠️ LinkedIn profile is required for verification'); return; }

  const request = {
    id: 'claim-' + Date.now(),
    ecoId: _ecoClaimTarget.id,
    ecoName: _ecoClaimTarget.shortName,
    userId: currentUser.id,
    userAuthEmail: currentUser.email,
    name: name,
    email: email,
    linkedin: linkedin,
    role: role || 'Program Manager',
    note: note || '',
    status: 'pending',
    submitted_at: new Date().toISOString()
  };

  _ecoClaimRequests.push(request);
  saveClaimRequests();

  // Also persist to Supabase if available (via eco_activity_log as a workaround)
  if (_ecoUseSupabase && currentUser) {
    _supabase.from('eco_activity_log').insert({
      manager_id: currentUser.id,
      action: 'CLAIM_REQUEST:' + JSON.stringify({ ecoId: request.ecoId, ecoName: request.ecoName, name, email, linkedin, role })
    }).then(() => {});
  }

  closeModal('eco-claim-modal');
  toast('📨 Verification request submitted for ' + _ecoClaimTarget.shortName + '. The platform admin will review your credentials and respond shortly.');
  _ecoClaimTarget = null;
}

function finalizeClaim(ecoId) {
  const eco = PARTNER_ECOSYSTEMS.find(e => e.id === ecoId);
  if (!eco) return;
  if (_ecoSettings) {
    _ecoSettings.program_name = _ecoSettings.program_name || eco.shortName;
    _ecoSettings.partner_ecosystem_id = eco.id;
  } else {
    _ecoSettings = { program_name: eco.shortName, program_type: eco.type, partner_ecosystem_id: eco.id, description: eco.description, website: eco.website };
  }
  saveEcoData();
  eco.claimed = true;

  // Register this user as an ecosystem manager (dynamic access)
  if (currentUser) {
    registerEcoManager(currentUser.id, currentUser.email, eco.id, eco.shortName);
    // Also grant ecosystem_access tag on their profile so it persists through persona changes
    if (_userProfile) {
      const tags = _userProfile.admin_tags || [];
      if (!tags.includes('ecosystem_access')) {
        tags.push('ecosystem_access');
        _userProfile.admin_tags = tags;
        _supabase.from('profiles').update({ admin_tags: tags }).eq('id', currentUser.id).then(() => {});
      }
    }
    // Re-apply persona UI so the nav button shows immediately
    if (_userProfile) applyPersonaUI(_userProfile);
  }

  toast('🎉 ' + eco.shortName + ' linked! Let\'s set up your workspace.');
  // Start the setup wizard
  _ecoSetupStep = 0;
  _ecoSetupForm = {
    programName: eco.shortName || '',
    programType: eco.type || '',
    location: _userProfile?.location || eco.location || '',
    teamSize: '1-3',
    template: null,
    features: [],
    roles: []
  };
  go('ecosystem_ws');
}

// Admin: approve or deny claim requests
function ecoAdminApproveClaim(requestId) {
  const req = _ecoClaimRequests.find(r => r.id === requestId);
  if (!req) return;
  req.status = 'approved';
  req.reviewed_at = new Date().toISOString();
  req.reviewed_by = currentUser?.email || 'admin';
  saveClaimRequests();
  // Register the claimant as an ecosystem manager
  registerEcoManager(req.userId, req.userAuthEmail || req.email, req.ecoId, req.ecoName);
  // Grant ecosystem_access tag on their profile
  if (req.userId) {
    const p = _allProfiles.find(x => x.id === req.userId);
    if (p) {
      const tags = p.admin_tags || [];
      if (!tags.includes('ecosystem_access')) {
        tags.push('ecosystem_access');
        p.admin_tags = tags;
        _supabase.from('profiles').update({ admin_tags: tags }).eq('id', req.userId).then(() => {});
      }
    }
  }
  const eco = PARTNER_ECOSYSTEMS.find(e => e.id === req.ecoId);
  if (eco) eco.claimed = true;
  toast('✅ Approved ' + req.name + ' as manager of ' + req.ecoName + ' — they now have Ecosystem Workspace access');
  render(currentPage);
}

function ecoAdminDenyClaim(requestId) {
  const req = _ecoClaimRequests.find(r => r.id === requestId);
  if (!req) return;
  req.status = 'denied';
  req.reviewed_at = new Date().toISOString();
  req.reviewed_by = currentUser?.email || 'admin';
  saveClaimRequests();
  toast('❌ Denied claim request from ' + req.name);
  render(currentPage);
}

// ══════════════════════════════════════════════════════════════
// "LIST YOUR ECOSYSTEM" — Application flow for new programs
// ══════════════════════════════════════════════════════════════
let _ecoListings = JSON.parse(localStorage.getItem('foc_eco_listings') || '[]');
let _ecoListingStep = 0;
let _ecoListingForm = {};

function saveEcoListings() {
  localStorage.setItem('foc_eco_listings', JSON.stringify(_ecoListings));
}

function openListEcosystemForm() {
  if (!currentUser) { toast('🔐 Please sign in first'); return; }
  _ecoListingStep = 0;
  _ecoListingForm = {
    programName: '', orgName: '', managerName: _userProfile?.full_name || '',
    managerTitle: _userProfile?.job_title || '', managerEmail: currentUser?.email || '',
    linkedinUrl: _userProfile?.linkedin_url || '', location: _userProfile?.location || '',
    country: '', type: '', focus: [], description: '', website: '',
    startupCount: '', founded: '', highlights: '',
    whyJoin: '', currentTools: ''
  };
  openModal('eco-listing-modal');
  setTimeout(() => renderEcoListingModal(), 50);
}

function ecoListingNext() {
  // Per-step validation
  if (_ecoListingStep === 0) {
    _ecoListingForm.programName = document.getElementById('ecol-program-name')?.value?.trim() || _ecoListingForm.programName;
    _ecoListingForm.orgName = document.getElementById('ecol-org-name')?.value?.trim() || _ecoListingForm.orgName;
    _ecoListingForm.managerName = document.getElementById('ecol-manager-name')?.value?.trim() || _ecoListingForm.managerName;
    _ecoListingForm.managerTitle = document.getElementById('ecol-manager-title')?.value?.trim() || _ecoListingForm.managerTitle;
    _ecoListingForm.managerEmail = document.getElementById('ecol-manager-email')?.value?.trim() || _ecoListingForm.managerEmail;
    _ecoListingForm.linkedinUrl = document.getElementById('ecol-linkedin')?.value?.trim() || _ecoListingForm.linkedinUrl;
    if (!_ecoListingForm.programName) { toast('Please enter your program name.'); return; }
    if (!_ecoListingForm.managerName) { toast('Please enter your name.'); return; }
    if (!_ecoListingForm.managerEmail) { toast('Please enter your email.'); return; }
  } else if (_ecoListingStep === 1) {
    _ecoListingForm.location = document.getElementById('ecol-location')?.value?.trim() || _ecoListingForm.location;
    _ecoListingForm.country = document.getElementById('ecol-country')?.value?.trim() || _ecoListingForm.country;
    _ecoListingForm.description = document.getElementById('ecol-description')?.value?.trim() || _ecoListingForm.description;
    _ecoListingForm.website = document.getElementById('ecol-website')?.value?.trim() || _ecoListingForm.website;
    _ecoListingForm.startupCount = document.getElementById('ecol-startup-count')?.value?.trim() || _ecoListingForm.startupCount;
    _ecoListingForm.founded = document.getElementById('ecol-founded')?.value?.trim() || _ecoListingForm.founded;
    _ecoListingForm.highlights = document.getElementById('ecol-highlights')?.value?.trim() || _ecoListingForm.highlights;
    if (!_ecoListingForm.location) { toast('Please enter your location.'); return; }
    if (!_ecoListingForm.type) { toast('Please select a program type.'); return; }
    if (!_ecoListingForm.description) { toast('Please describe your program.'); return; }
  }
  _ecoListingStep++;
  renderEcoListingModal();
}

function ecoListingBack() {
  if (_ecoListingStep > 0) _ecoListingStep--;
  renderEcoListingModal();
}

function ecoListingToggleFocus(f) {
  const idx = _ecoListingForm.focus.indexOf(f);
  if (idx >= 0) _ecoListingForm.focus.splice(idx, 1);
  else _ecoListingForm.focus.push(f);
  renderEcoListingModal();
}

function ecoListingSetType(t) {
  _ecoListingForm.type = t;
  renderEcoListingModal();
}

async function ecoListingSubmit() {
  _ecoListingForm.whyJoin = document.getElementById('ecol-why-join')?.value?.trim() || _ecoListingForm.whyJoin;
  _ecoListingForm.currentTools = document.getElementById('ecol-current-tools')?.value?.trim() || _ecoListingForm.currentTools;
  if (!_ecoListingForm.whyJoin) { toast('Please tell us why you want to join.'); return; }

  const listing = {
    id: 'listing-' + Date.now(),
    ...JSON.parse(JSON.stringify(_ecoListingForm)),
    userId: currentUser?.id || null,
    status: 'pending',
    submitted_at: new Date().toISOString(),
    admin_notes: ''
  };

  _ecoListings.push(listing);
  saveEcoListings();

  // Also try Supabase
  if (_supabase && currentUser) {
    try {
      await _supabase.from('eco_activity_log').insert({
        manager_id: currentUser.id,
        action: 'ECO_LISTING_APP:' + JSON.stringify(listing)
      });
    } catch(e) { console.log('Listing save to Supabase note:', e); }
  }

  closeModal('eco-listing-modal');
  toast('🎉 Application submitted! Our team will review your program and get back to you within 30 days.');
  _ecoListingStep = 0;
  _ecoListingForm = {};
  updateNotifBell();
  render(currentPage);
}

