    html += '<div><label style="display:block;font-size:11px;font-weight:700;color:var(--text);margin-bottom:4px">Year Founded</label><input id="ecol-founded" type="text" value="' + (f.founded||'').replace(/"/g,'&quot;') + '" placeholder="2020" style="width:100%;padding:10px 12px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:13px;box-sizing:border-box"></div></div>';
