// Admin: approve/deny ecosystem listing
function ecoAdminApproveListing(listingId) {
  const listing = _ecoListings.find(l => l.id === listingId);
  if (!listing) return;
  listing.status = 'approved';
  listing.reviewed_at = new Date().toISOString();
  listing.reviewed_by = currentUser?.email || 'admin';
  saveEcoListings();

  // Generate a slug and invite code
  const slug = (listing.programName || 'program').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
  const initials = (listing.programName || 'XX').split(/\s+/).map(w => w[0]).join('').toUpperCase().slice(0,4);
  const inviteCode = initials + '-2026-' + (listing.managerName||'').split(' ').map(w=>w[0]).join('').toUpperCase();
  const color = ['#0e7490','#7c3aed','#c2410c','#0369a1','#b91c1c','#4338ca','#0f766e','#a16207'][Math.floor(Math.random()*8)];

  // Add to PARTNER_ECOSYSTEMS
  const newEco = {
    id: slug, slug: slug,
    name: listing.programName,
    shortName: listing.programName.length > 25 ? listing.programName.split(/[\s\-\/]+/).slice(0,3).join(' ') : listing.programName,
    org: listing.orgName || listing.programName,
    manager: listing.managerName,
    managerTitle: listing.managerTitle || 'Program Manager',
    location: listing.location,
    country: listing.country || 'US',
    type: listing.type || 'Innovation Hub',
    focus: listing.focus.length > 0 ? listing.focus : ['General AgTech'],
    description: listing.description,
    highlights: listing.highlights ? listing.highlights.split('\n').filter(h => h.trim()).slice(0,4) : ['New to FounderOps Center'],
    website: listing.website || '',
    color: color,
    startupCount: listing.startupCount || 'New',
    founded: listing.founded || new Date().getFullYear().toString(),
    claimed: false,
    inviteCode: inviteCode
  };
  PARTNER_ECOSYSTEMS.push(newEco);

  // Send automated acceptance email via Resend
  if (listing.managerEmail) {
    const tpl = FOC_EMAIL_TEMPLATES.ecoAccepted(listing.managerName || 'there', listing.programName, inviteCode);
    sendAutoEmail(listing.managerEmail, tpl.subject, tpl.html);
  }
  // Also open mailto for Russell to review/personalize if desired
  ecoListingEmailAction('accept', listing.managerEmail, listing.managerName, listing.programName);

  toast('✅ ' + listing.programName + ' approved and added to Partner Ecosystems! Invite code: ' + inviteCode);
  render(currentPage);
}

function ecoAdminDenyListing(listingId) {
  const listing = _ecoListings.find(l => l.id === listingId);
  if (!listing) return;
  listing.status = 'denied';
  listing.reviewed_at = new Date().toISOString();
  listing.reviewed_by = currentUser?.email || 'admin';
  saveEcoListings();
  // Send automated decline email via Resend
  if (listing.managerEmail) {
    const tpl = FOC_EMAIL_TEMPLATES.ecoDeclined(listing.managerName || 'there', listing.programName);
    sendAutoEmail(listing.managerEmail, tpl.subject, tpl.html);
  }
  ecoListingEmailAction('decline', listing.managerEmail, listing.managerName, listing.programName);
  toast('❌ Listing application from ' + listing.managerName + ' denied');
  render(currentPage);
}

// ── Ecosystem Listing Admin Email Actions ──
function ecoListingEmailAction(type, email, name, programName) {
  const firstName = (name || '').split(' ')[0] || 'there';
  const emails = {
    confirm: {
      subject: 'We received your application — ' + (programName || 'Your Program') + ' | FounderOps Center',
      body: 'Hi ' + firstName + ',\n\nThank you for applying to list ' + (programName || 'your program') + ' on the FounderOps Center partner ecosystem directory.\n\nHere\'s what happens next:\n\n- Our team will review your application within 30 days, or at our next monthly review — whichever comes first.\n- If we have questions, we\'ll reach out directly.\n- In the meantime, feel free to explore the platform — browse startups, market data, and the existing partner ecosystems at founderopscenter.com.\n\nWe\'re building something special here and programs like yours are exactly what makes the AgTech ecosystem stronger.\n\nWe\'ll be in touch soon.\n\nBest,\nRussell Cole\nFounder, FounderOps Center\nfounderopscenter.com'
    },
    info: {
      subject: 'Quick follow-up on ' + (programName || 'your listing application') + ' | FounderOps Center',
      body: 'Hi ' + firstName + ',\n\nThanks again for applying to list ' + (programName || 'your program') + ' on FounderOps Center. We\'ve been reviewing your application and we\'re excited about the potential.\n\nBefore we move forward, could you help us with a few things?\n\n1. [Specific question about the program]\n2. [Question about current cohort or enrollments]\n3. [Any additional context]\n\nNo rush — just reply whenever you get a chance.\n\nBest,\nRussell Cole\nFounder, FounderOps Center'
    },
    call: {
      subject: 'Let\'s talk about listing ' + (programName || 'your program') + ' — FounderOps Center',
      body: 'Hi ' + firstName + ',\n\nThanks for your interest in listing ' + (programName || 'your program') + ' on FounderOps Center. I\'d love to connect and learn more about what you\'re doing.\n\nWould any of these times work for a 20-minute introductory call?\n\n- [Option 1]\n- [Option 2]\n- [Option 3]\n\nI want to understand your program better so we can figure out the best way to integrate you into our ecosystem network.\n\nBest,\nRussell Cole\nFounder, FounderOps Center'
    },
    accept: {
      subject: 'Welcome to the network — ' + (programName || 'Your Program') + ' is now on FounderOps Center!',
      body: 'Hi ' + firstName + ',\n\nGreat news — ' + (programName || 'your program') + ' has been approved and added to the FounderOps Center partner ecosystem directory!\n\nHere\'s what you get:\n\n- A verified listing on our Partner Ecosystems page visible to founders, investors, and advisors\n- An invite code to claim your program and unlock your Ecosystem Workspace\n- Pipeline management tools, application review, and cohort tracking\n- Cross-ecosystem intelligence and founder/investor matching\n\nYour invite code will be shared separately. Once you claim your program, you\'ll have full access to your Ecosystem Workspace.\n\nNext step: Log into founderopscenter.com, navigate to Partner Ecosystems, find your listing, and click "Claim as Manager." Enter your invite code and you\'re live.\n\nOne more thing — to keep the platform healthy, we ask all ecosystem managers to complete a brief monthly check-in sharing program updates, enrollment numbers, and upcoming events. This helps us surface the freshest opportunities to founders and investors.\n\nWelcome to the network. Let\'s build something great together.\n\nBest,\nRussell Cole\nFounder, FounderOps Center\nfounderopscenter.com'
    },
    decline: {
      subject: 'Update on your listing application | FounderOps Center',
      body: 'Hi ' + firstName + ',\n\nThank you for your interest in listing ' + (programName || 'your program') + ' on FounderOps Center. We appreciate you taking the time to apply.\n\nAfter review, we\'ve decided not to add this listing at this time. This could be due to focus area alignment, program stage, or simply capacity — it\'s not a reflection of your program\'s quality.\n\nHere\'s what you can do:\n\n- Stay active on the platform in your current role\n- Reapply in the future as your program evolves\n- Connect with our existing partner ecosystems for potential collaboration\n\nWe\'d love to stay in touch and revisit this down the road.\n\nBest,\nRussell Cole\nFounder, FounderOps Center'
    }
  };
  const e = emails[type];
  if (!e) return;
  const mailto = 'mailto:' + encodeURIComponent(email) + '?subject=' + encodeURIComponent(e.subject) + '&body=' + encodeURIComponent(e.body);
  window.open(mailto, '_blank');
  toast('📧 Email draft opened for ' + (name || email));
}

function ecoListingUpdateStatus(listingId, newStatus) {
  const listing = _ecoListings.find(l => l.id === listingId);
  if (!listing) return;
  listing.status = newStatus;
  listing.status_updated_at = new Date().toISOString();
  saveEcoListings();
  toast('📋 ' + listing.programName + ' status → ' + newStatus);
  render(currentPage);
}

function ecoListingSaveNotes(listingId) {
  const listing = _ecoListings.find(l => l.id === listingId);
  if (!listing) return;
  const textarea = document.getElementById('ecol-notes-' + listingId);
  if (!textarea) return;
  listing.admin_notes = textarea.value;
  saveEcoListings();
  toast('💾 Notes saved for ' + listing.programName);
}


