// ── Rubric System (Phase B: bring-your-own-rubric) ──
// Ecosystems can edit dimension labels, score labels, and tier thresholds via the Rubric Builder
// in Settings → Rubric. Overrides are persisted to Supabase (eco_program_settings.rubric JSONB)
// and applied on load. Until an override is saved, the Starter Rubric defaults are used.
// Three dimensions × 0-4 scale → max total 12.
const STARTER_RUBRIC = Object.freeze({
  scoreLabels: { 1:'Early', 2:'Developing', 3:'Promising', 4:'Advanced' },
  scoreColors: { 1:'#ef4444', 2:'#f59e0b', 3:'#3b82f6', 4:'#22c55e' },
  totalTiers: [
    { min:10, max:12, label:'Prioritize', color:'#22c55e', desc:'Advance to next stage' },
    { min:6,  max:9,  label:'Explore',    color:'#f59e0b', desc:'Monitor and re-evaluate' },
    { min:0,  max:5,  label:'Pass',       color:'#ef4444', desc:'Not a fit right now' }
  ],
  dimensions: [
    { key:'dim1', label:'Innovation', field:'tech',   airtableField:'techScore',   desc:'Novelty, differentiation, defensibility of the approach' },
    { key:'dim2', label:'Execution',  field:'team',   airtableField:'teamScore',   desc:'Team experience, coachability, ability to deliver' },
    { key:'dim3', label:'Traction',   field:'market', airtableField:'marketScore', desc:'Market pull, early adoption, customer or partner signal' }
  ],
  maxTotal: 12
});

// Mutable live rubric — other code paths read these names directly.
// applyRubric() overwrites them when an ecosystem override loads.
let SCORE_LABELS      = { ...STARTER_RUBRIC.scoreLabels };
let SCORE_COLORS      = { ...STARTER_RUBRIC.scoreColors };
let TOTAL_TIERS       = STARTER_RUBRIC.totalTiers.map(t => ({ ...t }));
let RUBRIC_DIMENSIONS = STARTER_RUBRIC.dimensions.map(d => ({ ...d }));
let RUBRIC_MAX_TOTAL  = STARTER_RUBRIC.maxTotal;

// Return the currently-active rubric as a single object (for the Rubric Builder UI)
function getRubric() {
  return {
    scoreLabels: { ...SCORE_LABELS },
    scoreColors: { ...SCORE_COLORS },
    totalTiers:  TOTAL_TIERS.map(t => ({ ...t })),
    dimensions:  RUBRIC_DIMENSIONS.map(d => ({ ...d })),
    maxTotal:    RUBRIC_MAX_TOTAL
  };
}

// Validate + apply a rubric override in place. Missing fields fall back to STARTER_RUBRIC.
// Accepts the shape stored in eco_program_settings.rubric.
function applyRubric(rubric) {
  const r = rubric && typeof rubric === 'object' ? rubric : {};
  // Score labels (1..4)
  const sl = r.scoreLabels || {};
  SCORE_LABELS = {
    1: (sl[1] || sl['1'] || STARTER_RUBRIC.scoreLabels[1]),
    2: (sl[2] || sl['2'] || STARTER_RUBRIC.scoreLabels[2]),
    3: (sl[3] || sl['3'] || STARTER_RUBRIC.scoreLabels[3]),
    4: (sl[4] || sl['4'] || STARTER_RUBRIC.scoreLabels[4])
  };
  // Score colors (optional override — default palette stays neutral)
  const sc = r.scoreColors || {};
  SCORE_COLORS = {
    1: (sc[1] || sc['1'] || STARTER_RUBRIC.scoreColors[1]),
    2: (sc[2] || sc['2'] || STARTER_RUBRIC.scoreColors[2]),
    3: (sc[3] || sc['3'] || STARTER_RUBRIC.scoreColors[3]),
    4: (sc[4] || sc['4'] || STARTER_RUBRIC.scoreColors[4])
  };
  // Dimensions — labels/descriptions editable; Airtable field bindings stay fixed
  const dims = Array.isArray(r.dimensions) ? r.dimensions : [];
  RUBRIC_DIMENSIONS = STARTER_RUBRIC.dimensions.map((def, i) => {
    const d = dims[i] || {};
    return {
      key: def.key,
      label: (d.label || def.label),
      field: def.field,
      airtableField: def.airtableField,
      desc: (d.desc || def.desc)
    };
  });
  // Tier thresholds + labels
  const tiers = Array.isArray(r.totalTiers) && r.totalTiers.length === 3 ? r.totalTiers : null;
  if (tiers) {
    TOTAL_TIERS = tiers.map((t, i) => ({
      min:   Number.isFinite(+t.min) ? +t.min : STARTER_RUBRIC.totalTiers[i].min,
      max:   Number.isFinite(+t.max) ? +t.max : STARTER_RUBRIC.totalTiers[i].max,
      label: t.label || STARTER_RUBRIC.totalTiers[i].label,
      color: t.color || STARTER_RUBRIC.totalTiers[i].color,
      desc:  t.desc  || STARTER_RUBRIC.totalTiers[i].desc
    }));
  } else {
    TOTAL_TIERS = STARTER_RUBRIC.totalTiers.map(t => ({ ...t }));
  }
  RUBRIC_MAX_TOTAL = Number.isFinite(+r.maxTotal) ? +r.maxTotal : STARTER_RUBRIC.maxTotal;
}

