// ── Airtable REST Client ──
async function atFetch(tableId, opts = {}) {
  if (!_wksPAT) return null;
  let url = 'https://api.airtable.com/v0/' + WORKSPACE_BASE_ID + '/' + tableId + '?';
  if (opts.fields) opts.fields.forEach(f => { url += 'fields[]=' + encodeURIComponent(f) + '&'; });
  if (opts.formula) url += 'filterByFormula=' + encodeURIComponent(opts.formula) + '&';
  if (opts.maxRecords) url += 'maxRecords=' + opts.maxRecords + '&';
  if (opts.offset) url += 'offset=' + encodeURIComponent(opts.offset) + '&';
  if (opts.sort) opts.sort.forEach((s,i) => { url += 'sort['+i+'][field]='+encodeURIComponent(s.field)+'&sort['+i+'][direction]='+(s.dir||'asc')+'&'; });
  try {
    const r = await fetch(url, { headers: { 'Authorization': 'Bearer ' + _wksPAT } });
    if (!r.ok) throw new Error('AT ' + r.status);
    return await r.json();
  } catch(e) { console.error('Airtable:', e); return null; }
}

async function atPatch(tableId, recId, fields) {
  if (!_wksPAT) { _wksPendingWrites.push({tableId,recId,fields,ts:Date.now()}); return false; }
  try {
    const r = await fetch('https://api.airtable.com/v0/'+WORKSPACE_BASE_ID+'/'+tableId+'/'+recId, {
      method:'PATCH', headers:{'Authorization':'Bearer '+_wksPAT,'Content-Type':'application/json'},
      body: JSON.stringify({fields})
    });
    return r.ok;
  } catch(e) { console.error('AT patch:', e); _wksPendingWrites.push({tableId,recId,fields,ts:Date.now()}); return false; }
}

async function atPost(tableId, fields) {
  if (!_wksPAT) return null;
  try {
    const r = await fetch('https://api.airtable.com/v0/'+WORKSPACE_BASE_ID+'/'+tableId, {
      method:'POST', headers:{'Authorization':'Bearer '+_wksPAT,'Content-Type':'application/json'},
      body: JSON.stringify({fields})
    });
    return r.ok ? await r.json() : null;
  } catch(e) { console.error('AT post:', e); return null; }
}

// ── Airtable → Supabase bulk sync (admin importer) ──
// Pulls every record from every WORKSPACE_TABLES table via the user's PAT and
// mirrors it into public.ws_airtable_records via the upsert_ws_records RPC.
// Returns { ok, totals, errors }.
async function syncWorkspaceFromAirtable(workspaceId, pat) {
  if (!workspaceId) return { ok:false, message:'Missing workspace id' };
  if (!_supabase)   return { ok:false, message:'Supabase not initialized' };
  const usePat = pat || _wksPAT || localStorage.getItem('wks_at_pat') || '';
  if (!usePat) return { ok:false, message:'No Airtable PAT available. Save one in Settings → Integrations first.' };
  // Temporarily swap _wksPAT so atFetch can be reused
  const prevPat = _wksPAT; _wksPAT = usePat;
  const totals = {}; const errors = [];
  try {
    for (const [tableKey, tableId] of Object.entries(WORKSPACE_TABLES)) {
      let all = [], offset;
      do {
        const p = {}; if (offset) p.offset = offset;
        const r = await atFetch(tableId, p);
        if (!r) { errors.push(tableKey + ': fetch failed'); break; }
        all = all.concat(r.records || []);
        offset = r.offset;
      } while (offset);
      // Shape: [{source_id, fields}]
      const payload = all.map(rec => ({ source_id: rec.id, fields: rec.fields || rec.cellValuesByFieldId || {} }));
      const { data, error } = await _supabase.rpc('upsert_ws_records', {
        p_workspace_id: workspaceId,
        p_table_key: tableKey,
        p_source_system: 'airtable',
        p_records: payload
      });
      if (error) { errors.push(tableKey + ': ' + error.message); totals[tableKey] = 0; }
      else { totals[tableKey] = data || payload.length; }
      // log per-table
      try {
        await _supabase.rpc('log_ws_sync', {
          p_workspace_id: workspaceId,
          p_source_system: 'airtable',
          p_table_key: tableKey,
          p_records_count: payload.length,
          p_status: error ? 'error' : 'success',
          p_error: error ? error.message : null
        });
      } catch(e) { /* ignore log errors */ }
    }
  } finally {
    _wksPAT = prevPat;
  }
  return { ok: errors.length === 0, totals, errors };
}

// Admin UI click handler — prompts for PAT if not saved, then syncs.
async function handleSyncWorkspaceClick(workspaceId, workspaceName) {
  if (!workspaceId) return;
  let pat = localStorage.getItem('wks_at_pat') || _wksPAT || '';
  if (!pat) {
    pat = prompt('Paste your Airtable Personal Access Token to sync "' + (workspaceName||'this workspace') + '" from Airtable.\n\n(It will be saved locally as wks_at_pat.)');
    if (!pat) return;
    localStorage.setItem('wks_at_pat', pat.trim());
    _wksPAT = pat.trim();
  }
  const btn = document.getElementById('sync-btn-'+workspaceId);
  if (btn) { btn.disabled = true; btn.textContent = '🔄 Syncing…'; }
  const res = await syncWorkspaceFromAirtable(workspaceId, pat);
  if (btn) { btn.disabled = false; btn.textContent = '🔄 Sync from Airtable'; }
  if (res.ok) {
    const summary = Object.entries(res.totals||{}).map(([k,v]) => k+':'+v).join('  ');
    toast('✅ Synced ' + (workspaceName||'workspace') + ' — ' + summary);
  } else {
    const msg = res.message || (res.errors && res.errors.join('; ')) || 'Sync failed';
    toast('⚠️ ' + msg);
  }
  renderWorkspacesAdmin();
}

// ── Parse Airtable records ──
function parseAtOrg(rec) {
  const f = rec.cellValuesByFieldId || rec.fields || {};
  const gs = k => { const v = f[AT[k]]; return v && typeof v === 'object' ? (v.name || null) : (v || null); };
  const gv = k => f[AT[k]] || null;
  return {
    id:rec.id, name:gv('orgName')||'(Unnamed)', stage:gs('stage'), classification:gs('classification'),
    tech:gv('techScore'), team:gv('teamScore'), market:gv('marketScore'), total:gv('totalScore')||0,
    trl:gs('trl'), funding:gs('fundingStage'), website:gv('website'), techProblem:gv('techProblem'),
    country:gv('country'), province:gv('province'), owner:gs('owner'), charter:gs('charterStatus'),
    nextSteps:gv('nextSteps'), coachability:gv('coachability'), runway:gv('runway'),
    teamSize:gv('teamSize'), teamBg:gv('teamBg'), ip:gv('ip'), needs:gv('needs'),
    advisors:gv('advisors'), techTheme:gs('techTheme'), farmSupport:gs('farmSupport'),
    firstOutreach:gv('firstOutreach'), introCallDate:gv('introCallDate'),
    pitchToFarms:gs('pitchToFarms'), referralReason:gv('referralReason'),
    referralDest:gv('referralDest'), cropsSupported:gv('cropsSupported')
  };
}

function parseAtMeeting(rec) {
  const f = rec.cellValuesByFieldId || rec.fields || {};
  const orgs = f.fldwi7hw1GQi8MtcQ;
  return {
    id:rec.id, title:f.fld1Ld4MBl4Mz4TXs||'', date:f.fldqscAUAoy3htbox||'',
    type: f.fldDVKkrJlk3wKZaK ? (f.fldDVKkrJlk3wKZaK.name||f.fldDVKkrJlk3wKZaK) : '',
    orgNames: Array.isArray(orgs) ? orgs.map(o=>o.name||o.id) : [],
    orgIds: Array.isArray(orgs) ? orgs.map(o=>o.id) : [],
    notes:f.fld3t6OCDVZPxZjpU||'', nextSteps:f.fldXSHtpRsA7F2cBf||'',
    actionItems:f.fldf30mSRGA4YFnqg||'', followUp:f.fldO6c4kj9SN8UMyQ||''
  };
}

function parseAtProject(rec) {
  const f = rec.cellValuesByFieldId || rec.fields || {};
  return {
    id:rec.id, name:f.fldTjkCCXZZuXJBlJ||'',
    year: Array.isArray(f.fld2DFH69zs6JKAdR) ? f.fld2DFH69zs6JKAdR.map(y=>y.name||y).join(', ') : '',
    hubs: Array.isArray(f.fldDbTZXBdlFn8Way) ? f.fldDbTZXBdlFn8Way.map(h=>h.name||h) : [],
    sowLink:f.fld787Xw4wbxw1kn0||'', notes:f.fldU6v3IHY94RaHu5||'',
    actionItems:f.fldn8lwsqwfQ1n8V5||'', checklist:f.fld2Srj44HxWbAC2Q||'',
    contacts:f.fldhVveYfDwVMBIXn||'', orgIds: Array.isArray(f.fld0wrsGklq5Qy3tY) ? f.fld0wrsGklq5Qy3tY.map(o=>({id:o.id,name:o.name})) : [],
    wksDeliverables:f.fldYDTnSSBqyuZcO8||'', vhDeliverables:f.fldjpiVS7E7gKZAez||''
  };
}

// ── Load pipeline data ──
async function loadAivaData() {
  if (_wksLoaded || _wksLoading) return;
  _wksLoading = true;
  if (_wksPAT) {
    try {
      let all = [], offset;
      do {
        const p = {}; if (offset) p.offset = offset;
        const r = await atFetch(WORKSPACE_TABLES.orgs, p);
        if (!r) break;
        all = all.concat((r.records||[]).map(parseAtOrg));
        offset = r.offset;
      } while (offset);
      _wksOrgs = all.filter(o => o.name !== '(Unnamed)');
      const mr = await atFetch(WORKSPACE_TABLES.meetings, {});
      if (mr) _wksMeetings = (mr.records||[]).map(parseAtMeeting);
      let allP = [], pOff;
      do {
        const pp = {}; if (pOff) pp.offset = pOff;
        const pr = await atFetch(WORKSPACE_TABLES.projects, pp);
        if (!pr) break;
        allP = allP.concat((pr.records||[]).map(parseAtProject));
        pOff = pr.offset;
      } while (pOff);
      _wksProjects = allP;
      _wksLastSync = new Date();
      console.log('✅ Pipeline: ' + _wksOrgs.length + ' orgs, ' + _wksMeetings.length + ' meetings, ' + _wksProjects.length + ' projects');
    } catch(e) { console.error('Pipeline load:', e); }
  }
  if (_wksOrgs.length === 0) {
    _wksOrgs = CACHED_ORGS || [];
    console.log('📦 Pipeline: cached ' + _wksOrgs.length + ' orgs');
  }
  _wksLoaded = true; _wksLoading = false;
}

async function wksRefresh() {
  _wksLoaded = false; _wksLoading = false;
  _wksOrgs = []; _wksMeetings = []; _wksProjects = [];
  await loadAivaData();
  render('ecosystem_ws');
}

// ── Stage advancement ──
async function wksAdvanceStage(recId, newStage) {
  const org = _wksOrgs.find(o => o.id === recId);
  if (!org) return;
  const oldStage = org.stage;
  org.stage = newStage;
  render('ecosystem_ws');
  const ok = await atPatch(WORKSPACE_TABLES.orgs, recId, { [AT.stage]: newStage });
  if (ok) {
    ecoAddActivity('Pipeline: ' + org.name + ' moved from ' + (oldStage||'none') + ' → ' + newStage);
  } else if (!_wksPAT) {
    showModal('Offline Change', '<p style="font-size:13px;color:var(--text-muted)">Stage change saved locally. Connect your Airtable PAT in Settings to sync.</p>');
  }
}

// ── Score update ──
async function wksSaveScores(recId) {
  const draft = _wksScoringDraft[recId];
  if (!draft) return;
  const org = _wksOrgs.find(o => o.id === recId);
  if (!org) return;
  const fields = {};
  if (draft.tech !== undefined) { fields[AT.techScore] = parseInt(draft.tech); org.tech = parseInt(draft.tech); }
  if (draft.team !== undefined) { fields[AT.teamScore] = parseInt(draft.team); org.team = parseInt(draft.team); }
  if (draft.market !== undefined) { fields[AT.marketScore] = parseInt(draft.market); org.market = parseInt(draft.market); }
  org.total = (org.tech||0) + (org.team||0) + (org.market||0);
  if (draft.comments) { fields[AT.nextSteps] = draft.comments; org.nextSteps = draft.comments; }
  _wksScoringDraft[recId] = {};
  render('ecosystem_ws');
  await atPatch(WORKSPACE_TABLES.orgs, recId, fields);
  ecoAddActivity('Scored: ' + org.name + ' → Tech:' + (org.tech||0) + ' Team:' + (org.team||0) + ' Market:' + (org.market||0) + ' = ' + org.total);
}

// ── Meeting log ──
async function wksSaveMeeting() {
  if (!_wksMeetingForm) return;
  const f = _wksMeetingForm;
  const fields = {
    fld1Ld4MBl4Mz4TXs: f.title,
    fldqscAUAoy3htbox: f.date,
    fld3t6OCDVZPxZjpU: f.notes,
    fldXSHtpRsA7F2cBf: f.nextSteps,
    fldf30mSRGA4YFnqg: f.actionItems,
    fldO6c4kj9SN8UMyQ: f.followUp
  };
  if (f.type) fields.fldDVKkrJlk3wKZaK = f.type;
  if (f.orgId) fields.fldwi7hw1GQi8MtcQ = [{ id: f.orgId }];
  const result = await atPost(WORKSPACE_TABLES.meetings, fields);
  if (result) {
    _wksMeetings.unshift(parseAtMeeting(result));
    ecoAddActivity('Meeting logged: ' + f.title);
  }
  _wksMeetingForm = null;
  render('ecosystem_ws');
}

