// ── SOW Gap-field persistence ──
function wksLoadSOWDraft(orgId) {
  try {
    const all = JSON.parse(localStorage.getItem('wks_sow_drafts') || '{}');
    _wksSOWDraft[orgId] = all[orgId] || {};
  } catch(e) { _wksSOWDraft[orgId] = {}; }
  return _wksSOWDraft[orgId];
}
function wksSaveSOWDraft() {
  try {
    localStorage.setItem('wks_sow_drafts', JSON.stringify(_wksSOWDraft));
  } catch(e) {}
}
function wksSOWField(orgId, key, value) {
  if (!_wksSOWDraft[orgId]) _wksSOWDraft[orgId] = {};
  _wksSOWDraft[orgId][key] = value;
  wksSaveSOWDraft();
  // Debounced re-render to update progress without losing input focus
  clearTimeout(window._sowRenderTimer);
  window._sowRenderTimer = setTimeout(() => render('ecosystem_ws'), 400);
}
function wksSOWAutofill(orgId) {
  const o = _wksOrgs.find(x => x.id === orgId);
  if (!o) return;
  if (!_wksSOWDraft[orgId]) _wksSOWDraft[orgId] = {};
  const d = _wksSOWDraft[orgId];
  if (!d.techName) d.techName = o.name || '';
  if (!d.innovCategory && o.techTheme) d.innovCategory = o.techTheme;
  if (!d.targetedUser) d.targetedUser = 'Agronomist or farmer';
  const _netName = getEcoNetworkName();
  if (!d.projectPurpose && o.techProblem) d.projectPurpose = 'Validate and assess ' + (o.name||'the technology') + ' across the participating sites in the ' + _netName + '.';
  if (!d.keyOutcomes && o.needs) d.keyOutcomes = o.needs;
  if (!d.projectOutputs) d.projectOutputs = 'Paired data collection across a minimum of two participating sites.';
  if (!d.hubs) d.hubs = 'Participating Site 1, Participating Site 2, Participating Site 3, Participating Site 4';
  if (!d.cropsHubMix && o.cropsSupported) d.cropsHubMix = o.cropsSupported;
  if (!d.innovatorResources) d.innovatorResources = 'Technology platform, onboarding materials, and technical support throughout the validation period.';
  if (!d.hubResources) d.hubResources = 'Field staff, sampling tools, and infrastructure required to execute the protocol at each site.';
  if (!d.projectCost) d.projectCost = '$0 for the 2026 growing season';
  if (!d.timelineStart) d.timelineStart = '2026-04-15';
  if (!d.timelineEnd) d.timelineEnd = '2026-08-31';
  if (!d.finalDataDate) d.finalDataDate = '2026-10-31';
  if (!d.feedbackReportDate) d.feedbackReportDate = '2026-10-31';
  if (!d.dataHandling) d.dataHandling = 'Data from analysis and technology outputs will be exported, shared with the Innovator, and analyzed jointly by the ' + _netName + ' team and the Innovator team.';
  if (!d.methodology) d.methodology = 'See appendix for crop-specific sampling protocols. All samples to be recorded with sample ID, field, GPS coordinates, crop variety, and growth stage.';
  wksSaveSOWDraft();
  toast('✨ Auto-filled from charter data');
  render('ecosystem_ws');
}
function wksSOWClear(orgId) {
  if (!confirm('Clear all SOW gap fields for this startup?')) return;
  _wksSOWDraft[orgId] = {};
  wksSaveSOWDraft();
  render('ecosystem_ws');
}

