// Venture studio
function setVentureStep(n) { _ventureStep = n; render('venture'); }
function _dismissVentureModal(el) {
  el.closest('[style*=fixed]')?.remove();
  _ventureForm = {};
  _ventureStep = 0;
}
function dismissVentureToSignin(el)   { _dismissVentureModal(el); openModal('signin-modal'); }
function dismissVentureToStep0(el)    { _dismissVentureModal(el); render('venture'); }
function dismissVentureToOverview(el) { _dismissVentureModal(el); go('overview'); }
function markVentureAfterSignIn() {
  _ventureStudioAfterSignIn = true;
  localStorage.setItem('foc_venture_after_signin', 'true');
  enterApp();
}

